export interface TrackInfo {
  id: number;
  name: string;
  instrument: {
    name: string;
    number: number;
    family: string;
  };
  noteCount: number;
  ornamentCount?: number;
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  LOADED = 'LOADED',
  ERROR = 'ERROR',
  GENERATING = 'GENERATING', 
  SUCCESS = 'SUCCESS',
}

export type MidiEventType = 'pitchBend' | 'controlChange' | 'programChange';

export interface MidiEventCounts {
  pitchBend: number;
  controlChange: number;
  programChange: number;
}

export type TempoChangeMode = 'speed' | 'time';

export type InversionMode = 'off' | 'global' | '1beat' | '2beats' | 'measure' | '2measures' | '4measures' | '8measures';

export type OutputStrategy = 'combine' | 'separate_tracks' | 'separate_voices';

export type VoiceAssignmentMode = 'auto' | 'manual'; 

export type RhythmFamily = 'Simple' | 'Triple' | 'Quintuplet';

export type HarmonicAnalysisMode = 'attack' | 'sustain' | 'hybrid' | 'arpeggio_window' | 'hia_v2';

export type PitchAnalysisMode = 'modal' | 'frequency';

export type HybridVoiceRole = 'sustain' | 'attack' | 'arpeggio' | 'ignore';

export type ArpeggioStrategy = 'note_based' | 'time_based';

export interface RhythmRule {
    enabled: boolean;
    family: RhythmFamily;
    minNoteValue: string; 
}

export interface AnalysisSection {
    id: string;
    name: string;
    startMeasure: number;
    endMeasure: number;
    harmonyMode: HarmonicAnalysisMode;
    pitchStatsMode: PitchAnalysisMode;

    // Granular Harmony Settings
    chordTolerance: string; 
    chordMinDuration: string; 
    arpeggioWindowVal: string; // Replaces bucketSizeBeats
    ignorePassingMotion: boolean; 

    // Hybrid Specifics
    hybridConfig: {
        voiceRoles: Record<number, HybridVoiceRole>;
        arpStrategy: ArpeggioStrategy;
        arpHistoryCount: number; 
        arpHistoryTime: string; 
    };

    // Reporting
    debugLogging?: boolean;
}

export interface ModalConversionOptions {
    enabled: boolean;
    root: number; 
    modeName: string; 
    mappings: Record<number, number>; 
}

export interface ConversionOptions {
    tempo: number;
    timeSignature: {
        numerator: number;
        denominator: number;
    };
    tempoChangeMode: TempoChangeMode;
    originalTempo: number;
    transposition: number;
    noteTimeScale: number;
    inversionMode: InversionMode;

    // Shadow Grid Options
    primaryRhythm: RhythmRule;
    secondaryRhythm: RhythmRule;

    quantizationValue: string; 

    quantizeDurationMin: string; 
    shiftToMeasure: boolean;
    detectOrnaments: boolean; 
    modalConversion: ModalConversionOptions;
    removeShortNotesThreshold: number; 
    pruneOverlaps: boolean; 
    pruneThresholdIndex: number;
    // Voice Separation Logic
    voiceSeparationOverlapTolerance: number; 
    voiceSeparationPitchBias: number; 
    voiceSeparationMaxVoices: number; 
    voiceSeparationDisableChords: boolean; 
    voiceAssignmentMode: VoiceAssignmentMode; 

    // Export Options
    outputStrategy: OutputStrategy;

    // Global Voice Naming
    voiceNames: Record<number, string>;

    // Analysis Options
    sections: AnalysisSection[];
}

export interface NoteRole {
    name: string;
    midi: number;
    role: 'Root' | '3rd' | '5th' | 'Ext' | 'NCT';
}

export interface HarmonicRegion {
    startTick: number;
    endTick: number;
    type: 'consonant_stable' | 'dissonant_primary' | 'dissonant_secondary' | 'dissonant_tertiary' | 'dissonant_severe';
    errorType?: 'parallel' | 'direct' | null;
    intervalLabel: string;
    description?: string;
    detailedInfo?: {
        chordName: string;
        root?: string;
        quality?: string;
        allNotes: string[];
        noteDetails: NoteRole[];
        chordTones: string[];
        ncts: string[];
    };
}

export interface PianoRollTrackData {
    notes: {
        midi: number;
        ticks: number;
        durationTicks: number;
        velocity: number;
        name: string;
        voiceIndex?: number;
        isOrnament?: boolean;
    }[]; 
    name: string;
    ppq: number;
    timeSignature: {
        numerator: number;
        denominator: number;
    };
    harmonicRegions?: HarmonicRegion[];
}

export interface NoteValueStat {
    name: string;
    count: number;
    percentage: number;
    standardMultiplier: number; 
}

export interface ChordMatch {
    name: string;
    root: string;
    quality: string;
    bass?: string;
    inversion?: string;
    score: number;
    missingNotes: string[];
}

export interface ChordEvent {
    timestamp: number; 
    measure: number;   
    formattedTime: string; 
    name: string;      
    root: string;
    quality: string;
    bass?: string;     
    inversion?: string; 
    ticks: number;     
    constituentNotes: string[]; 
    missingNotes: string[]; 
    alternatives: ChordMatch[];
    debugInfo?: string; 
}

export interface RawNote {
    midi: number;
    ticks: number;
    durationTicks: number;
    velocity: number;
    name: string;
    time?: number;
    duration?: number;
    voiceIndex?: number;
    isOrnament?: boolean;
}

export interface TransformationStats {
    notesQuantized: number;
    notesDurationChanged: number;
    notesExtended: number;
    notesShortened: number;
    avgShiftTicks: number;
    notesRemovedDuration: number;
    notesRemovedOverlap: number;
    notesTruncatedOverlap: number;
    totalNotesInput: number;
    totalNotesOutput: number;
    inputGridAlignment: number;
    outputGridAlignment: number;
}

export interface PitchStats {
    count: number;
    durationTicks: number;
}

export interface TrackAnalysisData {
    trackName: string;
    topNoteValues: NoteValueStat[];
    outputNoteValues?: NoteValueStat[]; 

    voiceRhythmStats?: Record<number, NoteValueStat[]>;

    gridAlignmentScore: number; 
    durationConsistencyScore: number; 
    averageOffsetTicks: number;
    totalNotes: number;
    detectedGridType: string; 
    pitchClassHistogram: Record<number, number>; 
    chordsSustain: ChordEvent[]; 
    chordsAttack: ChordEvent[];  
    chordsHybrid?: ChordEvent[]; 
    chordsArpeggioWindow?: ChordEvent[];
    chordsBucketed?: ChordEvent[]; 
    bestKeyPrediction?: { root: number, mode: string, score: number };

    pitchStatsGlobal?: Record<number, PitchStats>;
    pitchStatsByVoice?: Record<number, Record<number, PitchStats>>;

    voiceIntervals: Record<number, number>; 
    voiceIntervalsByVoice?: Record<number, Record<number, number>>;

    transformationStats?: TransformationStats;

    notesRaw: RawNote[]; 
    ppq: number;
    timeSignature: { numerator: number, denominator: number };
    tempo: number;

    voiceCount: number;
}

// --- Stretto Specific Types ---

export type StrettoGrade = 'STRONG' | 'VIABLE' | 'INVALID';

export interface StrettoError {
    tick: number;
    timeFormatted: string;
    type: 'Parallel 5th' | 'Parallel 8ve' | 'Direct 5th' | 'Direct 8ve' | 'Consecutive Dissonance' | 'Unresolved Dissonance';
    details: string;
    severity: 'fatal' | 'warning';
}

export interface StrettoCandidate {
    id: string;
    intervalSemis: number;
    intervalLabel: string;
    delayBeats: number;
    delayTicks: number;
    grade: StrettoGrade;
    errors: StrettoError[];
    notes: RawNote[]; // The combined notes of Subject + Answer
    regions?: HarmonicRegion[]; // Visualization data
    detectedChords?: string[]; // List of chord names found in this texture
    dissonanceRatio: number; // Ratio of dissonant time to overlapping time
    pairDissonanceScore: number; // Duration weighted count of all dissonant pairs
    endsOnDissonance: boolean; 
}

export interface StrettoConfig {
    intervals: {
        unison: boolean;
        octave: boolean; // +/- 1 & 2
        fifth: boolean; // +/- P5
        fourth: boolean; // +/- P4
    };
    maxDistanceBeats: number; // calculated limit
}

export interface StrettoChainOption {
    startBeat: number; // Relative to start of piece (or previous entry if chained logic, but logic usually normalized to 0)
    transposition: number;
    type: 'N' | 'I'; // Normal or Inverted
    length: number; // Full or Truncated length in ticks
    voiceIndex: number;
}

export interface ScoreLogItem {
    reason: string;
    points: number;
}

export interface ScoreLog {
    base: number;
    penalties: ScoreLogItem[];
    bonuses: ScoreLogItem[];
    total: number;
}

export interface StrettoChainResult {
    id: string;
    entries: StrettoChainOption[];
    warnings: string[];
    score: number; // Higher is better (variety of distances, lack of errors)
    scoreLog?: ScoreLog;
    variations?: StrettoChainResult[]; // Variations with same rhythmic structure but different intervals
    detectedChords?: string[]; // For UI reporting
    dissonanceRatio?: number;
    pairDissonanceScore?: number;
}

export interface StrettoSearchReport {
    results: StrettoChainResult[];
    stats: {
        nodesVisited: number;
        timeMs: number;
        stopReason: 'Success' | 'Timeout' | 'NodeLimit' | 'Exhausted';
        maxDepthReached: number;
    };
}

export type StrettoConstraintMode = 'None' | 'Max 1' | 'Unlimited';

export interface StrettoSearchOptions {
    ensembleTotal: number;
    targetChainLength: number;
    subjectVoiceIndex: number;
    truncationMode: StrettoConstraintMode;
    truncationTargetBeats: number; 
    inversionMode: StrettoConstraintMode;
    useChromaticInversion: boolean; 
    thirdSixthMode: StrettoConstraintMode;
    pivotMidi: number; // For inversion
    requireConsonantEnd: boolean;
    disallowComplexExceptions: boolean;
    voiceNames?: Record<number, string>;
    // New Scale Context for Rule 10 (Strict Tonal Inversion)
    scaleRoot: number; // 0-11
    scaleMode: string; // 'Major', 'Natural Minor', 'Harmonic Minor', etc.
}

import React, { useMemo, useState } from 'react';
import { StrettoSearchOptions, StrettoConstraintMode, RawNote } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';
import { getVoiceLabel } from '../services/midiVoices';

interface StrettoSearchPanelProps {
    options: StrettoSearchOptions;
    setOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
    subjectNotes: RawNote[];
    ppq: number;
}

const SCALE_MODES = ['Major', 'Natural Minor', 'Harmonic Minor', 'Melodic Minor', 'Dorian', 'Phrygian', 'Lydian', 'Mixolydian'];

export default function StrettoSearchPanel({ 
    options, setOptions, onSearch, isSearching, 
    voiceNames, setVoiceNames, subjectNotes, ppq 
}: StrettoSearchPanelProps) {

    const [showVoiceConfig, setShowVoiceConfig] = useState(false);

    const handleChange = (field: keyof StrettoSearchOptions, val: any) => {
        setOptions({ ...options, [field]: val });
    };

    const handleVoiceNameChange = (idx: number, name: string) => {
        if (setVoiceNames && voiceNames) {
            setVoiceNames({ ...voiceNames, [idx]: name });
        }
    };

    const renderConstraintSelector = (label: string, field: keyof StrettoSearchOptions, value: StrettoConstraintMode) => (
        <div className="bg-gray-900 p-2 rounded border border-gray-700">
            <label className="block text-[10px] font-bold text-gray-400 mb-2 uppercase">{label}</label>
            <div className="flex gap-1">
                {['None', 'Max 1', 'Unlimited'].map((mode) => (
                    <button
                        key={mode}
                        onClick={() => handleChange(field, mode as StrettoConstraintMode)}
                        className={`flex-1 py-1 text-[10px] rounded border transition-colors ${value === mode ? 'bg-brand-primary text-white border-brand-primary' : 'bg-gray-800 text-gray-500 border-gray-600 hover:border-gray-500'}`}
                    >
                        {mode}
                    </button>
                ))}
            </div>
        </div>
    );

    const availableAbove = options.subjectVoiceIndex; 
    const availableBelow = (options.ensembleTotal - 1) - options.subjectVoiceIndex;

    // Truncation Visualization Logic
    const truncationVisual = useMemo(() => {
        if (subjectNotes.length === 0) return null;

        const sorted = [...subjectNotes].sort((a,b) => a.ticks - b.ticks);
        const startTick = sorted[0].ticks;
        const totalDuration = Math.max(...sorted.map(n => n.ticks + n.durationTicks)) - startTick;

        const targetTicks = Math.round(options.truncationTargetBeats * ppq);
        const minMidi = Math.min(...sorted.map(n => n.midi));
        const maxMidi = Math.max(...sorted.map(n => n.midi));
        const range = maxMidi - minMidi + 12; // Buffer

        return (
            <div className="w-full h-16 bg-gray-900 border border-gray-700 rounded mt-2 relative overflow-hidden select-none">
                <svg className="w-full h-full" preserveAspectRatio="none" viewBox={`0 0 ${totalDuration} ${range}`}>
                    {/* Background Grid (Beats) */}
                    {Array.from({ length: Math.ceil(totalDuration / ppq) }).map((_, i) => (
                        <line 
                            key={i} 
                            x1={i * ppq} y1={0} 
                            x2={i * ppq} y2={range} 
                            stroke="#333" 
                            strokeWidth={i % 4 === 0 ? 2 : 1}
                            vectorEffect="non-scaling-stroke" 
                        />
                    ))}

                    {/* Notes */}
                    {sorted.map((n, i) => {
                        const relStart = n.ticks - startTick;
                        const relEnd = relStart + n.durationTicks;

                        // Check if note is cut
                        let isKept = true;
                        let opacity = 1.0;
                        let fill = "#14b8a6"; // brand-primary

                        if (relStart >= targetTicks) {
                            isKept = false;
                            opacity = 0.3;
                            fill = "#4b5563"; // gray-600
                        } else if (relEnd > targetTicks) {
                            // Split note visualization?
                            fill = "#f59e0b"; // amber for clipped
                        }

                        // Invert Y for SVG
                        const y = range - (n.midi - minMidi) - 6;

                        return (
                            <rect 
                                key={i}
                                x={relStart}
                                y={y}
                                width={n.durationTicks}
                                height={4} // Note height
                                fill={fill}
                                opacity={opacity}
                                rx={2}
                            />
                        );
                    })}

                    {/* Cut Line */}
                    <line 
                        x1={targetTicks} y1={0} 
                        x2={targetTicks} y2={range} 
                        stroke="#ef4444" 
                        strokeWidth={2} 
                        strokeDasharray="4,4"
                        vectorEffect="non-scaling-stroke"
                    />
                </svg>
                <div className="absolute top-1 right-1 text-[9px] bg-black/50 px-1 rounded text-gray-400">
                    {options.truncationTargetBeats} Beats / {(totalDuration/ppq).toFixed(1)} Total
                </div>
            </div>
        );
    }, [subjectNotes, options.truncationTargetBeats, ppq]);

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 mb-6 shadow-sm">
            <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                <h3 className="text-sm font-bold text-gray-300 uppercase tracking-wider">Algorithmic Chain Finder</h3>
                {isSearching && <span className="text-xs text-brand-primary animate-pulse">Searching...</span>}
            </div>

            {/* Ensemble & Voice Naming Configuration */}
            <div className="mb-6 bg-black/20 p-2 rounded border border-gray-700">
                <button 
                    onClick={() => setShowVoiceConfig(!showVoiceConfig)}
                    className="w-full flex justify-between items-center text-[10px] font-bold text-gray-500 uppercase tracking-widest px-2"
                >
                    <span>Voice Configuration (SATB)</span>
                    <span>{showVoiceConfig ? '▲' : '▼'}</span>
                </button>

                {showVoiceConfig && (
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mt-4 px-2 pb-2 animate-fade-in">
                        {Array.from({ length: options.ensembleTotal }).map((_, idx) => {
                            const defaultLabel = getVoiceLabel(idx, options.ensembleTotal);
                            return (
                                <div key={idx} className="flex flex-col gap-1">
                                    <label className="text-[9px] text-gray-400 font-bold uppercase">
                                        Voice {idx + 1} {idx === options.subjectVoiceIndex ? "(Subject)" : ""}
                                    </label>
                                    <input 
                                        type="text"
                                        placeholder={defaultLabel}
                                        value={voiceNames?.[idx] || ''}
                                        onChange={(e) => handleVoiceNameChange(idx, e.target.value)}
                                        className="bg-gray-900 border border-gray-600 rounded px-2 py-1 text-xs text-white focus:border-brand-primary outline-none"
                                    />
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4 mb-4">

                {/* 1. Ensemble Configuration (Col 3) */}
                <div className="lg:col-span-3 bg-gray-900 p-2 rounded border border-gray-700 flex flex-col gap-2">
                    <label className="block text-[10px] font-bold text-gray-400 uppercase">Search Setup</label>

                    <div className="flex gap-2">
                        <div className="flex-1">
                            <label className="block text-[9px] text-gray-500 mb-1">Total Voices</label>
                            <select 
                                value={options.ensembleTotal}
                                onChange={(e) => {
                                    const total = parseInt(e.target.value);
                                    const newSubj = Math.min(options.subjectVoiceIndex, total - 1);
                                    setOptions({ ...options, ensembleTotal: total, subjectVoiceIndex: newSubj });
                                }}
                                className="w-full bg-gray-800 border border-gray-600 rounded text-xs text-white px-1 py-1"
                            >
                                {Array.from({length: 7}, (_, i) => i + 2).map(num => (
                                    <option key={num} value={num}>{num} Voices</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex-1">
                            <label className="block text-[9px] text-gray-500 mb-1">Subject Voice</label>
                            <select 
                                value={options.subjectVoiceIndex}
                                onChange={(e) => handleChange('subjectVoiceIndex', parseInt(e.target.value))}
                                className="w-full bg-gray-800 border border-gray-600 rounded text-xs text-white px-1 py-1"
                            >
                                {Array.from({length: options.ensembleTotal}, (_, i) => i).map(idx => {
                                    const label = voiceNames?.[idx] || getVoiceLabel(idx, options.ensembleTotal);
                                    return <option key={idx} value={idx}>{label}</option>;
                                })}
                            </select>
                        </div>
                    </div>

                    <div className="flex-1 mt-1">
                        <label className="block text-[9px] text-gray-500 mb-1">Chain Length (Entries)</label>
                        <select 
                            value={options.targetChainLength}
                            onChange={(e) => handleChange('targetChainLength', parseInt(e.target.value))}
                            className="w-full bg-gray-800 border border-brand-primary/50 rounded text-xs text-white px-1 py-1"
                        >
                            {Array.from({length: 12}, (_, i) => i + 2).map(num => (
                                <option key={num} value={num}>{num} Entries</option>
                            ))}
                        </select>
                    </div>

                    <div className="text-[10px] text-gray-400 flex justify-between bg-black/20 p-1 rounded mt-1">
                        <span>↑ {availableAbove} Above</span>
                        <span className="font-bold text-brand-primary">S</span>
                        <span>↓ {availableBelow} Below</span>
                    </div>
                </div>

                {/* 2. Truncation (Col 4) */}
                <div className="lg:col-span-4 flex flex-col gap-2">
                    {renderConstraintSelector("Truncated Entries", "truncationMode", options.truncationMode)}
                    <div className={`flex flex-col gap-2 px-1 transition-opacity ${options.truncationMode === 'None' ? 'opacity-30 pointer-events-none' : ''}`}>
                        <div className="flex items-center gap-2">
                            <label className="text-[9px] text-gray-500 block">Cut Length (Beats)</label>
                            <input 
                                type="number" 
                                min="0.5" step="0.5"
                                value={options.truncationTargetBeats}
                                onChange={(e) => handleChange('truncationTargetBeats', parseFloat(e.target.value))}
                                className="w-16 bg-gray-900 border border-gray-600 text-xs rounded px-1 py-1 text-white text-center"
                            />
                        </div>
                        {truncationVisual}
                    </div>
                </div>

                {/* 3. Inversion (Col 2) */}
                <div className="lg:col-span-2 flex flex-col gap-2">
                    {renderConstraintSelector("Inverted Entries", "inversionMode", options.inversionMode)}
                    <div className={`flex flex-col gap-1 px-1 transition-opacity ${options.inversionMode === 'None' ? 'opacity-30 pointer-events-none' : ''}`}>
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] text-gray-500 whitespace-nowrap">Scale:</span>
                            <select 
                                value={options.scaleRoot}
                                onChange={(e) => handleChange('scaleRoot', parseInt(e.target.value))}
                                className="bg-gray-900 border border-gray-600 text-[10px] rounded px-1 py-0.5 text-gray-300 w-12"
                            >
                                {['C','C#','D','Eb','E','F','F#','G','Ab','A','Bb','B'].map((k, i) => (
                                    <option key={k} value={i}>{k}</option>
                                ))}
                            </select>
                            <select 
                                value={options.scaleMode}
                                onChange={(e) => handleChange('scaleMode', e.target.value)}
                                className="bg-gray-900 border border-gray-600 text-[10px] rounded px-1 py-0.5 text-gray-300 flex-grow"
                            >
                                {SCALE_MODES.map(m => (
                                    <option key={m} value={m}>{m}</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex items-center gap-2 mt-1">
                            <span className="text-[10px] text-gray-500 whitespace-nowrap">Pivot:</span>
                            <select 
                                value={options.pivotMidi}
                                onChange={(e) => handleChange('pivotMidi', parseInt(e.target.value))}
                                className="bg-gray-900 border border-gray-600 text-[10px] rounded px-1 py-0.5 text-gray-300 flex-grow"
                            >
                                {Array.from({length: 12}).map((_, i) => {
                                    const midi = 60 + i; 
                                    return <option key={midi} value={midi}>{getStrictPitchName(midi)}</option>
                                })}
                            </select>
                        </div>
                    </div>
                </div>

                {/* 4. Intervals (Col 3) */}
                <div className="lg:col-span-3 bg-gray-900 p-2 rounded border border-gray-700 flex flex-col gap-2">
                    {renderConstraintSelector("3rds & 6ths (from Subj)", "thirdSixthMode", options.thirdSixthMode)}

                    <div className="flex flex-col gap-2 mt-1">
                        <label className="flex items-center cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={options.requireConsonantEnd} 
                                onChange={(e) => handleChange('requireConsonantEnd', e.target.checked)} 
                                className="h-3 w-3 rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0"
                            />
                            <span className="ml-2 text-[10px] font-bold text-gray-300">Require Consonant End</span>
                        </label>

                        <label className="flex items-center cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={options.disallowComplexExceptions} 
                                onChange={(e) => handleChange('disallowComplexExceptions', e.target.checked)} 
                                className="h-3 w-3 rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0"
                            />
                            <span className="ml-2 text-[10px] font-bold text-gray-300" title="Prevents combining Inversion/Truncation with 3rd/6th intervals">Disallow Complex Exceptions</span>
                        </label>
                    </div>
                </div>
            </div>

            <button 
                onClick={onSearch}
                disabled={isSearching}
                className="w-full py-2 bg-brand-primary hover:bg-brand-secondary text-white font-bold rounded shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed text-sm uppercase tracking-wide"
            >
                {isSearching ? 'Processing Combinations...' : 'Run Search Algorithm v4.3'}
            </button>
        </div>
    );
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, ScoreLog, StrettoSearchReport } from '../../types';
import { SCORING, INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';
import { getVoiceLabel } from './midiVoices';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

interface SubjectVariant {
    type: 'N' | 'I';
    truncationBeats: number; // 0 for full
    notes: InternalNote[];
    length8: number;
}

interface PairCompatKey {
    delay8: number;
    transposition: number;
    typeA: 'N' | 'I';
    typeB: 'N' | 'I';
}

interface ValidationResult {
    isValid: boolean;
    polyphonyIntegral: number;
    dissonanceDuration: number;
    polyphonicDuration: number;
    errors: string[];
    detectedChords: string[];
    harmonicReward: number;
    harmonicPenalty: number;
}

// --- Precomputation: Scales & Inversion ---

const SCALE_INTERVALS: Record<string, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11],
    'Natural Minor': [0, 2, 3, 5, 7, 8, 10],
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11],
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Ascending assumed
    'Dorian': [0, 2, 3, 5, 7, 9, 10],
    'Phrygian': [0, 1, 3, 5, 7, 8, 10],
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10],
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

// Map pitch to (octave, degreeIndex)
// degreeIndex is 0-6 within the scale
function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; // Normalize to positive 0-11
    // Find closest scale step
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    // Calculate raw octave based on root
    // Note: This simple division assumes root is C(0). If root is say B(11), 
    // a C(12) is +1 semitone but same octave? No, usually relative to C.
    // Let's use absolute pitch logic.
    // We want a monotonic index: global_degree = octave * 7 + degree
    // Adjusted pitch relative to root:
    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; // Fallback

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        // Inversion logic: pivot - (current - pivot) = 2*pivot - current
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

// --- Phase 0: Normalization ---

function normalizeSubject(notes: RawNote[], ppq: number): InternalNote[] {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return [];

    // Resolve Polyphony: Monophonic assumption -> Keep Top Note
    // Group by start time tolerance
    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); // 32nd note bucket for clustering
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        // Sort by pitch desc, take top
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    return monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));
}

// --- Rules Logic ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
const PERFECT_INTERVALS = new Set([0, 7]);

function checkPair(
    variantA: SubjectVariant, 
    variantB: SubjectVariant, 
    delay8: number, 
    transposition: number
): { compatible: boolean } {
    // Overlay variantB onto variantA
    // variantB is shifted by delay8 and transposition

    const notesA = variantA.notes;
    const notesB = variantB.notes;

    // Timeline map: tick8 -> { pitchA, pitchB }
    // Only need to check overlap region
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    // Populate A
    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    // Populate B
    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) { // Only care about overlap
                timeline.get(tick)!.pB = n.pitch + transposition;
            }
        }
    });

    // Check Rules 5 & 6
    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    // Rule 6 accumulator
    let consecutiveDiss = 0;

    for (const t of ticks) {
        const state = timeline.get(t)!;
        if (state.pA === undefined || state.pB === undefined) {
            // Gap in overlap or end of overlap - reset tracking
            prevP1 = null; prevP2 = null;
            consecutiveDiss = 0;
            continue;
        }

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects
        if (prevP1 !== null && prevP2 !== null) {
            // Check motion
            if (p1 !== prevP1 && p2 !== prevP2) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) {
                        return { compatible: false }; // Fatal: Parallel Perfect
                    }
                }
            }
        }

        // Rule 6: Dissonance
        let isDiss = DISSONANT_INTERVALS.has(interval);
        // P4 (5) check against bass: if interval is 5, it is always against bass in 2-part
        if (interval === 5) isDiss = true; 

        if (isDiss) {
            consecutiveDiss++;
            if (consecutiveDiss > 2) return { compatible: false }; // Rule 6.C2: Max 2 events
        } else {
            consecutiveDiss = 0; // Resolution
        }

        prevP1 = p1; prevP2 = p2;
    }

    // Check if ended on Dissonance Run? (Rule 6.C3 Mandatory Resolution)
    if (consecutiveDiss > 0) return { compatible: false };

    return { compatible: true };
}

// --- Generator Class ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    // 1. Normalize Subject (8th note grid)
    const baseNotes = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    // 2. Generate Variants
    // Type: N (Normal), I (Inverted)
    // Truncation: 0, or Target (if set)
    const variants: SubjectVariant[] = [];

    // A. Rectus Full
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });

    // B. Inversus Full (Rule 10 Strict)
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }

    // C. Truncated Variants (Optional optimization: Generate on fly? No, precompute better for ID)
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            // Trunc Rectus
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            // Trunc Inversus
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    // 3. Phase 1: Compatibility Table
    // Key: `${typeA}_${typeB}_${delay8}_${transposition}` -> boolean
    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Pre-calculate compatibility for all variants vs all variants
    // Optimization: Since we build chains, we only compare NEW entry vs PREVIOUS entries.
    // We need to know if Variant X at Pos T is compatible with Variant Y at Pos 0.

    // Iterate all variant PAIRS
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    const res = checkPair(vA, vB, d, t);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    // 4. Phase 2: Delay Reachability (Forward/Backward)
    // Rule 1: d <= 2/3 L
    // Rule 2: d_next <= d_prev + 1.0 (8 ticks)
    // Rule 1B: Forced Contraction
    // Rule 1C: Late Stage Tightening (pos > 3 -> d < 1/2 L)

    // We compute sets validDelays[position]
    const posValidDelays: Set<number>[] = Array.from({length: options.targetChainLength}, () => new Set());

    // Initial: Pos 0 is fixed (Delay 0).
    // Pos 1 (Entry 2 relative to 1): Rule 1A
    validDelays.forEach(d => posValidDelays[1].add(d));

    // Forward Pass
    for (let i = 1; i < options.targetChainLength - 1; i++) {
        const prevSet = posValidDelays[i];
        const nextSet = posValidDelays[i+1];

        prevSet.forEach(dPrev => {
            // Determine range for dNext
            let maxNext = dPrev + 2; // Rule 2A: +1 beat (2 8ths)

            // Rule 1B: Forced Contraction
            if (dPrev > (subjectLength8 / 2)) {
                maxNext = Math.min(maxNext, dPrev - 1); 
            }

            // Rule 1C: Late Stage
            if ((i + 1) >= 3) { // 0-based index, so index 3 is 4th entry
                maxNext = Math.min(maxNext, Math.floor(subjectLength8 / 2) - 1);
            }

            // Generate valid successors
            for (let d = 1; d <= maxNext; d++) {
                // Rule 3: Anti-repetition (approx) - prefer non-equal if large
                // Strict rule: if dPrev >= 1/3 L, dNext != dPrev
                if (dPrev >= subjectLength8/3 && d === dPrev) continue;

                nextSet.add(d);
            }
        });
    }

    // Backward Pass (Pruning dead ends)
    for (let i = options.targetChainLength - 2; i >= 1; i--) {
        const currSet = posValidDelays[i];
        const nextSet = posValidDelays[i+1];
        const pruned = new Set<number>();

        currSet.forEach(dCurr => {
            let canReach = false;
            // Check if ANY dNext exists that satisfies transitions FROM dCurr
            for (const dNext of nextSet) {
                // Re-verify transition logic
                let maxNext = dCurr + 2;
                if (dCurr > (subjectLength8 / 2)) maxNext = Math.min(maxNext, dCurr - 1);
                if ((i + 1) >= 3) maxNext = Math.min(maxNext, Math.floor(subjectLength8 / 2) - 1);
                if (dCurr >= subjectLength8/3 && dNext === dCurr) continue;

                if (dNext <= maxNext) {
                    canReach = true;
                    break;
                }
            }
            if (canReach) pruned.add(dCurr);
        });
        posValidDelays[i] = pruned;
    }

    // --- Phase 5: Search ---

    const results: StrettoChainResult[] = [];

    // Initial Chain: Entry 1 (Subject Voice, Rectus, Full)
    // Note: Rule 11 says v(1) is fixed.
    const rootVariantIdx = 0; // Assume first is Rectus Full

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], // Keep track of which variant used
        voiceEndTimes8: number[], // For Rule 7 (Re-entry)
        nInv: number, 
        nTrunc: number,
        n3rd: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS) return;
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            // Full Chain Found!
            // Final validation (Global Harmonics if needed, though pairwise handled most)
            // Build Result
            const final = validateAndScore(chain, variants, variantIndices, options, ppq);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; // Index of next entry
        const prevEntry = chain[depth - 1];
        const prevDelay = depth > 1 ? prevEntry.startBeat - chain[depth-2].startBeat : 0; 
        const prevDelay8 = Math.round(prevDelay * 2); // To 8ths

        // 1. Determine Delays
        const possibleDelays8 = Array.from(posValidDelays[depth]); // Set to Array
        // Sort for heuristic? Small delays first?
        possibleDelays8.sort((a,b) => a - b);

        for (const delay8 of possibleDelays8) {
            // Rule 2B (Lookback)
            if (depth >= 3) {
                const dPrev = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                const dPrevPrev = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                if (dPrev > dPrevPrev) {
                    // Previous step was expansion
                    // Must contract: dNext < dPrev - w
                    let limit = dPrev;
                    if (dPrev > subjectLength8/3) limit = dPrev - 1;
                    if (delay8 > limit) continue; 
                }
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            // 2. Transpositions (Rule 8)
            for (const t of transpositions) {
                // Rule 1: Global Uniqueness of Delay not strictly enforced here but Anti-Repetition Rule 3 handles local.
                // Rule 4: Stratification (Voice Order) handled in Voice Loop

                // 3. Voices
                for (let v = 0; v < options.ensembleTotal; v++) {
                    // Rule 7: Re-entry
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; // Must be 1 beat (2 8ths) before end

                    // Rule 4A: Immediate Neighbor
                    // If v < v(prev), t >= t(prev)
                    // We need to check against currently active voices or just assignment?
                    // Spec: "s_vj >= s_v(j+1)". Voices ranked 1=High to N=Low.
                    // Meaning Voice 0 (High) should have Higher Pitch (Transposition).
                    // So T(0) >= T(1) >= T(2).
                    // We need to check against *assigned* voices in the chain.
                    // This is a constraint on the *set* of assignments.
                    // Simplified: We only check against the immediately adjacent voice if it is active?
                    // Actually, Stretto usually implies a fixed order of entry voices? No.
                    // Let's check against ANY entry currently active in voice v-1 or v+1.

                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];
                        const eStart8 = Math.round(e.startBeat * 2);
                        const eEnd8 = eStart8 + variants[variantIndices[existingIdx]].length8;

                        // Overlap?
                        if (absStart8 < eEnd8) { // Overlaps
                            if (e.voiceIndex === v - 1) {
                                // Neighbor Above (v-1). My T must be <= Their T
                                if (t > e.transposition) stratFail = true;
                            }
                            if (e.voiceIndex === v + 1) {
                                // Neighbor Below (v+1). My T must be >= Their T
                                if (t < e.transposition) stratFail = true;
                            }
                        }
                    }
                    if (stratFail) continue;

                    // 4. Variants
                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quotas
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;
                        const is3rd = [3,4,8,9].includes(Math.abs(t % 12));

                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;
                        if (is3rd && !checkQuota(options.thirdSixthMode, n3rd)) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && is3rd) continue;

                        // 5. Pairwise Compatibility Check (Phase 5 Check)
                        // Check this new entry against ALL overlapping previous entries
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            // Does it overlap?
                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;

                                // Look up compatibility (A=Prev, B=Curr)
                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        // Add to chain
                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * (ppq/2), // convert back to ticks? Or keep normalized?
                            // Types require ticks. length8 is 8th notes. ticks = length8 * ppq/2
                            voiceIndex: v
                        } as StrettoChainOption]; // Casting length temporarily

                        // Fix length in options to be consistent
                        nextChain[depth].length = variant.length8; // Store 8th duration for internal consistency logic? 
                        // Actually StrettoChainOption expects 'length' but context varies. 
                        // Let's standardise: ScoreGenerator expects length in TICKS? No, it handles specs.
                        // StrettoGenerator output usually consumed by StrettoChainView which expects...
                        // Re-reading StrettoChainView: "entryEnd = entryStartTick + (entry.length * (currentPpq/4))"
                        // It assumes length is in 16th notes! 
                        // My unit is 8th notes. So I should multiply by 2 for the output object.
                        nextChain[depth].length = variant.length8 * 2; 

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            n3rd + (is3rd?1:0)
                        );
                    }
                }
            }
        }
    }

    // Initial Setup for Solve
    const rootVoice = options.subjectVoiceIndex;
    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[rootVoice] = variants[0].length8;

    // Start!
    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: rootVoice }],
        [0],
        initialVoiceState,
        0, 0, 0
    );

    return {
        results: results.sort((a,b) => b.score - a.score).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

function validateAndScore(
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[], 
    options: StrettoSearchOptions, 
    ppq: number
): StrettoChainResult {
    // Re-run global harmonic check (Rule 6 Strict + Consonant End)
    // Build full timeline
    const timeline = new Map<number, {pitch: number, voice: number}[]>();

    // 16th note grid for detailed scoring
    const ticksPer8 = 1; // logical unit

    let totalPolyphony = 0;
    let dissonantMoments = 0;
    let polyphonicMoments = 0;
    let warnings: string[] = [];
    let detectedChords = new Set<string>();

    // Populate
    let maxT = 0;
    chain.forEach((e, i) => {
        const variant = variants[variantIndices[i]];
        const start8 = Math.round(e.startBeat * 2);

        variant.notes.forEach(n => {
            for (let t=0; t<n.dur8; t++) {
                const tick = start8 + n.relTick8 + t;
                if (!timeline.has(tick)) timeline.set(tick, []);
                timeline.get(tick)!.push({ 
                    pitch: n.pitch + e.transposition, 
                    voice: e.voiceIndex 
                });
                if (tick > maxT) maxT = tick;
            }
        });
    });

    // Analyze timeline
    for (let t=0; t<=maxT; t++) {
        const voices = timeline.get(t);
        if (!voices || voices.length === 0) continue;

        if (voices.length > 1) {
            totalPolyphony += (voices.length - 1.5);
            polyphonicMoments++;

            // Check Dissonance
            const pitches = voices.map(v => v.pitch).sort((a,b)=>a-b);
            const bass = pitches[0];
            const bassVoice = voices.find(v => v.pitch === bass)?.voice;

            let isDiss = false;
            for(let i=0; i<pitches.length; i++) {
                for(let j=i+1; j<pitches.length; j++) {
                    const int = (pitches[j] - pitches[i]) % 12;
                    if (DISSONANT_INTERVALS.has(int)) isDiss = true;
                    if (int === 5 && pitches[i] === bass) isDiss = true;
                }
            }
            if (isDiss) dissonantMoments++;

            // Identify Chord (Optional for display)
            // Use analyzeStrettoHarmony logic?
            const harmony = analyzeStrettoHarmony({[t*4]: convertToOldFormat(voices)}, [t*4]);
            if(harmony.chords.length>0) detectedChords.add(harmony.chords[0]);
        }
    }

    // Check Consonant End
    if (options.requireConsonantEnd) {
        // For each voice, check its last note
        chain.forEach((e, i) => {
            const variant = variants[variantIndices[i]];
            const start8 = Math.round(e.startBeat * 2);
            const end8 = start8 + variant.length8;
            const lastMoment = end8 - 1;

            const voices = timeline.get(lastMoment);
            if (voices && voices.length > 1) {
                // Must be consonant with at least one other voice? 
                // Or globally consonant? Strict Rule: "IsDiss(t) = false" at resolution?
                // Let's check if *this* voice forms a dissonance.
                const myPitch = voices.find(v => v.voice === e.voiceIndex)?.pitch;
                if (myPitch !== undefined) {
                    const others = voices.filter(v => v.voice !== e.voiceIndex);
                    const pitches = [myPitch, ...others.map(o => o.pitch)].sort((a,b)=>a-b);
                    // Simplified: check if moment is dissonant
                    // See loop above.
                }
            }
        });
    }

    const dissRatio = polyphonicMoments > 0 ? dissonantMoments / polyphonicMoments : 0;

    // Scoring
    let score = 1000;
    const log: ScoreLog = { base: 1000, bonuses: [], penalties: [], total: 0 };

    // Polyphony Bonus
    const polyScore = Math.round(totalPolyphony * 50);
    score += polyScore;
    log.bonuses.push({ reason: "Polyphony", points: polyScore });

    // Dissonance Penalty
    if (dissRatio > 0.4) {
        const pen = Math.round((dissRatio - 0.4) * 2000);
        score -= pen;
        log.penalties.push({ reason: "High Dissonance", points: pen });
    }

    // Variety Bonus
    const uniqueTrans = new Set(chain.map(e => e.transposition)).size;
    if (uniqueTrans > 2) {
        score += (uniqueTrans * 50);
        log.bonuses.push({ reason: "Harmonic Variety", points: uniqueTrans * 50 });
    }

    // Compactness Bonus (Hyper Stretto)
    // Avg delay
    let totalDelay = 0;
    for(let i=1; i<chain.length; i++) totalDelay += (chain[i].startBeat - chain[i-1].startBeat);
    const avgDelay = totalDelay / (chain.length - 1);
    if (avgDelay <= 1.0) {
        score += 200;
        log.bonuses.push({ reason: "Hyper-Compact", points: 200 });
    }

    log.total = score;

    return {
        id: Math.random().toString(36),
        entries: chain,
        warnings,
        score,
        scoreLog: log,
        detectedChords: Array.from(detectedChords),
        dissonanceRatio: dissRatio,
        pairDissonanceScore: 0
    };
}

// Adapter for legacy harmony analyzer
function convertToOldFormat(voices: {pitch: number, voice: number}[]) {
    const map: any = {};
    voices.forEach(v => {
        map[v.voice] = { pitch: v.pitch, dur16: 4 };
    });
    return map;
}

