const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

interface SubjectVariant {
    type: 'N' | 'I';
    truncationBeats: number; // 0 for full
    notes: InternalNote[];
