// --- Precomputation: Scales & Inversion ---

const SCALE_INTERVALS: Record<string, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11],
    'Natural Minor': [0, 2, 3, 5, 7, 8, 10],
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11],
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Ascending assumed
    'Dorian': [0, 2, 3, 5, 7, 9, 10],
    'Phrygian': [0, 1, 3, 5, 7, 8, 10],
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10],
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

// Map pitch to (octave, degreeIndex)
// degreeIndex is 0-6 within the scale
function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; // Normalize to positive 0-11
    // Find closest scale step
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    // Calculate raw octave based on root
    // Note: This simple division assumes root is C(0). If root is say B(11), 
    // a C(12) is +1 semitone but same octave? No, usually relative to C.
    // Let's use absolute pitch logic.
    // We want a monotonic index: global_degree = octave * 7 + degree
    // Adjusted pitch relative to root:
    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; // Fallback

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        // Inversion logic: pivot - (current - pivot) = 2*pivot - current
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

// --- Phase 0: Normalization ---

function normalizeSubject(notes: RawNote[], ppq: number): InternalNote[] {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return [];

    // Resolve Polyphony: Monophonic assumption -> Keep Top Note
    // Group by start time tolerance
    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); // 32nd note bucket for clustering
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        // Sort by pitch desc, take top
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    return monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));
}

// --- Rules Logic ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
const PERFECT_INTERVALS = new Set([0, 7]);

function checkPair(
    variantA: SubjectVariant, 
    variantB: SubjectVariant, 
    delay8: number, 
    transposition: number
): { compatible: boolean } {
    // Overlay variantB onto variantA
    // variantB is shifted by delay8 and transposition

    const notesA = variantA.notes;
    const notesB = variantB.notes;

    // Timeline map: tick8 -> { pitchA, pitchB }
    // Only need to check overlap region
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    // Populate A
    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    // Populate B
    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) { // Only care about overlap
                timeline.get(tick)!.pB = n.pitch + transposition;
            }
        }
    });

    // Check Rules 5 & 6
    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    // Rule 6 accumulator
    let consecutiveDiss = 0;

    for (const t of ticks) {
        const state = timeline.get(t)!;
        if (state.pA === undefined || state.pB === undefined) {
            // Gap in overlap or end of overlap - reset tracking
            prevP1 = null; prevP2 = null;
            consecutiveDiss = 0;
            continue;
        }

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects
        if (prevP1 !== null && prevP2 !== null) {
            // Check motion
            if (p1 !== prevP1 && p2 !== prevP2) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) {
                        return { compatible: false }; // Fatal: Parallel Perfect
                    }
                }
            }
        }

        // Rule 6: Dissonance
        let isDiss = DISSONANT_INTERVALS.has(interval);
        // P4 (5) check against bass: if interval is 5, it is always against bass in 2-part
        if (interval === 5) isDiss = true; 

        if (isDiss) {
            consecutiveDiss++;
            if (consecutiveDiss > 2) return { compatible: false }; // Rule 6.C2: Max 2 events
        } else {
            consecutiveDiss = 0; // Resolution
        }

        prevP1 = p1; prevP2 = p2;
    }

    // Check if ended on Dissonance Run? (Rule 6.C3 Mandatory Resolution)
    if (consecutiveDiss > 0) return { compatible: false };

    return { compatible: true };
}

// --- Generator Class ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    // 1. Normalize Subject (8th note grid)
    const baseNotes = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    // 2. Generate Variants
    // Type: N (Normal), I (Inverted)
    // Truncation: 0, or Target (if set)
    const variants: SubjectVariant[] = [];

    // A. Rectus Full
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });

    // B. Inversus Full (Rule 10 Strict)
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }

    // C. Truncated Variants (Optional optimization: Generate on fly? No, precompute better for ID)
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            // Trunc Rectus
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            // Trunc Inversus
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    // 3. Phase 1: Compatibility Table
    // Key: `${typeA}_${typeB}_${delay8}_${transposition}` -> boolean
    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Pre-calculate compatibility for all variants vs all variants
    // Optimization: Since we build chains, we only compare NEW entry vs PREVIOUS entries.
    // We need to know if Variant X at Pos T is compatible with Variant Y at Pos 0.

    // Iterate all variant PAIRS
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    const res = checkPair(vA, vB, d, t);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    // 4. Phase 2: Delay Reachability (Forward/Backward)
    // Rule 1: d <= 2/3 L
    // Rule 2: d_next <= d_prev + 1.0 (8 ticks)
    // Rule 1B: Forced Contraction
    // Rule 1C: Late Stage Tightening (pos > 3 -> d < 1/2 L)

    // We compute sets validDelays[position]
    const posValidDelays: Set<number>[] = Array.from({length: options.targetChainLength}, () => new Set());

    // Initial: Pos 0 is fixed (Delay 0).
    // Pos 1 (Entry 2 relative to 1): Rule 1A
    validDelays.forEach(d => posValidDelays[1].add(d));

    // Forward Pass
    for (let i = 1; i < options.targetChainLength - 1; i++) {
        const prevSet = posValidDelays[i];
        const nextSet = posValidDelays[i+1];

        prevSet.forEach(dPrev => {
            // Determine range for dNext
            let maxNext = dPrev + 2; // Rule 2A: +1 beat (2 8ths)

            // Rule 1B: Forced Contraction
            if (dPrev > (subjectLength8 / 2)) {
                maxNext = Math.min(maxNext, dPrev - 1); 
            }

            // Rule 1C: Late Stage
            if ((i + 1) >= 3) { // 0-based index, so index 3 is 4th entry
                maxNext = Math.min(maxNext, Math.floor(subjectLength8 / 2) - 1);
            }

            // Generate valid successors
            for (let d = 1; d <= maxNext; d++) {
                // Rule 3: Anti-repetition (approx) - prefer non-equal if large
                // Strict rule: if dPrev >= 1/3 L, dNext != dPrev
                if (dPrev >= subjectLength8/3 && d === dPrev) continue;

                nextSet.add(d);
            }
        });
    }

    // Backward Pass (Pruning dead ends)
    for (let i = options.targetChainLength - 2; i >= 1; i--) {
        const currSet = posValidDelays[i];
        const nextSet = posValidDelays[i+1];
        const pruned = new Set<number>();

        currSet.forEach(dCurr => {
            let canReach = false;
            // Check if ANY dNext exists that satisfies transitions FROM dCurr
            for (const dNext of nextSet) {
                // Re-verify transition logic
                let maxNext = dCurr + 2;
                if (dCurr > (subjectLength8 / 2)) maxNext = Math.min(maxNext, dCurr - 1);
                if ((i + 1) >= 3) maxNext = Math.min(maxNext, Math.floor(subjectLength8 / 2) - 1);
                if (dCurr >= subjectLength8/3 && dNext === dCurr) continue;

                if (dNext <= maxNext) {
                    canReach = true;
                    break;
                }
            }
            if (canReach) pruned.add(dCurr);
        });
        posValidDelays[i] = pruned;
    }

    // --- Phase 5: Search ---

    const results: StrettoChainResult[] = [];

    // Initial Chain: Entry 1 (Subject Voice, Rectus, Full)
    // Note: Rule 11 says v(1) is fixed.
    const rootVariantIdx = 0; // Assume first is Rectus Full

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], // Keep track of which variant used
        voiceEndTimes8: number[], // For Rule 7 (Re-entry)
        nInv: number, 
        nTrunc: number,
        n3rd: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS) return;
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            // Full Chain Found!
            // Final validation (Global Harmonics if needed, though pairwise handled most)
            // Build Result
            const final = validateAndScore(chain, variants, variantIndices, options, ppq);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; // Index of next entry
        const prevEntry = chain[depth - 1];
        const prevDelay = depth > 1 ? prevEntry.startBeat - chain[depth-2].startBeat : 0; 
        const prevDelay8 = Math.round(prevDelay * 2); // To 8ths

        // 1. Determine Delays
        const possibleDelays8 = Array.from(posValidDelays[depth]); // Set to Array
        // Sort for heuristic? Small delays first?
        possibleDelays8.sort((a,b) => a - b);

        for (const delay8 of possibleDelays8) {
            // Rule 2B (Lookback)
            if (depth >= 3) {
                const dPrev = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                const dPrevPrev = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                if (dPrev > dPrevPrev) {
                    // Previous step was expansion
                    // Must contract: dNext < dPrev - w
                    let limit = dPrev;
                    if (dPrev > subjectLength8/3) limit = dPrev - 1;
                    if (delay8 > limit) continue; 
                }
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            // 2. Transpositions (Rule 8)
            for (const t of transpositions) {
                // Rule 1: Global Uniqueness of Delay not strictly enforced here but Anti-Repetition Rule 3 handles local.
                // Rule 4: Stratification (Voice Order) handled in Voice Loop

                // 3. Voices
                for (let v = 0; v < options.ensembleTotal; v++) {
                    // Rule 7: Re-entry
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; // Must be 1 beat (2 8ths) before end

                    // Rule 4A: Immediate Neighbor
                    // If v < v(prev), t >= t(prev)
                    // We need to check against currently active voices or just assignment?
                    // Spec: "s_vj >= s_v(j+1)". Voices ranked 1=High to N=Low.
                    // Meaning Voice 0 (High) should have Higher Pitch (Transposition).
                    // So T(0) >= T(1) >= T(2).
                    // We need to check against *assigned* voices in the chain.
                    // This is a constraint on the *set* of assignments.
                    // Simplified: We only check against the immediately adjacent voice if it is active?
                    // Actually, Stretto usually implies a fixed order of entry voices? No.
                    // Let's check against ANY entry currently active in voice v-1 or v+1.

                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];
                        const eStart8 = Math.round(e.startBeat * 2);
                        const eEnd8 = eStart8 + variants[variantIndices[existingIdx]].length8;

                        // Overlap?
                        if (absStart8 < eEnd8) { // Overlaps
                            if (e.voiceIndex === v - 1) {
                                // Neighbor Above (v-1). My T must be <= Their T
                                if (t > e.transposition) stratFail = true;
                            }
                            if (e.voiceIndex === v + 1) {
                                // Neighbor Below (v+1). My T must be >= Their T
                                if (t < e.transposition) stratFail = true;
                            }
                        }
                    }
                    if (stratFail) continue;

                    // 4. Variants
                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quotas
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;
                        const is3rd = [3,4,8,9].includes(Math.abs(t % 12));

                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;
                        if (is3rd && !checkQuota(options.thirdSixthMode, n3rd)) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && is3rd) continue;

                        // 5. Pairwise Compatibility Check (Phase 5 Check)
                        // Check this new entry against ALL overlapping previous entries
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            // Does it overlap?
                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;

                                // Look up compatibility (A=Prev, B=Curr)
                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        // Add to chain
                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * (ppq/2), // convert back to ticks? Or keep normalized?
                            // Types require ticks. length8 is 8th notes. ticks = length8 * ppq/2
                            voiceIndex: v
                        } as StrettoChainOption]; // Casting length temporarily

                        // Fix length in options to be consistent
                        nextChain[depth].length = variant.length8; // Store 8th duration for internal consistency logic? 
                        // Actually StrettoChainOption expects 'length' but context varies. 
                        // Let's standardise: ScoreGenerator expects length in TICKS? No, it handles specs.
                        // StrettoGenerator output usually consumed by StrettoChainView which expects...
                        // Re-reading StrettoChainView: "entryEnd = entryStartTick + (entry.length * (currentPpq/4))"
                        // It assumes length is in 16th notes! 
                        // My unit is 8th notes. So I should multiply by 2 for the output object.
                        nextChain[depth].length = variant.length8 * 2; 

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            n3rd + (is3rd?1:0)
                        );
                    }
                }
            }
        }
    }

    // Initial Setup for Solve
    const rootVoice = options.subjectVoiceIndex;
    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[rootVoice] = variants[0].length8;

    // Start!
    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: rootVoice }],
        [0],
        initialVoiceState,
        0, 0, 0
    );

    return {
        results: results.sort((a,b) => b.score - a.score).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

function validateAndScore(
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[], 
    options: StrettoSearchOptions, 
    ppq: number
): StrettoChainResult {
    // Re-run global harmonic check (Rule 6 Strict + Consonant End)
    // Build full timeline
    const timeline = new Map<number, {pitch: number, voice: number}[]>();

    // 16th note grid for detailed scoring
    const ticksPer8 = 1; // logical unit

    let totalPolyphony = 0;
    let dissonantMoments = 0;
    let polyphonicMoments = 0;
    let warnings: string[] = [];
    let detectedChords = new Set<string>();

    // Populate
    let maxT = 0;
    chain.forEach((e, i) => {
        const variant = variants[variantIndices[i]];
        const start8 = Math.round(e.startBeat * 2);

        variant.notes.forEach(n => {
            for (let t=0; t<n.dur8; t++) {
                const tick = start8 + n.relTick8 + t;
                if (!timeline.has(tick)) timeline.set(tick, []);
                timeline.get(tick)!.push({ 
                    pitch: n.pitch + e.transposition, 
                    voice: e.voiceIndex 
                });
                if (tick > maxT) maxT = tick;
            }
        });
    });

    // Analyze timeline
    for (let t=0; t<=maxT; t++) {
        const voices = timeline.get(t);
        if (!voices || voices.length === 0) continue;

        if (voices.length > 1) {
            totalPolyphony += (voices.length - 1.5);
            polyphonicMoments++;

            // Check Dissonance
            const pitches = voices.map(v => v.pitch).sort((a,b)=>a-b);
            const bass = pitches[0];

            let isDiss = false;
            for(let i=0; i<pitches.length; i++) {
                for(let j=i+1; j<pitches.length; j++) {
                    const int = (pitches[j] - pitches[i]) % 12;
                    if (DISSONANT_INTERVALS.has(int)) isDiss = true;
                    if (int === 5 && pitches[i] === bass) isDiss = true;
                }
            }
            if (isDiss) dissonantMoments++;

            // Identify Chord (Optional for display)
            // Use analyzeStrettoHarmony logic?
            const harmony = analyzeStrettoHarmony({[t*4]: convertToOldFormat(voices)}, [t*4]);
            if(harmony.chords.length>0) detectedChords.add(harmony.chords[0]);
        }
    }

    // Check Consonant End
    let isValid = true;
    if (options.requireConsonantEnd) {
        // For each voice, check its last note
        chain.forEach((e, i) => {
            const variant = variants[variantIndices[i]];
            const start8 = Math.round(e.startBeat * 2);
            const end8 = start8 + variant.length8;
            const lastMoment = end8 - 1;

            const voices = timeline.get(lastMoment);
            if (voices && voices.length > 1) {
                // Must be consonant with at least one other voice? 
                // Or globally consonant? Strict Rule: "IsDiss(t) = false" at resolution?
                // Let's check if *this* voice forms a dissonance.
                const myPitch = voices.find(v => v.voice === e.voiceIndex)?.pitch;
                if (myPitch !== undefined) {
                    const others = voices.filter(v => v.voice !== e.voiceIndex);
                    const pitches = [myPitch, ...others.map(o => o.pitch)].sort((a,b)=>a-b);

                    let isDiss = false;
                    for(let k=0; k<pitches.length; k++) {
                        for(let j=k+1; j<pitches.length; j++) {
                            const int = (pitches[j] - pitches[k]) % 12;
                            if (DISSONANT_INTERVALS.has(int)) isDiss = true;
                            if (int === 5 && pitches[k] === pitches[0]) isDiss = true;
                        }
                    }
                    if (isDiss) isValid = false;
                }
            }
        });
    }

    const dissRatio = polyphonicMoments > 0 ? dissonantMoments / polyphonicMoments : 0;

    // Scoring
    let score = 1000;
    const log: ScoreLog = { base: 1000, bonuses: [], penalties: [], total: 0 };

    // Polyphony Bonus
    const polyScore = Math.round(totalPolyphony * 50);
    score += polyScore;
    log.bonuses.push({ reason: "Polyphony", points: polyScore });

    // Dissonance Penalty
    if (dissRatio > 0.4) {
        const pen = Math.round((dissRatio - 0.4) * 2000);
        score -= pen;
        log.penalties.push({ reason: "High Dissonance", points: pen });
    }

    // Variety Bonus
    const uniqueTrans = new Set(chain.map(e => e.transposition)).size;
    if (uniqueTrans > 2) {
        score += (uniqueTrans * 50);
        log.bonuses.push({ reason: "Harmonic Variety", points: uniqueTrans * 50 });
    }

    // Compactness Bonus (Hyper Stretto)
    // Avg delay
    let totalDelay = 0;
    for(let i=1; i<chain.length; i++) totalDelay += (chain[i].startBeat - chain[i-1].startBeat);
    const avgDelay = totalDelay / (chain.length - 1);
    if (avgDelay <= 1.0) {
        score += 200;
        log.bonuses.push({ reason: "Hyper-Compact", points: 200 });
    }

    log.total = score;

    return {
        id: Math.random().toString(36),
        entries: chain,
        warnings,
        score,
        scoreLog: log,
        detectedChords: Array.from(detectedChords),
        dissonanceRatio: dissRatio,
        pairDissonanceScore: 0,
        isValid
    };
}

// Adapter for legacy harmony analyzer
function convertToOldFormat(voices: {pitch: number, voice: number}[]) {
    const map: any = {};
    voices.forEach(v => {
        map[v.voice] = { pitch: v.pitch, dur16: 4 };
    });
    return map;
}

import { RawNote } from '../../types';

// Standard ABC Pitch Mapping
// C = Middle C (MIDI 60)
// c = C5 (MIDI 72)
const BASE_PITCHES: Record<string, number> = {
    'C': 60, 'D': 62, 'E': 64, 'F': 65, 'G': 67, 'A': 69, 'B': 71,
    'c': 72, 'd': 74, 'e': 76, 'f': 77, 'g': 79, 'a': 81, 'b': 83
};

// Key Signature Definitions (Standard sharps/flats for Major keys)
const KEY_SIGNATURES: Record<string, Record<string, number>> = {
    'C':  {},
    'G':  { 'f': 1,  'F': 1 },
    'D':  { 'f': 1,  'F': 1, 'c': 1, 'C': 1 },
    'A':  { 'f': 1,  'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1 },
    'E':  { 'f': 1,  'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1 },
    'B':  { 'f': 1,  'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1, 'a': 1, 'A': 1 },
    'F#': { 'f': 1,  'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1, 'a': 1, 'A': 1, 'e': 1, 'E': 1 },
    'GB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1, 'g': -1, 'G': -1, 'c': -1, 'C': -1 },
    'F':  { 'b': -1, 'B': -1 },
    'Bb': { 'b': -1, 'B': -1, 'e': -1, 'E': -1 },
    'EB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1 },
    'AB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1 },
    'DB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1, 'g': -1, 'G': -1 },
    'CB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1, 'g': -1, 'G': -1, 'c': -1, 'C': -1, 'f': -1, 'F': -1 },
};

function getBaseMidi(char: string): number {
    return BASE_PITCHES[char] || 60;
}

export function extractKeyFromAbc(abc: string): { root: number, mode: string } | null {
    const lines = abc.split(/\r?\n/);
    for (const line of lines) {
        const m = line.trim().match(/^K\s*:\s*(.*)/i);
        if (m) {
            const val = m[1].trim();
            // Regex to grab pitch (Letter + optional acc) + remainder (mode)
            const pMatch = val.match(/^([A-G][#b]?)(.*)/i);
            if (pMatch) {
                const pitchStr = pMatch[1];
                let modeStr = pMatch[2].trim().toLowerCase();

                // Determine Root
                const baseLetter = pitchStr.charAt(0).toUpperCase();
                let root = getBaseMidi(baseLetter) % 12;

                if (pitchStr.length > 1) {
                    const acc = pitchStr.charAt(1);
                    if (acc === '#') root = (root + 1) % 12;
                    if (acc === 'b') root = (root + 11) % 12;
                }

                // Determine Mode
                let mode = 'Major'; // Default
                if ((modeStr.startsWith('m') && !modeStr.startsWith('mix') && !modeStr.startsWith('maj')) || modeStr === 'min') {
                    mode = 'Natural Minor';
                }
                if (modeStr.includes('maj')) mode = 'Major';
                if (modeStr.includes('dor')) mode = 'Dorian';
                if (modeStr.includes('phr')) mode = 'Phrygian';
                if (modeStr.includes('lyd')) mode = 'Lydian';
                if (modeStr.includes('mix')) mode = 'Mixolydian';
                if (modeStr.includes('loc')) mode = 'Locrian';

                return { root, mode };
            }
        }
    }
    return null;
}

export function parseSimpleAbc(abcString: string, ppq: number = 480): RawNote[] {
    const lines = abcString.split(/\r?\n/);

    // Default Context
    let keyAccidentals: Record<string, number> = {};
    let defaultNoteLength = 1/8; 
    let tempo = 120;

    const notes: RawNote[] = [];
    let currentTick = 0;

    // 1. Parse Headers
    let bodyStartLine = 0;
    for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (line.length === 0) continue;

        // Relaxed regex: Allows space before colon (e.g., "K : F#")
        const headerMatch = line.match(/^([A-Za-z])\s*:\s*(.*)/);

        if (headerMatch) {
            const field = headerMatch[1].toUpperCase();
            const value = headerMatch[2].trim();

            if (field === 'K') {
                // Normalize key string (e.g. "F# Major" -> "F#")
                const keyClean = value.toUpperCase()
                    .replace('MAJ', '')
                    .replace('OR', '')
                    .replace('MIN', '')
                    .trim()
                    .split(/\s+/)[0]; 

                if (KEY_SIGNATURES[keyClean]) {
                    keyAccidentals = { ...KEY_SIGNATURES[keyClean] };
                } else {
                    keyAccidentals = {};
                }
            } else if (field === 'L') {
                const parts = value.split('/');
                if (parts.length === 2) {
                    const num = parseFloat(parts[0]);
                    const den = parseFloat(parts[1]);
                    if (!isNaN(num) && !isNaN(den) && den !== 0) defaultNoteLength = num / den;
                }
            } else if (field === 'Q') {
                if (value.includes('=')) tempo = parseFloat(value.split('=')[1]);
                else tempo = parseFloat(value);
            }
        } else {
            // Stop at first non-header line (likely notes or comment)
            if (!line.startsWith('%')) {
                bodyStartLine = i;
                break;
            }
        }
    }

    // 2. Parse Notes
    const bodyText = lines.slice(bodyStartLine).join(' ');
    // Match Accidental + Note + Octave + Duration
    const regex = /([\^=_]*)?([a-gA-GzZxX])([,']*)?([0-9]*\/?[0-9]*)?/g;

    let match;
    const wholeNoteTicks = ppq * 4;

    while ((match = regex.exec(bodyText)) !== null) {
        if (match[0] === '') continue;

        const accStr = match[1] || '';
        const letter = match[2];
        const octStr = match[3] || '';
        const lenStr = match[4] || '';

        if (!letter) continue;

        // Calculate Duration
        let durMult = 1.0;
        if (lenStr) {
            if (lenStr === '/') durMult = 0.5;
            else if (lenStr === '//') durMult = 0.25;
            else if (lenStr.startsWith('/')) {
                durMult = 1 / parseFloat(lenStr.substring(1));
            } else if (lenStr.includes('/')) {
                const [n, d] = lenStr.split('/');
                const num = n === '' ? 1 : parseFloat(n);
                const den = d === '' ? 1 : parseFloat(d); 
                durMult = num / den;
            } else {
                durMult = parseFloat(lenStr);
            }
        }

        const durationTicks = Math.round(wholeNoteTicks * defaultNoteLength * durMult);

        if (['z', 'Z', 'x', 'X'].includes(letter)) {
            currentTick += durationTicks;
            continue;
        }

        let midi = getBaseMidi(letter);
        let accidentalOffset = 0;

        // --- Accidental Logic ---

        if (accStr !== '') {
            if (accStr.includes('^^')) accidentalOffset = 2;
            else if (accStr.includes('^')) accidentalOffset = 1;
            else if (accStr.includes('__')) accidentalOffset = -2;
            else if (accStr.includes('_')) accidentalOffset = -1;
            else if (accStr.includes('=')) accidentalOffset = 0; 
        } 
        else if (keyAccidentals[letter] !== undefined) {
            accidentalOffset = keyAccidentals[letter];
        }

        midi += accidentalOffset;

        // Apply Octaves
        if (octStr) {
            const up = (octStr.match(/'/g) || []).length;
            const down = (octStr.match(/,/g) || []).length;
            midi += (up * 12) - (down * 12);
        }

        notes.push({
            midi,
            ticks: currentTick,
            durationTicks,
            velocity: 0.8,
            name: `${accStr}${letter}${octStr}`,
            isOrnament: false
        });

        currentTick += durationTicks;
    }

    return notes;
}

