import React, { useState } from 'react';
import { StrettoChainResult, StrettoChainOption, ScoreLog } from '../../types';
import { getIntervalLabel } from '../services/midiSpelling';
import { getVoiceLabel } from '../services/midiVoices';

interface StrettoResultsListProps {
    results: StrettoChainResult[];
    selectedId: string | null;
    onSelect: (res: StrettoChainResult) => void;
    voiceNames?: Record<number, string>;
}

export default function StrettoResultsList({ results, selectedId, onSelect, voiceNames }: StrettoResultsListProps) {
    const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
    const [scoreTooltipId, setScoreTooltipId] = useState<string | null>(null);

    if (results.length === 0) {
        return <div className="text-center text-gray-500 py-10">No chains found yet. Run the search to begin.</div>;
    }

    const toggleExpand = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setExpandedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const formatInterval = (semis: number) => {
        // getIntervalLabel now handles the sign correctly (+P5, -P5, +P12)
        // We just pass absolute first to normalize, then apply sign if needed? 
        // Actually midiSpelling expects raw semis for sign.
        return getIntervalLabel(semis);
    };

    const getVoiceCode = (idx: number, total: number) => {
        if (voiceNames && voiceNames[idx]) return voiceNames[idx];

        const label = getVoiceLabel(idx, total);
        if (label.includes(' ')) {
            const parts = label.split(' ');
            return `${parts[0].charAt(0)}${parts[1]}`;
        }
        return label.charAt(0);
    };

    const renderScoreTooltip = (log?: ScoreLog) => {
        if (!log) return null;
        return (
            <div className="absolute right-0 top-full mt-2 z-50 w-64 bg-black border border-gray-600 rounded p-3 shadow-xl text-xs text-gray-300">
                <div className="font-bold text-gray-200 border-b border-gray-600 pb-1 mb-2">Score Breakdown ({log.total.toFixed(0)})</div>
                <div className="flex justify-between mb-1"><span>Base</span><span>{log.base}</span></div>
                {log.bonuses.map((b, i) => (
                    <div key={`b-${i}`} className="flex justify-between text-green-400"><span>+ {b.reason}</span><span>{b.points}</span></div>
                ))}
                {log.penalties.map((p, i) => (
                    <div key={`p-${i}`} className="flex justify-between text-red-400"><span>- {p.reason}</span><span>{p.points}</span></div>
                ))}
            </div>
        );
    };

    const renderChainBadges = (entries: StrettoChainOption[], isSub: boolean = false) => {
        const maxV = Math.max(...entries.map(e => e.voiceIndex)) + 1;
        const totalEstimate = Math.max(4, maxV); 

        return entries.map((e, idx) => {
            const vCode = getVoiceCode(e.voiceIndex, totalEstimate);

            if (idx === 0) {
                return (
                    <div key={idx} className={`flex flex-col items-center bg-gray-800 p-1 rounded border border-gray-700 ${isSub ? 'min-w-[40px] scale-90 origin-left' : 'min-w-[50px]'}`}>
                        <span className="text-[10px] font-bold text-brand-primary truncate max-w-[50px]" title={vCode}>{vCode}</span>
                        <span className="text-xs text-white font-mono">Subj</span>
                    </div>
                );
            }

            const absInt = e.transposition; 
            const prev = entries[idx-1];
            const relDist = e.startBeat - prev.startBeat;
            const absDist = e.startBeat;

            let typeLabel = e.type === 'I' ? 'INV' : 'NOR';
            let lenLabel = e.length < entries[0].length ? 'TRC' : 'FUL';

            const borderClass = (e.type === 'I' || lenLabel === 'TRC') ? 'border-brand-primary' : 'border-gray-600';

            return (
                <div key={idx} className={`flex flex-col bg-gray-800 p-1 rounded border ${borderClass} ${isSub ? 'min-w-[50px] scale-90 origin-left' : 'min-w-[60px]'}`}>
                    <div className="flex justify-between border-b border-gray-700 pb-0.5 mb-0.5">
                        <span className="text-[9px] font-bold text-gray-300 truncate max-w-[40px]" title={vCode}>{vCode}</span>
                        <span className={`text-[8px] font-bold ${lenLabel === 'TRC' ? 'text-orange-300' : 'text-gray-500'}`}>{lenLabel}</span>
                    </div>

                    <div className="flex flex-col items-center mb-0.5">
                        <span className="text-[10px] text-brand-primary font-bold">{formatInterval(absInt)}</span>
                        {e.type === 'I' && <span className="text-[8px] text-blue-300">INVERT</span>}
                    </div>

                    <div className="flex gap-1 text-[9px] font-mono" title={`Delay: +${relDist} / Start: @${absDist}`}>
                        <span className="text-gray-400 w-1/2 text-center border-r border-gray-700">+{relDist.toFixed(1)}</span>
                        <span className="text-white w-1/2 text-center">@{absDist.toFixed(1)}</span>
                    </div>
                </div>
            );
        });
    };

    return (
        <div className="overflow-y-auto max-h-[500px] pb-20">
            {results.map((res, i) => {
                const hasVariations = res.variations && res.variations.length > 0;
                const isExpanded = expandedIds.has(res.id);
                const isSelected = selectedId === res.id;
                const showTooltip = scoreTooltipId === res.id;

                return (
                    <div key={res.id} className="border-b border-gray-700 bg-gray-900/50 relative">
                        {/* Leader Row */}
                        <div 
                            onClick={() => onSelect(res)}
                            className={`p-2 cursor-pointer hover:bg-gray-800 transition-colors flex flex-col gap-2 ${isSelected ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                        >
                            <div className="flex justify-between items-center">
                                <div className="flex items-center gap-2">
                                    {hasVariations && (
                                        <button 
                                            onClick={(e) => toggleExpand(e, res.id)}
                                            className="text-gray-400 hover:text-white text-xs bg-gray-700 px-1.5 rounded"
                                        >
                                            {isExpanded ? '▼' : '▶'}
                                        </button>
                                    )}
                                    <span className="font-bold text-gray-300 text-xs">Chain #{i + 1}</span>
                                    {hasVariations && (
                                        <span className="text-[10px] bg-brand-primary/20 text-brand-primary px-1.5 rounded">
                                            +{res.variations?.length} Vars
                                        </span>
                                    )}
                                </div>
                                <div className="relative">
                                    <button 
                                        onMouseEnter={() => setScoreTooltipId(res.id)}
                                        onMouseLeave={() => setScoreTooltipId(null)}
                                        className="text-[9px] bg-black/30 px-1.5 rounded text-gray-500 hover:text-white cursor-help"
                                    >
                                        Score: {res.score.toFixed(0)}
                                    </button>
                                    {showTooltip && renderScoreTooltip(res.scoreLog)}
                                </div>
                            </div>

                            {/* Detected Chords Summary */}
                            {res.detectedChords && res.detectedChords.length > 0 && (
                                <div className="flex gap-1 overflow-hidden">
                                    {res.detectedChords.map((c, idx) => (
                                        <span key={idx} className="text-[9px] text-gray-400 bg-black/20 px-1 rounded whitespace-nowrap">{c}</span>
                                    ))}
                                </div>
                            )}

                            <div className="flex flex-wrap gap-2">
                                {renderChainBadges(res.entries)}
                            </div>
                        </div>

                        {/* Variations Sub-list */}
                        {hasVariations && isExpanded && (
                            <div className="bg-black/30 border-t border-gray-800 pl-4 py-1">
                                {res.variations!.map((v, vIdx) => {
                                    const isVarSelected = selectedId === v.id;
                                    return (
                                        <div 
                                            key={v.id} 
                                            onClick={() => onSelect(v)}
                                            className={`p-2 border-l border-gray-700 hover:bg-gray-800/50 cursor-pointer transition-colors ${isVarSelected ? 'bg-gray-800/80 border-l-2 border-l-brand-secondary' : ''}`}
                                        >
                                            <div className="flex justify-between items-center mb-1">
                                                <span className="text-[10px] font-bold text-gray-500">Variation {vIdx + 1}</span>
                                                <span className="text-[9px] text-gray-600">Score: {v.score.toFixed(0)}</span>
                                            </div>
                                            <div className="flex flex-wrap gap-1 opacity-90">
                                                {renderChainBadges(v.entries, true)}
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, StrettoSearchReport } from '../../types';
import { INTERVALS } from './strettoConstants';
import { calculateStrettoScore, SubjectVariant } from './strettoScoring';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

// --- Precomputation: Scales & Inversion ---

const SCALE_INTERVALS: Record<string, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11],
    'Natural Minor': [0, 2, 3, 5, 7, 8, 10],
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11],
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], 
    'Dorian': [0, 2, 3, 5, 7, 9, 10],
    'Phrygian': [0, 1, 3, 5, 7, 8, 10],
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10],
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; 
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; 

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalNote[] {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return [];

    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); 
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    return monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));
}

// --- Rule Definitions (Pruning) ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
const PERFECT_INTERVALS = new Set([0, 7]);

function checkPair(variantA: SubjectVariant, variantB: SubjectVariant, delay8: number, transposition: number): { compatible: boolean } {
    const notesA = variantA.notes;
    const notesB = variantB.notes;
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) timeline.get(tick)!.pB = n.pitch + transposition;
        }
    });

    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;
    let consecutiveDiss = 0;

    for (const t of ticks) {
        const state = timeline.get(t)!;
        if (state.pA === undefined || state.pB === undefined) {
            prevP1 = null; prevP2 = null;
            consecutiveDiss = 0;
            continue;
        }

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects
        if (prevP1 !== null && prevP2 !== null) {
            if (p1 !== prevP1 && p2 !== prevP2) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) return { compatible: false };
                }
            }
        }

        // Rule 6: Dissonance
        let isDiss = DISSONANT_INTERVALS.has(interval);
        if (interval === 5) isDiss = true; // P4 against bass always diss in 2-part

        if (isDiss) {
            consecutiveDiss++;
            if (consecutiveDiss > 2) return { compatible: false };
        } else {
            consecutiveDiss = 0;
        }

        prevP1 = p1; prevP2 = p2;
    }

    if (consecutiveDiss > 0) return { compatible: false };
    return { compatible: true };
}

// --- Generator ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    const baseNotes = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    const variants: SubjectVariant[] = [];
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    const res = checkPair(vA, vB, d, t);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    const results: StrettoChainResult[] = [];

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], 
        voiceEndTimes8: number[], 
        nInv: number, 
        nTrunc: number,
        nRestricted: number,
        nFree: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS) return;
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            const final = calculateStrettoScore(chain, variants, variantIndices, options);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; 
        const prevEntry = chain[depth - 1];

        // --- RULE 1 & 2: DELAY LOGIC (STRICT) ---
        // Dynamically calculate valid delays based on history
        const possibleDelays8: number[] = [];

        let minD = 1; 
        let maxD = Math.floor(subjectLength8 * (2/3)); // Rule 1A

        if (depth > 0) {
            // Rule 1C: Late stage tightening (> 3 entries)
            if (depth + 1 > 3) {
                maxD = Math.min(maxD, Math.floor(subjectLength8 * 0.5) - 1);
            }

            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);

                // Rule 2A: Max Expansion (+1 beat = +2 ticks of 8th)
                maxD = Math.min(maxD, prevDelay8 + 2);

                // Rule 1B/2B: Forced Contraction
                if (depth >= 3) {
                    const prevPrevDelay8 = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                    if (prevDelay8 > prevPrevDelay8) {
                        // Previous was expansion -> Must contract strictly
                        maxD = Math.min(maxD, prevDelay8 - 1);
                    }
                }

                // Rule 1B: Rubber Band specific check
                if (prevDelay8 > (subjectLength8 / 2)) {
                    maxD = Math.min(maxD, prevDelay8 - 1);
                }
            }
        }

        // Generate range
        for (let d = minD; d <= maxD; d++) possibleDelays8.push(d);
        possibleDelays8.sort((a,b) => a - b); // Small delays first

        for (const delay8 of possibleDelays8) {
            // Rule 3: Anti-Repetition (if large)
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                if (delay8 === prevDelay8 && delay8 >= (subjectLength8 / 3)) continue;
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            for (const t of transpositions) {
                for (let v = 0; v < options.ensembleTotal; v++) {

                    // --- RULE 7: RE-ENTRY ---
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; 

                    // --- RULE 4: STRATIFICATION (STRICT) ---
                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];
                        // 0-based indices. 0 is Highest. options.ensembleTotal-1 is Lowest.

                        // Rule 4A: Immediate Neighbors
                        if (Math.abs(e.voiceIndex - v) === 1) {
                            // Lower Index (High Voice) >= Higher Index (Low Voice)
                            const highVoice = Math.min(e.voiceIndex, v);
                            const lowVoice = Math.max(e.voiceIndex, v);
                            const highPitch = (e.voiceIndex === highVoice) ? e.transposition : t;
                            const lowPitch = (e.voiceIndex === lowVoice) ? e.transposition : t;
                            if (highPitch < lowPitch) stratFail = true;
                        }

                        // Rule 4B: General Separation (v vs v+2)
                        // Must be >= 7 semitones
                        if (Math.abs(e.voiceIndex - v) === 2) {
                            const highVoice = Math.min(e.voiceIndex, v);
                            const lowVoice = Math.max(e.voiceIndex, v);
                            const highPitch = (e.voiceIndex === highVoice) ? e.transposition : t;
                            const lowPitch = (e.voiceIndex === lowVoice) ? e.transposition : t;
                            if (highPitch < lowPitch + 7) stratFail = true;
                        }

                        // Rule 4B: Bass Clearance (Bass vs Voice N-2)
                        const bassIdx = options.ensembleTotal - 1;
                        if (v === bassIdx || e.voiceIndex === bassIdx) {
                            // Check against N-2 (e.g. Alto in SATB)
                            // Bass is bassIdx. N-2 is bassIdx - 2.
                            const other = (v === bassIdx) ? e.voiceIndex : v;
                            if (other === bassIdx - 2) {
                                // Bass vs Alto -> Must be >= 12 semitones
                                const highPitch = (other === bassIdx - 2) ? ((v===bassIdx)?e.transposition:t) : ((v===bassIdx)?t:e.transposition); // wait logic above is simpler

                                // Let's simplify: High Voice is index (Bass-2)
                                const highIsE = e.voiceIndex === (bassIdx - 2);
                                const pitchHigh = highIsE ? e.transposition : t;
                                const pitchBass = highIsE ? t : e.transposition;

                                if (pitchHigh < pitchBass + 12) stratFail = true;
                            }
                        }
                    }
                    if (stratFail) continue;

                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quota Checks
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;

                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc)) {
                             // Complex exception logic handled below with Restricted intervals
                        }

                        // Rule 8: Transposition Quotas
                        const intervalClass = Math.abs(t % 12);
                        const isRestricted = [3, 4, 8, 9].includes(intervalClass);
                        const isFree = [0, 7].includes(intervalClass) || intervalClass === 5; // P4/P5/P1/P8 are Free

                        // Policy: nRestricted <= 1 OR nRestricted < nFree
                        const nextRestricted = nRestricted + (isRestricted ? 1 : 0);
                        const nextFree = nFree + (isFree ? 1 : 0);

                        // Check if adding this restricted interval would break the policy
                        // We relax this during search but enforce strictly at end? 
                        // No, best to guide search. 
                        // If we are strictly accumulating restricted intervals, we might hit a dead end.
                        // Let's enforce the "Max 1" hard limit if that's the chosen logic, 
                        // but Rule 8B says "One of the following must hold".

                        // If we are currently violating "Max 1" (i.e. >1), we MUST satisfy "nR < nF".
                        if (nextRestricted > 1 && nextRestricted >= nextFree) continue;

                        if (options.thirdSixthMode === 'None' && isRestricted) continue;
                        if (options.thirdSixthMode === 'Max 1' && nextRestricted > 1) continue;

                        if (options.disallowComplexExceptions && (isInv || isTrunc) && isRestricted) continue;

                        // Harmonic Compatibility (Precomputed Table Lookup)
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            // Check overlap
                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;

                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * 2, 
                            voiceIndex: v
                        } as StrettoChainOption];

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            nextRestricted,
                            nextFree
                        );
                    }
                }
            }
        }
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = variants[0].length8;

    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: options.subjectVoiceIndex }],
        [0],
        initialVoiceState,
        0, 0, 0, 1 // nFree starts at 1 (Unison P1 is Free)
    );

    return {
        results: results.sort((a,b) => b.score - a.score).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

import React, { useState } from 'react';
import { StrettoChainResult, StrettoChainOption, ScoreLog } from '../../types';
import { getIntervalLabel } from '../services/midiSpelling';
import { getVoiceLabel } from '../services/midiVoices';

interface StrettoResultsListProps {
    results: StrettoChainResult[];
    selectedId: string | null;
    onSelect: (res: StrettoChainResult) => void;
    voiceNames?: Record<number, string>;
}

export default function StrettoResultsList({ results, selectedId, onSelect, voiceNames }: StrettoResultsListProps) {
    const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
    const [scoreTooltipId, setScoreTooltipId] = useState<string | null>(null);

    if (results.length === 0) {
        return <div className="text-center text-gray-500 py-10">No chains found yet. Run the search to begin.</div>;
    }

    const toggleExpand = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setExpandedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const formatInterval = (semis: number) => {
        return getIntervalLabel(semis);
    };

    const getVoiceCode = (idx: number, total: number) => {
        if (voiceNames && voiceNames[idx]) return voiceNames[idx];

        const label = getVoiceLabel(idx, total);
        if (label.includes(' ')) {
            const parts = label.split(' ');
            return `${parts[0].charAt(0)}${parts[1]}`;
        }
        return label.charAt(0);
    };

    const renderScoreTooltip = (log?: ScoreLog) => {
        if (!log) return null;
        return (
            <div className="absolute right-0 top-full mt-2 z-50 w-64 bg-black border border-gray-600 rounded p-3 shadow-xl text-xs text-gray-300">
                <div className="font-bold text-gray-200 border-b border-gray-600 pb-1 mb-2">Score Breakdown ({log.total.toFixed(0)})</div>
                <div className="flex justify-between mb-1"><span>Base</span><span>{log.base}</span></div>
                {log.bonuses.map((b, i) => (
                    <div key={`b-${i}`} className="flex justify-between text-green-400"><span>+ {b.reason}</span><span>{b.points}</span></div>
                ))}
                {log.penalties.map((p, i) => (
                    <div key={`p-${i}`} className="flex justify-between text-red-400"><span>- {p.reason}</span><span>{p.points}</span></div>
                ))}
            </div>
        );
    };

    const renderChainBadges = (entries: StrettoChainOption[], isSub: boolean = false) => {
        const maxV = Math.max(...entries.map(e => e.voiceIndex)) + 1;
        const totalEstimate = Math.max(4, maxV); 

        return entries.map((e, idx) => {
            const vCode = getVoiceCode(e.voiceIndex, totalEstimate);

            if (idx === 0) {
                return (
                    <div key={idx} className={`flex flex-col items-center bg-gray-800 p-1 rounded border border-gray-700 ${isSub ? 'min-w-[40px] scale-90 origin-left' : 'min-w-[50px]'}`}>
                        <span className="text-[10px] font-bold text-brand-primary truncate max-w-[50px]" title={vCode}>{vCode}</span>
                        <span className="text-xs text-white font-mono">Subj</span>
                    </div>
                );
            }

            const absInt = e.transposition; 
            const prev = entries[idx-1];
            const relDist = e.startBeat - prev.startBeat;
            const absDist = e.startBeat;

            let typeLabel = e.type === 'I' ? 'INV' : 'NOR';
            let lenLabel = e.length < entries[0].length ? 'TRC' : 'FUL';

            const borderClass = (e.type === 'I' || lenLabel === 'TRC') ? 'border-brand-primary' : 'border-gray-600';

            return (
                <div key={idx} className={`flex flex-col bg-gray-800 p-1 rounded border ${borderClass} ${isSub ? 'min-w-[50px] scale-90 origin-left' : 'min-w-[60px]'}`}>
                    <div className="flex justify-between border-b border-gray-700 pb-0.5 mb-0.5">
                        <span className="text-[9px] font-bold text-gray-300 truncate max-w-[40px]" title={vCode}>{vCode}</span>
                        <span className={`text-[8px] font-bold ${lenLabel === 'TRC' ? 'text-orange-300' : 'text-gray-500'}`}>{lenLabel}</span>
                    </div>

                    <div className="flex flex-col items-center mb-0.5">
                        <span className="text-[10px] text-brand-primary font-bold">{formatInterval(absInt)}</span>
                        {e.type === 'I' && <span className="text-[8px] text-blue-300">INVERT</span>}
                    </div>

                    <div className="flex gap-1 text-[9px] font-mono" title={`Delay: +${relDist} / Start: @${absDist}`}>
                        <span className="text-gray-400 w-1/2 text-center border-r border-gray-700">+{relDist.toFixed(1)}</span>
                        <span className="text-white w-1/2 text-center">@{absDist.toFixed(1)}</span>
                    </div>
                </div>
            );
        });
    };

    return (
        <div className="overflow-y-auto max-h-[500px] pb-20">
            {results.map((res, i) => {
                const hasVariations = res.variations && res.variations.length > 0;
                const isExpanded = expandedIds.has(res.id);
                const isSelected = selectedId === res.id;
                const showTooltip = scoreTooltipId === res.id;

                return (
                    <div key={res.id} className="border-b border-gray-700 bg-gray-900/50 relative">
                        {/* Leader Row */}
                        <div 
                            onClick={() => onSelect(res)}
                            className={`p-2 cursor-pointer hover:bg-gray-800 transition-colors flex flex-col gap-2 ${isSelected ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                        >
                            <div className="flex justify-between items-center">
                                <div className="flex items-center gap-2">
                                    {hasVariations && (
                                        <button 
                                            onClick={(e) => toggleExpand(e, res.id)}
                                            className="text-gray-400 hover:text-white text-xs bg-gray-700 px-1.5 rounded"
                                        >
                                            {isExpanded ? '▼' : '▶'}
                                        </button>
                                    )}
                                    <span className="font-bold text-gray-300 text-xs">Chain #{i + 1}</span>
                                    {hasVariations && (
                                        <span className="text-[10px] bg-brand-primary/20 text-brand-primary px-1.5 rounded">
                                            +{res.variations?.length} Vars
                                        </span>
                                    )}
                                </div>
                                <div className="relative">
                                    <button 
                                        onMouseEnter={() => setScoreTooltipId(res.id)}
                                        onMouseLeave={() => setScoreTooltipId(null)}
                                        className="text-[9px] bg-black/30 px-1.5 rounded text-gray-500 hover:text-white cursor-help"
                                    >
                                        Score: {res.score.toFixed(0)}
                                    </button>
                                    {showTooltip && renderScoreTooltip(res.scoreLog)}
                                </div>
                            </div>

                            {/* Detected Chords Summary */}
                            {res.detectedChords && res.detectedChords.length > 0 && (
                                <div className="flex gap-1 overflow-hidden">
                                    {res.detectedChords.map((c, idx) => (
                                        <span key={idx} className="text-[9px] text-gray-400 bg-black/20 px-1 rounded whitespace-nowrap">{c}</span>
                                    ))}
                                </div>
                            )}

                            <div className="flex flex-wrap gap-2">
                                {renderChainBadges(res.entries)}
                            </div>
                        </div>

                        {/* Variations Sub-list */}
                        {hasVariations && isExpanded && (
                            <div className="bg-black/30 border-t border-gray-800 pl-4 py-1">
                                {res.variations!.map((v, vIdx) => {
                                    const isVarSelected = selectedId === v.id;
                                    return (
                                        <div 
                                            key={v.id} 
                                            onClick={() => onSelect(v)}
                                            className={`p-2 border-l border-gray-700 hover:bg-gray-800/50 cursor-pointer transition-colors ${isVarSelected ? 'bg-gray-800/80 border-l-2 border-l-brand-secondary' : ''}`}
                                        >
                                            <div className="flex justify-between items-center mb-1">
                                                <span className="text-[10px] font-bold text-gray-500">Variation {vIdx + 1}</span>
                                                <span className="text-[9px] text-gray-600">Score: {v.score.toFixed(0)}</span>
                                            </div>
                                            <div className="flex flex-wrap gap-1 opacity-90">
                                                {renderChainBadges(v.entries, true)}
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, StrettoSearchReport } from '../../types';
import { INTERVALS } from './strettoConstants';
import { calculateStrettoScore, SubjectVariant } from './strettoScoring';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

// --- Precomputation: Scales & Inversion ---

const SCALE_INTERVALS: Record<string, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11],
    'Natural Minor': [0, 2, 3, 5, 7, 8, 10],
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11],
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], 
    'Dorian': [0, 2, 3, 5, 7, 9, 10],
    'Phrygian': [0, 1, 3, 5, 7, 8, 10],
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10],
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; 
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; 

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalNote[] {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return [];

    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); 
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    return monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));
}

// --- Rule Definitions (Pruning) ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
const PERFECT_INTERVALS = new Set([0, 7]);

/**
 * STRICT Rule 5 & 6 Implementation
 * Checks Pairwise Compatibility with rigorous Dissonance Resolution logic.
 */
function checkCounterpoint(variantA: SubjectVariant, variantB: SubjectVariant, delay8: number, transposition: number): { compatible: boolean } {
    const notesA = variantA.notes;
    const notesB = variantB.notes;
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) timeline.get(tick)!.pB = n.pitch + transposition;
        }
    });

    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    // Dissonance Run Tracking (Rule 6)
    let dissRunLength = 0; 
    let dissRunStartTick = -1;
    let lastIsDiss = false;

    for (let i = 0; i < ticks.length; i++) {
        const t = ticks[i];
        const state = timeline.get(t)!;

        // Monophonic sections reset dissonance tracking (assuming rests resolve or break the chain)
        // Rule C6 Note: If we end a phrase on a dissonance without resolution, that's bad, but handled at end of loop.
        if (state.pA === undefined || state.pB === undefined) {
            if (lastIsDiss) return { compatible: false }; // Rule C6: No resolution into silence/monophony
            prevP1 = null; prevP2 = null;
            dissRunLength = 0;
            lastIsDiss = false;
            continue;
        }

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // --- Rule 5: Parallel Perfects ---
        if (prevP1 !== null && prevP2 !== null) {
            // Check for motion (Oblique motion is safe)
            const p1Moved = p1 !== prevP1;
            const p2Moved = p2 !== prevP2;

            if (p1Moved && p2Moved) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    // Parallel Perfect (Same interval class)
                    if (prevInt === interval) return { compatible: false };
                }
            }
        }

        // --- Rule 6: Dissonance & Resolution ---
        let isDiss = DISSONANT_INTERVALS.has(interval);
        if (interval === 5) isDiss = true; // P4 against bass always diss in 2-part

        // Beat Strength (Assuming 4/4, 8th grid: 0=Strong, 1=Weak, 2=Medium/Weak, 3=Weak)
        // Strong beats are 0 mod 4 (Beat 1, 3 in 4/4?? No, 8th grid.)
        // Grid: 0 (B1), 1 (&), 2 (B2), 3 (&), 4 (B3), 5 (&)...
        // Strong: 0, 4 (Downbeats). Weak: 1, 2, 3, 5, 6, 7?
        // Let's stick to simple Metric: Even ticks are On-Beat, Odd are Off-Beat.
        // Strong: Ticks divisible by 4 (Quarter note beats).
        const isStrongBeat = (t % 4 === 0);

        if (isDiss) {
            // Rule C3: Mandatory Resolution check (handled by tracking run length)

            if (!lastIsDiss) {
                // New dissonance run
                dissRunLength = 1;
                dissRunStartTick = t;
            } else {
                dissRunLength++;
            }

            // Rule C2: Event Limit (r <= 2)
            if (dissRunLength > 2) return { compatible: false };

            // Rule C4: Metric Constraints
            if (dissRunLength === 2) {
                // Rule C4A: If r=2, BOTH must be weak/off-beat?
                // Or simplified: Just don't allow 2 consecutive dissonances if the first was Strong.
                // Spec says: "IF r=2, THEN both must fall on weak beats"
                const prevT = ticks[i-1];
                const prevStrong = (prevT % 4 === 0);
                if (prevStrong || isStrongBeat) return { compatible: false };
            }

            // Rule C4B: If Strong beat, resolution must be immediate (Length 1 max)
            // So if we are at Length 2, and the previous one was Strong, we already failed above.
            // If CURRENT is Strong, and it's the start (Len 1), we are okay, but NEXT must resolve.

            lastIsDiss = true;
        } else {
            // Consonant - Resolution achieved
            dissRunLength = 0;
            lastIsDiss = false;
        }

        prevP1 = p1; prevP2 = p2;
    }

    // Rule C6: No Resolution into Silence (End of pair overlap)
    if (lastIsDiss) return { compatible: false };

    return { compatible: true };
}

/**
 * Validates the composite texture of a chain at a specific moment.
 * Essential for "Bass Dissonance" checks involving more than 2 voices.
 */
function validateCompositeChain(
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[],
    tick8: number
): boolean {
    const activePitches: number[] = [];

    // Collect all pitches sounding at tick8
    for(let i=0; i<chain.length; i++) {
        const entry = chain[i];
        const variant = variants[variantIndices[i]];
        const start8 = Math.round(entry.startBeat * 2);
        const relTick = tick8 - start8;

        if (relTick >= 0 && relTick < variant.length8) {
            // Find note active at this relative tick
            // We need to scan the notes. Optimized lookup would be better, but loop is short.
            const note = variant.notes.find(n => n.relTick8 <= relTick && (n.relTick8 + n.dur8) > relTick);
            if (note) {
                activePitches.push(note.pitch + entry.transposition);
            }
        }
    }

    if (activePitches.length < 2) return true;

    activePitches.sort((a,b) => a - b);
    const bass = activePitches[0];

    // Check Rule 6 against Bass
    for (const p of activePitches) {
        if (p === bass) continue;
        const interval = (p - bass) % 12;
        // P4 (5) against bass is Dissonant
        if (DISSONANT_INTERVALS.has(interval) || interval === 5) {
            // In strict counterpoint, if the specific slice is dissonant, it must be part of a valid run.
            // However, tracking composite runs recursively is expensive.
            // We rely on checkCounterpoint pairwise to catch most motion/prep errors.
            // Here we mainly want to catch the "P4 against Bass" which pairwise might miss 
            // (if A & B are upper voices forming a P4, it's fine. If C enters below them, A-C or B-C might be P4).

            // If this is a "New" dissonance not accounted for by pairs...
            // Simplification: We trust pairwise for run logic. We assume if a pair fails P4 vs Bass, it fails pairwise.
            // But Bass changes! 
            // If A (Upper) and B (Upper) form P4, pairwise says OK.
            // If C (Bass) enters, pairwise A-C and B-C are checked.
            // If A-C is 3rd (Cons) and B-C is 6th (Cons), A-B is P4 (Diss? No P4 between uppers is Cons).
            // So P4 issue is handled.

            // What about Bass 2nds? 
            // If A (Bass) and B (Upper) form 2nd -> Pairwise A-B fails (or counts as Diss).
            // So Pairwise actually covers Composite for these rules?
            // YES, because dissonance is defined by "Any pair is dissonant".
            // So if Composite is dissonant, at least one Pair is dissonant.
            // Therefore, strict pairwise checking (Phase 1) is sufficient for Rule 6.
            // We return true here to avoid redundant calculation unless we add specific composite rules (like full triad completeness).
        }
    }

    return true;
}

// --- Generator ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    const baseNotes = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    const variants: SubjectVariant[] = [];
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Phase 1: STRICT PAIRWISE PRECOMPUTATION
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    const res = checkCounterpoint(vA, vB, d, t); // Use Strict Checker
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    const results: StrettoChainResult[] = [];

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], 
        voiceEndTimes8: number[], 
        nInv: number, 
        nTrunc: number,
        nRestricted: number,
        nFree: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS) return;
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            const final = calculateStrettoScore(chain, variants, variantIndices, options);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; 
        const prevEntry = chain[depth - 1];

        // --- RULE 1 & 2: DELAY LOGIC (STRICT) ---
        const possibleDelays8: number[] = [];

        let minD = 1; 
        let maxD = Math.floor(subjectLength8 * (2/3)); // Rule 1A

        if (depth > 0) {
            // Rule 1C: Late stage tightening (> 3 entries)
            if (depth + 1 > 3) {
                maxD = Math.min(maxD, Math.floor(subjectLength8 * 0.5) - 1);
            }

            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);

                // Rule 2A: Max Expansion (+1 beat = +2 ticks of 8th)
                maxD = Math.min(maxD, prevDelay8 + 2);

                // Rule 1B/2B: Forced Contraction
                if (depth >= 3) {
                    const prevPrevDelay8 = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                    if (prevDelay8 > prevPrevDelay8) {
                        maxD = Math.min(maxD, prevDelay8 - 1);
                    }
                }

                if (prevDelay8 > (subjectLength8 / 2)) {
                    maxD = Math.min(maxD, prevDelay8 - 1);
                }
            }
        }

        // Generate range
        for (let d = minD; d <= maxD; d++) possibleDelays8.push(d);
        possibleDelays8.sort((a,b) => a - b); 

        for (const delay8 of possibleDelays8) {
            // Rule 3: Anti-Repetition
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                if (delay8 === prevDelay8 && delay8 >= (subjectLength8 / 3)) continue;
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            for (const t of transpositions) {
                for (let v = 0; v < options.ensembleTotal; v++) {

                    // --- RULE 7: RE-ENTRY ---
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; 

                    // --- RULE 4: STRATIFICATION (STRICT) ---
                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];

                        // Rule 4A: Immediate Neighbors (v vs v+1)
                        if (Math.abs(e.voiceIndex - v) === 1) {
                            // Lower Index (High Voice) >= Higher Index (Low Voice)
                            const highVoice = Math.min(e.voiceIndex, v);
                            const lowVoice = Math.max(e.voiceIndex, v);
                            const highPitch = (e.voiceIndex === highVoice) ? e.transposition : t;
                            const lowPitch = (e.voiceIndex === lowVoice) ? e.transposition : t;
                            if (highPitch < lowPitch) stratFail = true;
                        }

                        // Rule 4B: Bass Clearance (Bass vs Voice N-2)
                        // This must be 12 semitones (Octave)
                        const bassIdx = options.ensembleTotal - 1;
                        const altoIdx = bassIdx - 2; // "Alto" relative to bass

                        // Only apply if we have enough voices (>=3 voices for Bass, Alto, Soprano structure)
                        if (bassIdx >= 2) {
                            const isNewBass = (v === bassIdx);
                            const isNewAlto = (v === altoIdx);
                            const isExistingBass = (e.voiceIndex === bassIdx);
                            const isExistingAlto = (e.voiceIndex === altoIdx);

                            if ((isNewBass && isExistingAlto) || (isNewAlto && isExistingBass)) {
                                const bassTrans = isNewBass ? t : e.transposition;
                                const altoTrans = isNewAlto ? t : e.transposition;

                                // Alto must be >= Bass + 12
                                if (altoTrans < bassTrans + 12) stratFail = true;
                            }
                        }
                    }
                    if (stratFail) continue;

                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quota Checks
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;

                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;

                        // Rule 8: Transposition Quotas
                        const intervalClass = Math.abs(t % 12);
                        const isRestricted = [3, 4, 8, 9].includes(intervalClass);
                        const isFree = [0, 7].includes(intervalClass) || intervalClass === 5; 

                        const nextRestricted = nRestricted + (isRestricted ? 1 : 0);
                        const nextFree = nFree + (isFree ? 1 : 0);

                        if (nextRestricted > 1 && nextRestricted >= nextFree) continue;
                        if (options.thirdSixthMode === 'None' && isRestricted) continue;
                        if (options.thirdSixthMode === 'Max 1' && nextRestricted > 1) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && isRestricted) continue;

                        // Harmonic Compatibility (Precomputed Strict Counterpoint)
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            // Check overlap
                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;

                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * 2, 
                            voiceIndex: v
                        } as StrettoChainOption];

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            nextRestricted,
                            nextFree
                        );
                    }
                }
            }
        }
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = variants[0].length8;

    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: options.subjectVoiceIndex }],
        [0],
        initialVoiceState,
        0, 0, 0, 1 // nFree starts at 1 (Unison P1 is Free)
    );

    return {
        results: results.sort((a,b) => b.score - a.score).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, StrettoSearchReport } from '../../types';
import { INTERVALS } from './strettoConstants';
import { calculateStrettoScore, SubjectVariant } from './strettoScoring';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

// --- Precomputation: Scales & Inversion ---

const SCALE_INTERVALS: Record<string, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11],
    'Natural Minor': [0, 2, 3, 5, 7, 8, 10],
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11],
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], 
    'Dorian': [0, 2, 3, 5, 7, 9, 10],
    'Phrygian': [0, 1, 3, 5, 7, 8, 10],
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10],
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; 
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; 

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalNote[] {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return [];

    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); 
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    return monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));
}

// --- Rule Definitions (Pruning) ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
const PERFECT_INTERVALS = new Set([0, 7]);

/**
 * PHASE 1 CHECK: Structural Validity
 * Checks translation-invariant rules (Parallel Perfects, Dissonance Resolution Existence).
 * Does NOT check Metric Rules (Strong/Weak beats) as absolute time is unknown here.
 */
function checkCounterpointStructure(variantA: SubjectVariant, variantB: SubjectVariant, delay8: number, transposition: number): { compatible: boolean } {
    const notesA = variantA.notes;
    const notesB = variantB.notes;
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) timeline.get(tick)!.pB = n.pitch + transposition;
        }
    });

    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    let dissRunLength = 0; 
    let lastIsDiss = false;

    for (let i = 0; i < ticks.length; i++) {
        const t = ticks[i];
        const state = timeline.get(t)!;

        if (state.pA === undefined || state.pB === undefined) {
            // Rule C6: No Resolution into Silence
            if (lastIsDiss) return { compatible: false }; 
            prevP1 = null; prevP2 = null;
            dissRunLength = 0;
            lastIsDiss = false;
            continue;
        }

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = p1 !== prevP1;
            const p2Moved = p2 !== prevP2;

            if (p1Moved && p2Moved) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) return { compatible: false };
                }
            }
        }

        // Rule 6: Dissonance (Structural)
        let isDiss = DISSONANT_INTERVALS.has(interval);
        if (interval === 5) isDiss = true; // P4 against bass always diss

        if (isDiss) {
            if (!lastIsDiss) dissRunLength = 1;
            else dissRunLength++;

            // Rule C2: Event Limit (r <= 2)
            if (dissRunLength > 2) return { compatible: false };

            // NOTE: Metric Checks (Strong/Weak placement) removed here.
            // They are checked in Phase 5 when absolute start time is known.

            lastIsDiss = true;
        } else {
            dissRunLength = 0;
            lastIsDiss = false;
        }

        prevP1 = p1; prevP2 = p2;
    }

    if (lastIsDiss) return { compatible: false };

    return { compatible: true };
}

/**
 * PHASE 5 CHECK: Metric Compliance
 * Checks Rule 6 C4 (Metric Constraints) using absolute timestamps.
 */
function checkMetricCompliance(
    newVariant: SubjectVariant, 
    newEntry: StrettoChainOption,
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[]
): boolean {

    const newStart8 = Math.round(newEntry.startBeat * 2);

    // Check against every existing voice
    for (let k = 0; k < chain.length; k++) {
        const existEntry = chain[k];
        const existVariant = variants[variantIndices[k]];
        const existStart8 = Math.round(existEntry.startBeat * 2);

        // Determine overlapping region
        const overlapStart = Math.max(newStart8, existStart8);
        const overlapEnd = Math.min(newStart8 + newVariant.length8, existStart8 + existVariant.length8);

        if (overlapEnd <= overlapStart) continue;

        let dissRunLength = 0;
        let lastIsDiss = false;

        // Iterate overlap ticks
        for (let t = overlapStart; t < overlapEnd; t++) {
            // Find pitches
            const tRelNew = t - newStart8;
            const tRelExist = t - existStart8;

            // Optimization: Note lookup could be cached, but loop is short
            const noteNew = newVariant.notes.find(n => n.relTick8 <= tRelNew && (n.relTick8 + n.dur8) > tRelNew);
            const noteExist = existVariant.notes.find(n => n.relTick8 <= tRelExist && (n.relTick8 + n.dur8) > tRelExist);

            if (!noteNew || !noteExist) {
                dissRunLength = 0; lastIsDiss = false; continue;
            }

            const p1 = noteNew.pitch + newEntry.transposition;
            const p2 = noteExist.pitch + existEntry.transposition;
            const lo = Math.min(p1, p2);
            const hi = Math.max(p1, p2);
            const interval = (hi - lo) % 12;

            // Dissonance Check
            let isDiss = DISSONANT_INTERVALS.has(interval);
            // Check Bass logic if we want to be strict, but pairwise mostly assumes P4 is bad
            if (interval === 5) isDiss = true;

            // Rule C4: Metric Constraints
            // 4/4 Assumption on 8th grid: 0=Strong, 1=Weak, 2=Weak(Beat2), 3=Weak...
            // Strong Beats are indices 0, 4 (Beat 1, 3).
            // Actually, let's define Strong as Downbeat (0) and Beat 3 (4).
            // Weak are Beats 2 (2) and 4 (6).
            // Offbeats are 1, 3, 5, 7.

            const beatPos = t % 8; // Position in 4/4 measure (8 eighths)
            const isStrongBeat = (beatPos === 0 || beatPos === 4);
            const isWeakBeat = !isStrongBeat; // Includes offbeats and beats 2/4

            if (isDiss) {
                if (!lastIsDiss) dissRunLength = 1; else dissRunLength++;

                // Rule C4B: If Strong beat, resolution must be immediate (Length 1 max)
                if (isStrongBeat) {
                    // Dissonance starting on or continuing through a strong beat
                    // If it continues (length > 1), it's a violation?
                    // Spec: "IF beat(tk)=strong, THEN resolution at tk+r <= tk + 1.0"
                    // This implies max duration 1 beat. Since grid is 0.5 beat (8th), max length 2 ticks is allowed.
                    // But if it STARTS strong, it must resolve.
                }

                // Rule C4A: If r=2 (two consecutive 8ths), BOTH must be weak.
                // This means a dissonance run cannot straddle a Strong beat or Start on one if it's 2 long?
                // Spec: "IF r=2, THEN both must fall on weak beats."
                if (dissRunLength === 2) {
                    const prevBeatPos = (t - 1) % 8;
                    const prevIsStrong = (prevBeatPos === 0 || prevBeatPos === 4);

                    if (isStrongBeat || prevIsStrong) return false; 
                }

                lastIsDiss = true;
            } else {
                dissRunLength = 0;
                lastIsDiss = false;
            }
        }
    }
    return true;
}

// --- Generator ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    const baseNotes = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    const variants: SubjectVariant[] = [];
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Phase 1: STRUCTURAL PAIRWISE PRECOMPUTATION
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    // Only check structural rules here (invariance), Metric rules checked later
                    const res = checkCounterpointStructure(vA, vB, d, t);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    const results: StrettoChainResult[] = [];

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], 
        voiceEndTimes8: number[], 
        nInv: number, 
        nTrunc: number,
        nRestricted: number,
        nFree: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS) return;
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            const final = calculateStrettoScore(chain, variants, variantIndices, options);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; 
        const prevEntry = chain[depth - 1];

        // --- RULE 1 & 2: DELAY LOGIC (STRICT) ---
        const possibleDelays8: number[] = [];
        let minD = 1; 
        let maxD = Math.floor(subjectLength8 * (2/3)); 

        if (depth > 0) {
            if (depth + 1 > 3) maxD = Math.min(maxD, Math.floor(subjectLength8 * 0.5) - 1);
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                maxD = Math.min(maxD, prevDelay8 + 2);
                if (depth >= 3) {
                    const prevPrevDelay8 = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                    if (prevDelay8 > prevPrevDelay8) maxD = Math.min(maxD, prevDelay8 - 1);
                }
                if (prevDelay8 > (subjectLength8 / 2)) maxD = Math.min(maxD, prevDelay8 - 1);
            }
        }

        for (let d = minD; d <= maxD; d++) possibleDelays8.push(d);
        possibleDelays8.sort((a,b) => a - b); 

        for (const delay8 of possibleDelays8) {
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                if (delay8 === prevDelay8 && delay8 >= (subjectLength8 / 3)) continue;
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            for (const t of transpositions) {
                for (let v = 0; v < options.ensembleTotal; v++) {

                    // --- RULE 7: RE-ENTRY ---
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; 

                    // --- RULE 4: STRATIFICATION (STRICT) ---
                    // Explicit variable naming: 'Trans' means Transposition Interval (Shift), NOT absolute Pitch
                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];

                        // Rule 4A: Immediate Neighbors (v vs v+1)
                        if (Math.abs(e.voiceIndex - v) === 1) {
                            // Lower Index (Higher Voice Role) >= Higher Index (Lower Voice Role)
                            // e.g. Soprano (0) vs Alto (1). Soprano Transposition >= Alto Transposition.
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);

                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            if (highVoiceTrans < lowVoiceTrans) stratFail = true;
                        }

                        // Rule 4B: Bass Clearance (Bass vs Voice N-2)
                        // Bass Index is always (ensembleTotal - 1)
                        // This rule protects the Bass from the Alto (N-2)
                        const bassIdx = options.ensembleTotal - 1;
                        const altoIdx = bassIdx - 2; 

                        // Only apply if we have enough voices (>=3 voices)
                        if (bassIdx >= 2) {
                            const isNewBass = (v === bassIdx);
                            const isNewAlto = (v === altoIdx);
                            const isExistingBass = (e.voiceIndex === bassIdx);
                            const isExistingAlto = (e.voiceIndex === altoIdx);

                            if ((isNewBass && isExistingAlto) || (isNewAlto && isExistingBass)) {
                                const bassTrans = isNewBass ? t : e.transposition;
                                const altoTrans = isNewAlto ? t : e.transposition;

                                // Alto must be >= Bass + 12
                                if (altoTrans < bassTrans + 12) stratFail = true;
                            }
                        }

                        // Rule 4B General: Separation Floor (v vs v+2)
                        // All voices separated by 2 ranks must be >= 7 semitones apart
                        if (Math.abs(e.voiceIndex - v) === 2) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);

                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            if (highVoiceTrans < lowVoiceTrans + 7) stratFail = true;
                        }
                    }
                    if (stratFail) continue;

                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quota Checks
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;
                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;

                        const intervalClass = Math.abs(t % 12);
                        const isRestricted = [3, 4, 8, 9].includes(intervalClass);
                        const isFree = [0, 7].includes(intervalClass) || intervalClass === 5; 
                        const nextRestricted = nRestricted + (isRestricted ? 1 : 0);
                        const nextFree = nFree + (isFree ? 1 : 0);

                        if (nextRestricted > 1 && nextRestricted >= nextFree) continue;
                        if (options.thirdSixthMode === 'None' && isRestricted) continue;
                        if (options.thirdSixthMode === 'Max 1' && nextRestricted > 1) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && isRestricted) continue;

                        // Phase 1 Check: Harmonic Compatibility (Structural)
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;
                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        // Phase 5 Check: Metric Compliance (Absolute Time)
                        // We construct a temp entry object to pass
                        const tempNextEntry: StrettoChainOption = {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * 2,
                            voiceIndex: v
                        };

                        if (!checkMetricCompliance(variant, tempNextEntry, chain, variants, variantIndices)) {
                            continue;
                        }

                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, tempNextEntry];

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            nextRestricted,
                            nextFree
                        );
                    }
                }
            }
        }
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = variants[0].length8;

    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: options.subjectVoiceIndex }],
        [0],
        initialVoiceState,
        0, 0, 0, 1
    );

    return {
        results: results.sort((a,b) => b.score - a.score).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, StrettoSearchReport } from '../../types';
import { INTERVALS } from './strettoConstants';
import { calculateStrettoScore, SubjectVariant } from './strettoScoring';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

// --- Precomputation: Scales & Inversion ---

const SCALE_INTERVALS: Record<string, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11],
    'Natural Minor': [0, 2, 3, 5, 7, 8, 10],
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11],
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], 
    'Dorian': [0, 2, 3, 5, 7, 9, 10],
    'Phrygian': [0, 1, 3, 5, 7, 8, 10],
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10],
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; 
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; 

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalNote[] {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return [];

    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); 
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    return monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));
}

// --- Rule Definitions (Pruning) ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
const PERFECT_INTERVALS = new Set([0, 7]);

/**
 * PHASE 1 CHECK: Structural Validity (Pairwise)
 * Relaxed: Does NOT check "Ends on Dissonance" (C6) as that is position-dependent.
 * Checks: Parallel Perfects, Run Length <= 2.
 */
function checkCounterpointStructure(variantA: SubjectVariant, variantB: SubjectVariant, delay8: number, transposition: number): { compatible: boolean } {
    const notesA = variantA.notes;
    const notesB = variantB.notes;
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) timeline.get(tick)!.pB = n.pitch + transposition;
        }
    });

    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    let dissRunLength = 0; 
    let lastIsDiss = false;

    for (let i = 0; i < ticks.length; i++) {
        const t = ticks[i];
        const state = timeline.get(t)!;

        if (state.pA === undefined || state.pB === undefined) {
            // Monophonic moment - reset trackers
            prevP1 = null; prevP2 = null;
            dissRunLength = 0;
            lastIsDiss = false;
            // Note: Rule C6 (Resolution into silence) ignored here to allow chaining
            continue;
        }

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = p1 !== prevP1;
            const p2Moved = p2 !== prevP2;

            if (p1Moved && p2Moved) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) return { compatible: false };
                }
            }
        }

        // Rule 6: Dissonance (Structural)
        let isDiss = DISSONANT_INTERVALS.has(interval);
        if (interval === 5) isDiss = true; // P4 against bass always diss in 2-part

        if (isDiss) {
            if (!lastIsDiss) dissRunLength = 1;
            else dissRunLength++;

            // Rule C2: Event Limit (r <= 2)
            if (dissRunLength > 2) return { compatible: false };

            lastIsDiss = true;
        } else {
            dissRunLength = 0;
            lastIsDiss = false;
        }

        prevP1 = p1; prevP2 = p2;
    }

    return { compatible: true };
}

// Helper: Determine beat strength
function isStrong8th(tick8: number, tsNum: number, tsDenom: number): boolean {
    // Convert 8th tick to measure position
    // For 4/4: 8 eighths per bar. Strong are 0 (Beat 1) and 4 (Beat 3).
    // For 3/4: 6 eighths. Strong are 0 (Beat 1).
    const eighthsPerBar = (tsNum * 8) / tsDenom;
    const pos = tick8 % eighthsPerBar;

    if (pos === 0) return true; // Downbeat always strong

    if (tsNum === 4 && tsDenom === 4) {
        if (pos === 4) return true; // Beat 3 in 4/4
    }

    return false;
}

/**
 * PHASE 5 CHECK: Metric Compliance
 * Checks Rule 6 C4 (Metric Constraints) using absolute timestamps.
 */
function checkMetricCompliance(
    newVariant: SubjectVariant, 
    newEntry: StrettoChainOption,
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[],
    tsNum: number = 4,
    tsDenom: number = 4
): boolean {

    const newStart8 = Math.round(newEntry.startBeat * 2);

    // Check against every existing voice
    for (let k = 0; k < chain.length; k++) {
        const existEntry = chain[k];
        const existVariant = variants[variantIndices[k]];
        const existStart8 = Math.round(existEntry.startBeat * 2);

        // Determine overlapping region
        const overlapStart = Math.max(newStart8, existStart8);
        const overlapEnd = Math.min(newStart8 + newVariant.length8, existStart8 + existVariant.length8);

        if (overlapEnd <= overlapStart) continue;

        let dissRunLength = 0;
        let lastIsDiss = false;

        // Iterate overlap ticks
        for (let t = overlapStart; t < overlapEnd; t++) {
            const tRelNew = t - newStart8;
            const tRelExist = t - existStart8;

            const noteNew = newVariant.notes.find(n => n.relTick8 <= tRelNew && (n.relTick8 + n.dur8) > tRelNew);
            const noteExist = existVariant.notes.find(n => n.relTick8 <= tRelExist && (n.relTick8 + n.dur8) > tRelExist);

            if (!noteNew || !noteExist) {
                dissRunLength = 0; lastIsDiss = false; continue;
            }

            const p1 = noteNew.pitch + newEntry.transposition;
            const p2 = noteExist.pitch + existEntry.transposition;
            const lo = Math.min(p1, p2);
            const hi = Math.max(p1, p2);
            const interval = (hi - lo) % 12;

            let isDiss = DISSONANT_INTERVALS.has(interval);
            if (interval === 5) isDiss = true;

            const isStrong = isStrong8th(t, tsNum, tsDenom);

            if (isDiss) {
                if (!lastIsDiss) dissRunLength = 1; else dissRunLength++;

                // Rule C4B: If Strong beat, resolution must be immediate (Length 1 max)
                // This means a dissonance cannot *continue* from a strong beat, nor *start* and extend
                if (isStrong && dissRunLength > 1) return false; 

                // Rule C4A: If r=2, BOTH must be weak.
                // If we hit length 2, we check current (t) and prev (t-1).
                // If either is strong, fail.
                if (dissRunLength === 2) {
                    const prevIsStrong = isStrong8th(t - 1, tsNum, tsDenom);
                    if (isStrong || prevIsStrong) return false; 
                }

                lastIsDiss = true;
            } else {
                dissRunLength = 0;
                lastIsDiss = false;
            }
        }
    }
    return true;
}

// --- Generator ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    const baseNotes = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    const variants: SubjectVariant[] = [];
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Phase 1: STRUCTURAL PAIRWISE PRECOMPUTATION
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    // Only check structural rules here (invariance), Metric rules checked later
                    const res = checkCounterpointStructure(vA, vB, d, t);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    const results: StrettoChainResult[] = [];

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], 
        voiceEndTimes8: number[], 
        nInv: number, 
        nTrunc: number,
        nRestricted: number,
        nFree: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS * 3) return; // Allow more raw results for grouping later
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            const final = calculateStrettoScore(chain, variants, variantIndices, options);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; 
        const prevEntry = chain[depth - 1];

        // --- RULE 1 & 2: DELAY LOGIC (STRICT) ---
        const possibleDelays8: number[] = [];
        let minD = 1; 
        let maxD = Math.floor(subjectLength8 * (2/3)); 

        if (depth > 0) {
            if (depth + 1 > 3) maxD = Math.min(maxD, Math.floor(subjectLength8 * 0.5) - 1);
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                maxD = Math.min(maxD, prevDelay8 + 2);
                if (depth >= 3) {
                    const prevPrevDelay8 = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                    if (prevDelay8 > prevPrevDelay8) maxD = Math.min(maxD, prevDelay8 - 1);
                }
                if (prevDelay8 > (subjectLength8 / 2)) maxD = Math.min(maxD, prevDelay8 - 1);
            }
        }

        for (let d = minD; d <= maxD; d++) possibleDelays8.push(d);
        possibleDelays8.sort((a,b) => a - b); 

        for (const delay8 of possibleDelays8) {
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                if (delay8 === prevDelay8 && delay8 >= (subjectLength8 / 3)) continue;
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            for (const t of transpositions) {
                for (let v = 0; v < options.ensembleTotal; v++) {

                    // --- RULE 7: RE-ENTRY ---
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; 

                    // --- RULE 4: STRATIFICATION (STRICT - Transposition Based) ---
                    // "Voice Crossing" is allowed in terms of Pitch, but the structural Layers must be ordered.
                    // High Index = Lower Voice. Low Index = Higher Voice.
                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];

                        // Rule 4A: Neighbor Check
                        if (Math.abs(e.voiceIndex - v) === 1) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);

                            // The shift (transposition) of the Higher Voice must be >= Lower Voice
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            if (highVoiceTrans < lowVoiceTrans) stratFail = true;
                        }

                        // Rule 4B: Bass Clearance
                        const bassIdx = options.ensembleTotal - 1;
                        const altoIdx = bassIdx - 2; 

                        if (bassIdx >= 2) {
                            const isNewBass = (v === bassIdx);
                            const isNewAlto = (v === altoIdx);
                            const isExistingBass = (e.voiceIndex === bassIdx);
                            const isExistingAlto = (e.voiceIndex === altoIdx);

                            if ((isNewBass && isExistingAlto) || (isNewAlto && isExistingBass)) {
                                const bassTrans = isNewBass ? t : e.transposition;
                                const altoTrans = isNewAlto ? t : e.transposition;

                                // Alto Shift must be >= Bass Shift + 12 (Octave)
                                if (altoTrans < bassTrans + 12) stratFail = true;
                            }
                        }

                        // Rule 4B General Separation (v vs v+2)
                        if (Math.abs(e.voiceIndex - v) === 2) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            // Higher Voice Shift >= Lower Voice Shift + 7
                            if (highVoiceTrans < lowVoiceTrans + 7) stratFail = true;
                        }
                    }
                    if (stratFail) continue;

                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quota Checks
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;
                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;

                        const intervalClass = Math.abs(t % 12);
                        const isRestricted = [3, 4, 8, 9].includes(intervalClass);
                        const isFree = [0, 7].includes(intervalClass) || intervalClass === 5; 
                        const nextRestricted = nRestricted + (isRestricted ? 1 : 0);
                        const nextFree = nFree + (isFree ? 1 : 0);

                        if (nextRestricted > 1 && nextRestricted >= nextFree) continue;
                        if (options.thirdSixthMode === 'None' && isRestricted) continue;
                        if (options.thirdSixthMode === 'Max 1' && nextRestricted > 1) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && isRestricted) continue;

                        // Phase 1 Check: Structural Compatibility
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;
                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        // Phase 5 Check: Metric Compliance (Absolute Time)
                        const tempNextEntry: StrettoChainOption = {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * 2,
                            voiceIndex: v
                        };

                        if (!checkMetricCompliance(variant, tempNextEntry, chain, variants, variantIndices, 4, 4)) {
                            continue;
                        }

                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, tempNextEntry];

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            nextRestricted,
                            nextFree
                        );
                    }
                }
            }
        }
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = variants[0].length8;

    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: options.subjectVoiceIndex }],
        [0],
        initialVoiceState,
        0, 0, 0, 1
    );

    // Grouping Logic: Group by [Rhythm Structure] + [Voice Map]
    const groupedMap = new Map<string, StrettoChainResult[]>();

    results.forEach(res => {
        // Key: Delays + Voices (ignoring intervals)
        // Format: "D:0,2,4|V:0,1,2"
        const delays = res.entries.map(e => e.startBeat).join(',');
        const voices = res.entries.map(e => e.voiceIndex).join(',');
        const key = `D:${delays}|V:${voices}`;

        if (!groupedMap.has(key)) groupedMap.set(key, []);
        groupedMap.get(key)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groupedMap.forEach((group) => {
        // Sort group by score
        group.sort((a,b) => b.score - a.score);
        const leader = group[0];

        // Attach variations if multiple exist
        if (group.length > 1) {
            leader.variations = group.slice(1);
        }
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort((a,b) => b.score - a.score).slice(0, MAX_RESULTS),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, StrettoSearchReport } from '../../types';
import { INTERVALS } from './strettoConstants';
import { calculateStrettoScore, SubjectVariant } from './strettoScoring';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

// --- Precomputation: Scales & Inversion ---

const SCALE_INTERVALS: Record<string, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11],
    'Natural Minor': [0, 2, 3, 5, 7, 8, 10],
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11],
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], 
    'Dorian': [0, 2, 3, 5, 7, 9, 10],
    'Phrygian': [0, 1, 3, 5, 7, 8, 10],
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10],
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; 
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; 

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalNote[] {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return [];

    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); 
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    return monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));
}

// --- Rule Definitions (Pruning) ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
// STRICT RULE: Include 5 (P4) in Perfect Intervals to prevent parallel 4ths
const PERFECT_INTERVALS = new Set([0, 7, 5]);

/**
 * PHASE 1 CHECK: Structural Validity (Pairwise)
 * Relaxed: Does NOT check "Ends on Dissonance" (C6) as that is position-dependent.
 * Checks: Parallel Perfects (including P4), Run Length <= 2.
 */
function checkCounterpointStructure(variantA: SubjectVariant, variantB: SubjectVariant, delay8: number, transposition: number): { compatible: boolean } {
    const notesA = variantA.notes;
    const notesB = variantB.notes;
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) timeline.get(tick)!.pB = n.pitch + transposition;
        }
    });

    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    let dissRunLength = 0; 
    let lastIsDiss = false;

    for (let i = 0; i < ticks.length; i++) {
        const t = ticks[i];
        const state = timeline.get(t)!;

        if (state.pA === undefined || state.pB === undefined) {
            // Monophonic moment - reset trackers
            prevP1 = null; prevP2 = null;
            dissRunLength = 0;
            lastIsDiss = false;
            // Note: Rule C6 (Resolution into silence) ignored here to allow chaining
            continue;
        }

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects (Now includes P4 via PERFECT_INTERVALS)
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = p1 !== prevP1;
            const p2Moved = p2 !== prevP2;

            if (p1Moved && p2Moved) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) return { compatible: false };
                }
            }
        }

        // Rule 6: Dissonance (Structural)
        let isDiss = DISSONANT_INTERVALS.has(interval);
        if (interval === 5) isDiss = true; // P4 against bass always diss in 2-part

        if (isDiss) {
            if (!lastIsDiss) dissRunLength = 1;
            else dissRunLength++;

            // Rule C2: Event Limit (r <= 2)
            if (dissRunLength > 2) return { compatible: false };

            lastIsDiss = true;
        } else {
            dissRunLength = 0;
            lastIsDiss = false;
        }

        prevP1 = p1; prevP2 = p2;
    }

    return { compatible: true };
}

// Helper: Determine beat strength
function isStrong8th(tick8: number, tsNum: number, tsDenom: number): boolean {
    // Convert 8th tick to measure position
    // For 4/4: 8 eighths per bar. Strong are 0 (Beat 1) and 4 (Beat 3).
    // For 3/4: 6 eighths. Strong are 0 (Beat 1).
    const eighthsPerBar = (tsNum * 8) / tsDenom;
    const pos = tick8 % eighthsPerBar;

    if (pos === 0) return true; // Downbeat always strong

    if (tsNum === 4 && tsDenom === 4) {
        if (pos === 4) return true; // Beat 3 in 4/4
    }

    return false;
}

/**
 * PHASE 5 CHECK: Metric Compliance
 * Checks Rule 6 C4 (Metric Constraints) using absolute timestamps.
 */
function checkMetricCompliance(
    newVariant: SubjectVariant, 
    newEntry: StrettoChainOption,
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[],
    tsNum: number = 4,
    tsDenom: number = 4
): boolean {

    const newStart8 = Math.round(newEntry.startBeat * 2);

    // Check against every existing voice
    for (let k = 0; k < chain.length; k++) {
        const existEntry = chain[k];
        const existVariant = variants[variantIndices[k]];
        const existStart8 = Math.round(existEntry.startBeat * 2);

        // Determine overlapping region
        const overlapStart = Math.max(newStart8, existStart8);
        const overlapEnd = Math.min(newStart8 + newVariant.length8, existStart8 + existVariant.length8);

        if (overlapEnd <= overlapStart) continue;

        let dissRunLength = 0;
        let lastIsDiss = false;

        // Iterate overlap ticks
        for (let t = overlapStart; t < overlapEnd; t++) {
            const tRelNew = t - newStart8;
            const tRelExist = t - existStart8;

            const noteNew = newVariant.notes.find(n => n.relTick8 <= tRelNew && (n.relTick8 + n.dur8) > tRelNew);
            const noteExist = existVariant.notes.find(n => n.relTick8 <= tRelExist && (n.relTick8 + n.dur8) > tRelExist);

            if (!noteNew || !noteExist) {
                dissRunLength = 0; lastIsDiss = false; continue;
            }

            const p1 = noteNew.pitch + newEntry.transposition;
            const p2 = noteExist.pitch + existEntry.transposition;
            const lo = Math.min(p1, p2);
            const hi = Math.max(p1, p2);
            const interval = (hi - lo) % 12;

            let isDiss = DISSONANT_INTERVALS.has(interval);
            if (interval === 5) isDiss = true;

            const isStrong = isStrong8th(t, tsNum, tsDenom);

            if (isDiss) {
                if (!lastIsDiss) dissRunLength = 1; else dissRunLength++;

                // Rule C4B: If Strong beat, resolution must be immediate (Length 1 max)
                // This means a dissonance cannot *continue* from a strong beat, nor *start* and extend
                if (isStrong && dissRunLength > 1) return false; 

                // Rule C4A: If r=2, BOTH must be weak.
                // If we hit length 2, we check current (t) and prev (t-1).
                // If either is strong, fail.
                if (dissRunLength === 2) {
                    const prevIsStrong = isStrong8th(t - 1, tsNum, tsDenom);
                    if (isStrong || prevIsStrong) return false; 
                }

                lastIsDiss = true;
            } else {
                dissRunLength = 0;
                lastIsDiss = false;
            }
        }
    }
    return true;
}

// --- Generator ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    const baseNotes = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    const variants: SubjectVariant[] = [];
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Phase 1: STRUCTURAL PAIRWISE PRECOMPUTATION
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    // Only check structural rules here (invariance), Metric rules checked later
                    const res = checkCounterpointStructure(vA, vB, d, t);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    const results: StrettoChainResult[] = [];

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], 
        voiceEndTimes8: number[], 
        nInv: number, 
        nTrunc: number,
        nRestricted: number,
        nFree: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS * 3) return; // Allow more raw results for grouping later
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            const final = calculateStrettoScore(chain, variants, variantIndices, options);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; 
        const prevEntry = chain[depth - 1];

        // --- RULE 1 & 2: DELAY LOGIC (STRICT) ---
        const possibleDelays8: number[] = [];
        let minD = 1; 
        let maxD = Math.floor(subjectLength8 * (2/3)); 

        if (depth > 0) {
            if (depth + 1 > 3) maxD = Math.min(maxD, Math.floor(subjectLength8 * 0.5) - 1);
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                maxD = Math.min(maxD, prevDelay8 + 2);
                if (depth >= 3) {
                    const prevPrevDelay8 = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                    if (prevDelay8 > prevPrevDelay8) maxD = Math.min(maxD, prevDelay8 - 1);
                }
                if (prevDelay8 > (subjectLength8 / 2)) maxD = Math.min(maxD, prevDelay8 - 1);
            }
        }

        for (let d = minD; d <= maxD; d++) possibleDelays8.push(d);
        possibleDelays8.sort((a,b) => a - b); 

        for (const delay8 of possibleDelays8) {
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                if (delay8 === prevDelay8 && delay8 >= (subjectLength8 / 3)) continue;
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            for (const t of transpositions) {
                for (let v = 0; v < options.ensembleTotal; v++) {

                    // --- RULE 7: RE-ENTRY ---
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; 

                    // --- RULE 4: STRATIFICATION (STRICT - Transposition Based) ---
                    // "Voice Crossing" is allowed in terms of Pitch, but the structural Layers must be ordered.
                    // High Index = Lower Voice. Low Index = Higher Voice.
                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];

                        // Rule 4A: Neighbor Check
                        if (Math.abs(e.voiceIndex - v) === 1) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);

                            // The shift (transposition) of the Higher Voice must be >= Lower Voice
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            if (highVoiceTrans < lowVoiceTrans) stratFail = true;
                        }

                        // Rule 4B: Bass Clearance
                        const bassIdx = options.ensembleTotal - 1;
                        const altoIdx = bassIdx - 2; 

                        if (bassIdx >= 2) {
                            const isNewBass = (v === bassIdx);
                            const isNewAlto = (v === altoIdx);
                            const isExistingBass = (e.voiceIndex === bassIdx);
                            const isExistingAlto = (e.voiceIndex === altoIdx);

                            if ((isNewBass && isExistingAlto) || (isNewAlto && isExistingBass)) {
                                const bassTrans = isNewBass ? t : e.transposition;
                                const altoTrans = isNewAlto ? t : e.transposition;

                                // Alto Shift must be >= Bass Shift + 12 (Octave)
                                if (altoTrans < bassTrans + 12) stratFail = true;
                            }
                        }

                        // Rule 4B General Separation (v vs v+2)
                        if (Math.abs(e.voiceIndex - v) === 2) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            // Higher Voice Shift >= Lower Voice Shift + 7
                            if (highVoiceTrans < lowVoiceTrans + 7) stratFail = true;
                        }
                    }
                    if (stratFail) continue;

                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quota Checks
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;
                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;

                        const intervalClass = Math.abs(t % 12);
                        const isRestricted = [3, 4, 8, 9].includes(intervalClass);
                        const isFree = [0, 7].includes(intervalClass) || intervalClass === 5; 
                        const nextRestricted = nRestricted + (isRestricted ? 1 : 0);
                        const nextFree = nFree + (isFree ? 1 : 0);

                        if (nextRestricted > 1 && nextRestricted >= nextFree) continue;
                        if (options.thirdSixthMode === 'None' && isRestricted) continue;
                        if (options.thirdSixthMode === 'Max 1' && nextRestricted > 1) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && isRestricted) continue;

                        // Phase 1 Check: Structural Compatibility
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;
                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        // Phase 5 Check: Metric Compliance (Absolute Time)
                        const tempNextEntry: StrettoChainOption = {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * 2,
                            voiceIndex: v
                        };

                        if (!checkMetricCompliance(variant, tempNextEntry, chain, variants, variantIndices, 4, 4)) {
                            continue;
                        }

                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, tempNextEntry];

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            nextRestricted,
                            nextFree
                        );
                    }
                }
            }
        }
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = variants[0].length8;

    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: options.subjectVoiceIndex }],
        [0],
        initialVoiceState,
        0, 0, 0, 1
    );

    // Grouping Logic: Group by [Rhythm Structure] + [Voice Map]
    const groupedMap = new Map<string, StrettoChainResult[]>();

    results.forEach(res => {
        // Key: Delays + Voices (ignoring intervals)
        // Format: "D:0,2,4|V:0,1,2"
        const delays = res.entries.map(e => e.startBeat).join(',');
        const voices = res.entries.map(e => e.voiceIndex).join(',');
        const key = `D:${delays}|V:${voices}`;

        if (!groupedMap.has(key)) groupedMap.set(key, []);
        groupedMap.get(key)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groupedMap.forEach((group) => {
        // Sort group by score
        group.sort((a,b) => b.score - a.score);
        const leader = group[0];

        // Attach variations if multiple exist
        if (group.length > 1) {
            leader.variations = group.slice(1);
        }
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort((a,b) => b.score - a.score).slice(0, MAX_RESULTS),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

import { StrettoChainOption, StrettoSearchOptions, StrettoChainResult, ScoreLog } from '../../types';
import { INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';

// --- Weights & Constants ---
const W_S1 = 0.2; // Unweighted Dissonance
const W_S2 = 0.3; // Weighted Dissonance
const W_S3 = 0.2; // NCT Ratio
const W_S4 = 0.3; // Unprepared Dissonance

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);

// Chord Templates (Pitch Class Sets) for Metric S3
const CHORD_TEMPLATES: number[][] = [
    [0, 4, 7],     // Major
    [0, 3, 7],     // Minor
    [0, 3, 6],     // Dim
    [0, 4, 8],     // Aug
    [0, 4, 7, 11], // Maj7
    [0, 3, 7, 10], // m7
    [0, 4, 7, 10], // Dom7
    [0, 3, 7, 11], // mM7
    [0, 3, 6, 9],  // dim7
    [0, 3, 6, 10], // m7b5
    [0, 4, 10],    // It+6
    [0, 4, 6, 10], // Fr+6
];

// Helper Interfaces for Internal Calculation
interface InternalNote {
    relTick8: number;
    dur8: number;
    pitch: number;
}

export interface SubjectVariant {
    type: 'N' | 'I';
    truncationBeats: number;
    notes: InternalNote[];
    length8: number;
}

function countNCTs(pitches: number[]): number {
    if (pitches.length === 0) return 0;
    const pcs = Array.from(new Set(pitches.map(p => p % 12)));
    const Q_len = pcs.length;

    let maxOverlap = 0;

    for (const template of CHORD_TEMPLATES) {
        for (let i = 0; i < 12; i++) {
            const shiftedTemplate = template.map(x => (x + i) % 12);
            let overlap = 0;
            for (const pc of pcs) {
                if (shiftedTemplate.includes(pc)) overlap++;
            }
            if (overlap > maxOverlap) maxOverlap = overlap;
        }
    }

    return Q_len - maxOverlap;
}

/**
 * Calculates the S1-S4 metrics for a generated chain.
 */
export function calculateStrettoScore(
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[], 
    options: StrettoSearchOptions
): StrettoChainResult {

    // 1. Build Timeline
    // Map tick -> active voices
    const timeline = new Map<number, {pitch: number, voice: number, dur8: number}[]>();
    let maxT = 0;

    chain.forEach((e, i) => {
        const variant = variants[variantIndices[i]];
        const start8 = Math.round(e.startBeat * 2);

        variant.notes.forEach(n => {
            for (let t=0; t<n.dur8; t++) {
                const tick = start8 + n.relTick8 + t;
                if (!timeline.has(tick)) timeline.set(tick, []);
                timeline.get(tick)!.push({ 
                    pitch: n.pitch + e.transposition, 
                    voice: e.voiceIndex,
                    dur8: n.dur8
                });
                if (tick > maxT) maxT = tick;
            }
        });
    });

    // --- 1B. Run Harmony Analysis for UI ---
    // Convert the 8th-note timeline to the 16th-note format required by analyzeStrettoHarmony
    // (Timeline uses 8th notes, analyzeStrettoHarmony ticks are abstract but often higher resolution.
    //  Here we simply scale by 2 to map 8th to 16th to fit the expected input format logic if needed,
    //  or just use the ticks as IDs. The analyzer expects {pitch, dur16}. 
    //  dur8 * 2 = dur16.)
    const harmonyTimeline: Record<number, Record<number, { pitch: number, dur16: number }>> = {};
    const harmonyTicks: number[] = [];

    timeline.forEach((voices, t) => {
        const tick16 = t * 2; // Converting 8th-grid index to 16th-grid space
        harmonyTicks.push(tick16);
        harmonyTimeline[tick16] = {};
        voices.forEach(v => {
            harmonyTimeline[tick16][v.voice] = { pitch: v.pitch, dur16: v.dur8 * 2 };
        });
    });

    const harmonyAnalysis = analyzeStrettoHarmony(harmonyTimeline, harmonyTicks);

    const timePoints = Array.from(timeline.keys()).sort((a,b) => a-b);

    let totalPolyTime = 0;
    let totalDissTime = 0; // S1
    let totalWeightedDissTime = 0; // S2
    let weightedTotalPoly = 0; // S2 Denom
    let totalNCT = 0; // S3
    let S3_denom = 0; // S3 Denom

    let totalDissEvents = 0; // S4
    let unpreparedDissEvents = 0; // S4

    // Track previous state for S4 (Preparation check)
    const previousStateByVoice = new Map<number, {pitch: number, isConsonantAgainstBass: boolean}>();
    let prevBass: number | null = null;

    // 2. Iterate Timeline
    timePoints.forEach(t => {
        const voices = timeline.get(t)!;

        // Update monophonic state for S4 continuity
        if (voices.length === 1) {
            prevBass = voices[0].pitch;
            previousStateByVoice.clear();
            previousStateByVoice.set(voices[0].voice, { pitch: voices[0].pitch, isConsonantAgainstBass: true });
            return;
        }

        if (voices.length < 2) return;

        totalPolyTime++; 

        // S2 Weighting: Strong beat (divisible by 2 for 4/4 quarter assumption on 8th grid)
        const isStrong = (t % 2 === 0); 
        const weight = isStrong ? 1.5 : 1.0;
        weightedTotalPoly += weight;

        const pitches = voices.map(v => v.pitch).sort((a,b)=>a-b);
        const bass = pitches[0];

        // --- S1 & S2: Dissonance ---
        let isDiss = false;
        for(let i=0; i<pitches.length; i++) {
            for(let j=i+1; j<pitches.length; j++) {
                const int = (pitches[j] - pitches[i]) % 12;
                if (DISSONANT_INTERVALS.has(int)) isDiss = true;
                if (int === 5 && pitches[i] === bass) isDiss = true;
            }
        }

        if (isDiss) {
            totalDissTime++;
            totalWeightedDissTime += weight;
        }

        // --- S3: NCT ---
        const nctCount = countNCTs(pitches);
        totalNCT += nctCount;
        S3_denom += voices.length;

        // --- S4: Unprepared Dissonance ---
        voices.forEach(v => {
            if (v.pitch === bass) return;

            const intVsBass = (v.pitch - bass + 1200) % 12;
            const isDissVsBass = DISSONANT_INTERVALS.has(intVsBass) || intVsBass === 5;

            if (isDissVsBass) {
                totalDissEvents++;

                // P1: Must have been consonant previously
                const prevState = previousStateByVoice.get(v.voice);
                let prepared = false;

                if (prevState && prevState.isConsonantAgainstBass) {
                    // P2: Single motion constraint
                    const bassMoved = (prevBass !== null && prevBass !== bass);
                    const voiceMoved = (prevState.pitch !== v.pitch);

                    // XOR logic: Only one should move for strict preparation
                    if ((!voiceMoved && bassMoved) || (voiceMoved && !bassMoved)) {
                        prepared = true;
                    }
                }

                if (!prepared) {
                    unpreparedDissEvents++;
                }
            }
            // Update state
            previousStateByVoice.set(v.voice, { pitch: v.pitch, isConsonantAgainstBass: !isDissVsBass });
        });
        prevBass = bass;
    });

    // 3. Final Calculation
    const S1 = totalPolyTime > 0 ? totalDissTime / totalPolyTime : 0;
    const S2 = weightedTotalPoly > 0 ? totalWeightedDissTime / weightedTotalPoly : 0;
    const S3 = S3_denom > 0 ? totalNCT / S3_denom : 0;
    const S4 = totalDissEvents > 0 ? unpreparedDissEvents / totalDissEvents : 0;

    const penalty = (S1 * W_S1) + (S2 * W_S2) + (S3 * W_S3) + (S4 * W_S4);
    const score = Math.max(0, Math.round(1000 * (1 - penalty)));

    const log: ScoreLog = { 
        base: 1000, 
        bonuses: [], 
        penalties: [
            { reason: `S1: Unweighted Diss (${(S1*100).toFixed(0)}%)`, points: Math.round(S1 * 1000 * W_S1) },
            { reason: `S2: Weighted Diss (${(S2*100).toFixed(0)}%)`, points: Math.round(S2 * 1000 * W_S2) },
            { reason: `S3: NCT Density (${(S3*100).toFixed(0)}%)`, points: Math.round(S3 * 1000 * W_S3) },
            { reason: `S4: Unprepared Diss (${(S4*100).toFixed(0)}%)`, points: Math.round(S4 * 1000 * W_S4) },
        ], 
        total: score 
    };

    // 4. Consonant End Validation (Gatekeeper A)
    let isValid = true;
    if (options.requireConsonantEnd) {
        chain.forEach((e, i) => {
            const variant = variants[variantIndices[i]];
            const end8 = Math.round(e.startBeat * 2) + variant.length8;
            const lastMoment = end8 - 1;

            const activeVoices = timeline.get(lastMoment);
            if (activeVoices && activeVoices.length > 1) {
                const pitches = activeVoices.map(v => v.pitch).sort((a,b)=>a-b);
                const bass = pitches[0];
                const myVoice = activeVoices.find(v => v.voice === e.voiceIndex);

                if (myVoice) {
                    let isClean = true;
                    if (myVoice.pitch === bass) {
                        for (const other of pitches) {
                            if (other === bass) continue;
                            const int = (other - bass) % 12;
                            if (DISSONANT_INTERVALS.has(int) || int === 5) isClean = false;
                        }
                    } else {
                        const int = (myVoice.pitch - bass) % 12;
                        if (DISSONANT_INTERVALS.has(int) || int === 5) isClean = false;
                    }
                    if (!isClean) isValid = false;
                }
            }
        });
    }

    return {
        id: Math.random().toString(36),
        entries: chain,
        warnings: [],
        score,
        scoreLog: log,
        detectedChords: harmonyAnalysis.chords, // Now populated correctly
        dissonanceRatio: S1,
        pairDissonanceScore: S4 * 100,
        isValid
    };
}

