const MAJOR_SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number, useChromatic: boolean): number {
    if (useChromatic) {
        return pivot - (pitch - pivot);
    }

    // Diatonic Inversion (Major Scale Assumption)
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;

    // Find closest scale step
    let degree = -1;
    let minErr = 99;
    MAJOR_SCALE_STEPS.forEach((s, i) => {
        if (Math.abs(s - semitone) < minErr) { 
            minErr = Math.abs(s - semitone); 
            degree = i; 
        }
    });

    // Invert the degree index relative to 0 (root)
    const absDegree = (octaves * 7) + degree;
    const invAbsDegree = -absDegree;

    const invOctaves = Math.floor(invAbsDegree / 7);
    const invIndex = (invAbsDegree % 7 + 7) % 7;

    return pivot + (invOctaves * 12) + MAJOR_SCALE_STEPS[invIndex];
}

// Determines if any dissonance exists in a set of pitches
function analyzeVerticalSlice(pitches: number[]): { isDissonant: boolean; label: string } {
    if (pitches.length < 2) return { isDissonant: false, label: '' };

    const sorted = [...pitches].sort((a,b) => a-b);
    const bass = sorted[0];

    for (let i = 0; i < sorted.length; i++) {
        for (let j = i + 1; j < sorted.length; j++) {
            const p1 = sorted[i];
            const p2 = sorted[j];
            const interval = Math.abs(p1 - p2);
            const ic = interval % 12;

            const isBassPair = (p1 === bass || p2 === bass);
            let isDiss = DISSONANT_INTERVALS.includes(ic);
            if (ic === 5 && isBassPair) isDiss = true; // P4 against bass

            if (isDiss) {
                // Prioritize displaying the "crunchiest" interval
                return { isDissonant: true, label: getIntervalLabel(interval) };
            }
        }
    }

    // If no dissonance, return first interval label or generic
    const firstInt = Math.abs(sorted[1] - sorted[0]);
    return { isDissonant: false, label: getIntervalLabel(firstInt) };
}

// Special function for Dyad inference (2 pitch classes)
function analyzeDyad(pc1: number, pc2: number): { name: string; root: number; quality: string } | null {
    const diff = (pc2 - pc1 + 12) % 12; // Assuming pc1 is bass for interval calc

    // 3rd (Major or Minor) -> Root is bottom
    if (diff === 3) return { name: "Min (no 5)", root: pc1, quality: "Min" };
    if (diff === 4) return { name: "Maj (no 5)", root: pc1, quality: "Maj" };

    // 6th (Inverted 3rd) -> Root is top
    if (diff === 8) return { name: "Maj (no 5)", root: pc2, quality: "Maj" }; // m6 -> Inverted Maj3
    if (diff === 9) return { name: "Min (no 5)", root: pc2, quality: "Min" }; // M6 -> Inverted min3

    // Perfect 5th -> Power Chord
    if (diff === 7) return { name: "5", root: pc1, quality: "5" };

    // Tritone -> Diminished (no 3rd) - Usually implies dim triad or dim7
    if (diff === 6) return { name: "Dim (no 3)", root: pc1, quality: "Dim" };

    // P4, 2nds, 7ths are treated as Intervals, not Chords here
    return null;
}

// Helper to identify chord and return quality + NCT count
// Prioritizes shapes where the chord root matches the actual bass note
function identifyChordWithNCT(pitches: number[]): { name: string, quality: string, nct: number, chordTones: number[], rootPC: number } | null {
    if (pitches.length < 2) return null;
    const uniquePCs = Array.from(new Set(pitches.map(p => p % 12)));

    // Dyad/Cluster handling for 2 unique PCs (even if multiple octaves)
    if (uniquePCs.length === 2) {
        const sortedPCs = [...uniquePCs].sort((a,b) => a-b);
        const sortedInput = [...pitches].sort((a,b) => a-b);
        const bassPC = sortedInput[0] % 12;
        const otherPC = uniquePCs.find(p => p !== bassPC) || bassPC;

        const dyadAnalysis = analyzeDyad(bassPC, otherPC);
        if (dyadAnalysis) {
            return {
                name: `${getStrictPitchName(dyadAnalysis.root).replace(/\d/g, '')} ${dyadAnalysis.name}`,
                quality: dyadAnalysis.quality,
                nct: 0,
                chordTones: uniquePCs,
                rootPC: dyadAnalysis.root
            };
        } else {
            // It's an interval (P4, 2nd, 7th)
            return null;
        }
    }

    // 3+ Unique PCs -> Standard Shape Matching
    const sorted = [...pitches].sort((a,b) => a-b);
    const bassPC = sorted[0] % 12;

    let bestMatch = null;
    let bestScore = -Infinity;

    for (const root of uniquePCs) {
        const intervals = uniquePCs.map(pc => (pc - root + 12) % 12);
        for (const shape of CHORD_SHAPES) {
            const matchedIntervals = intervals.filter(i => shape.intervals.includes(i));
            const nctCount = intervals.length - matchedIntervals.length;

            // Basic heuristic: Must match at least 2 notes of the shape
            if (matchedIntervals.length < 2) continue;

            // --- CONSTRAINT: Extension Existence ---
            if (shape.intervals.length > 3) {
                const extensionInterval = shape.intervals[shape.intervals.length - 1];
                if (!matchedIntervals.includes(extensionInterval)) {
                    continue; // Skip this shape, it's invalid (e.g. Maj7 without 7)
                }
            }

            // --- SCORING LOGIC v3 ---
            let missingPenalty = 0;
            const missingIntervals = shape.intervals.filter(i => !matchedIntervals.includes(i));

            missingIntervals.forEach(int => {
                if (int === 3 || int === 4) {
                    missingPenalty += 30; // Missing 3rd is expensive
                } else if (int === 7 || int === 6 || int === 8) {
                    missingPenalty += 10; // Missing 5th is cheap
                } else {
                    missingPenalty += 10; 
                }
            });

            let score = (matchedIntervals.length * 100) 
                      - (nctCount * 500) 
                      - missingPenalty;

            if (root === bassPC) score += 5;

            if (score > bestScore) {
                bestScore = score;
                const rootName = getStrictPitchName(root).replace(/\d/g, '');

                // Identify which PCs are Chord Tones
                const chordTones = uniquePCs.filter(pc => {
                    const int = (pc - root + 12) % 12;
                    return shape.intervals.includes(int);
                });

                bestMatch = { 
                    name: `${rootName} ${shape.name}`, 
                    quality: shape.name, 
                    nct: nctCount,
                    chordTones: chordTones,
                    rootPC: root
                };
            }
        }
    }
    return bestMatch;
}

export function generatePolyphonicHarmonicRegions(notes: RawNote[], keyRoot: number = 0): HarmonicRegion[] {
    if (notes.length === 0) return [];

    // 1. Collect all time boundaries
    const timePoints = new Set<number>();
    notes.forEach(n => {
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });
    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);

    const regions: HarmonicRegion[] = [];
    let consecutiveDissonanceCount = 0;

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const start = sortedPoints[i];
        const end = sortedPoints[i+1];
        const mid = start + (end - start) / 2; // Sample middle to avoid boundary edge cases

        // Active notes in this slice
        const active = notes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) {
            consecutiveDissonanceCount = 0; // Reset on rest/monophony
            continue;
        }

        const pitches = active.map(n => n.midi);
        const chordMatch = identifyChordWithNCT(pitches);
        const { isDissonant, label } = analyzeVerticalSlice(pitches);

        let type: HarmonicRegion['type'] = 'consonant_stable';

        let detailedInfo: NonNullable<HarmonicRegion['detailedInfo']> = {
            chordName: "",
            allNotes: active.map(n => getPitchName(n.midi, keyRoot)),
            noteDetails: [],
            chordTones: [],
            ncts: []
        };

        if (chordMatch) {
            const { quality, nct, name, chordTones, rootPC } = chordMatch;
            const isConsonantChord = CONSONANT_QUALITIES.has(quality);

            detailedInfo.chordName = name;
            detailedInfo.quality = quality;

            const ctSet = new Set(chordTones);
            const isAug = quality.toLowerCase().includes('aug');

            active.forEach(n => {
                const pc = n.midi % 12;
                const interval = (pc - rootPC + 12) % 12;
                const noteName = getPitchName(n.midi, keyRoot);

                let role: NoteRole['role'] = 'NCT';

                if (ctSet.has(pc)) {
                    detailedInfo.chordTones.push(noteName);

                    if (interval === 0) role = 'Root';
                    else if (interval === 3 || interval === 4) role = '3rd';
                    else if (interval === 7) role = '5th';
                    else if (interval === 6) role = 'Ext'; // Dim 5 / Tritone
                    else if (interval === 8) {
                        // 8 is Min 6th or Aug 5th.
                        // If chord quality is Aug, treat as 5th (Augmented)
                        role = isAug ? '5th' : 'Ext'; 
                    }
                    else role = 'Ext'; // 7th, 6th, etc.
                } else {
                    detailedInfo.ncts.push(noteName);
                    role = 'NCT';
                }

                detailedInfo.noteDetails.push({
                    name: noteName,
                    midi: n.midi,
                    role: role
                });
            });

            // Case 5: 2+ NCTs -> Red
            if (nct >= 2) {
                type = 'dissonant_severe';
                consecutiveDissonanceCount++; 
            } 
            // 1 NCT cases
            else if (nct === 1) {
                if (isConsonantChord) {
                    type = 'dissonant_secondary'; 
                } else {
                    type = 'dissonant_tertiary'; 
                }
                consecutiveDissonanceCount++;
            }
            // Clean Chords (0 NCT)
            else {
                if (isConsonantChord) {
                    type = 'consonant_stable'; 
                    consecutiveDissonanceCount = 0; 
                } else {
                    type = 'dissonant_primary'; 
                    consecutiveDissonanceCount++;
                }
            }
        } else {
            // No Chord Detected -> Interval Logic
            detailedInfo.chordName = `Interval: ${label}`;

            // For Intervals, we treat them as 'Chord Tones' but they don't have harmonic roles
            // We'll mark them as Ext to give them Purple color or maybe Root/5th if P5?
            // Let's just default to 'Root' for bass and 'Ext' for others to show color variety?
            // Actually, user spec is specific for Harmonic breakdown. For intervals, maybe just use NCT (Orange) or Ext (Purple).
            // Let's fallback to Ext (Purple) for clarity.
            const sortedActive = [...active].sort((a,b)=>a.midi - b.midi);
            sortedActive.forEach((n, i) => {
                detailedInfo.noteDetails.push({
                    name: getPitchName(n.midi, keyRoot),
                    midi: n.midi,
                    role: i === 0 ? 'Root' : 'Ext' // Arbitrary visual assignment for raw intervals
                });
            });
            detailedInfo.chordTones = detailedInfo.allNotes; 

            if (isDissonant) {
                consecutiveDissonanceCount++;
                if (consecutiveDissonanceCount === 1) {
                    type = 'dissonant_primary'; 
                } else if (consecutiveDissonanceCount === 2) {
                    type = 'dissonant_secondary'; 
                } else {
                    type = 'dissonant_tertiary'; 
                }
            } else {
                type = 'consonant_stable'; 
                consecutiveDissonanceCount = 0; 
            }
        }

        regions.push({
            startTick: start,
            endTick: end,
            type: type,
            intervalLabel: detailedInfo.chordName, // Short label
            description: detailedInfo.ncts.length > 0 ? `NCTs: ${detailedInfo.ncts.join(', ')}` : undefined,
            detailedInfo
        });
    }

    return regions;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60,
    useChromaticInversion: boolean = false,
    keyRoot: number = 0 // New param for spelling
): StrettoCandidate {

    if (subject.length === 0) {
        return {
            id: `empty`, intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, nctRatio: 0, pairDissonanceScore: 0, endsOnDissonance: true
        };
    }

    const subjectEntryPitch = subject[0].midi;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi: number;

        if (isInverted) {
            const rawInverted = invertPitch(n.midi, pivotMidi, useChromaticInversion);
            const invertedStart = invertPitch(subjectEntryPitch, pivotMidi, useChromaticInversion);
            const targetStart = subjectEntryPitch + intervalSemis;
            const shift = targetStart - invertedStart;
            newMidi = rawInverted + shift;
        } else {
            newMidi = n.midi + intervalSemis;
        }

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getPitchName(newMidi, keyRoot),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const allNotes = [...subject, ...answer];

    // Generate Regions using Polyphonic Logic with Key Root
    const harmonicRegions = generatePolyphonicHarmonicRegions(allNotes, keyRoot);

    // Calculate Metrics
    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let nctTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;

        // Dissonance accumulation
        if (r.type !== 'consonant_stable') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }

        // NCT accumulation
        if (r.detailedInfo && r.detailedInfo.ncts.length > 0) {
            nctTicks += dur;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;
    const nctRatio = totalOverlapTicks > 0 ? (nctTicks / totalOverlapTicks) : 0;

    let pairDissonanceScore = 0;
    harmonicRegions.forEach(r => {
        const mid = r.startTick + (r.endTick - r.startTick)/2;
        const active = allNotes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) return;

        const sorted = active.map(n => n.midi).sort((a,b) => a-b);
        const bass = sorted[0];
        let pairDissCount = 0;

        for(let i=0; i<sorted.length; i++) {
            for(let j=i+1; j<sorted.length; j++) {
                const interval = Math.abs(sorted[i] - sorted[j]);
                const ic = interval % 12;
                const isBassPair = (sorted[i] === bass || sorted[j] === bass);
                let isDiss = DISSONANT_INTERVALS.includes(ic);
                if (ic === 5 && isBassPair) isDiss = true;

                if (isDiss) pairDissCount++;
            }
        }

        const durBeats = (r.endTick - r.startTick) / ppq;
        pairDissonanceScore += (durBeats * pairDissCount);
    });

    const errors: StrettoError[] = [];

    let prevP1: number | null = null;
    let prevP2: number | null = null;

    const timePoints = new Set<number>();
    allNotes.forEach(n => { timePoints.add(n.ticks); timePoints.add(n.ticks+n.durationTicks); });
    const tPoints = Array.from(timePoints).sort((a,b)=>a-b);

    for(let i=0; i<tPoints.length-1; i++) {
        const t = tPoints[i];
        const n1 = subject.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);
        const n2 = answer.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);

        if (n1 && n2) {
            const p1 = n1.midi;
            const p2 = n2.midi;

            if (prevP1 !== null && prevP2 !== null) {
                if (prevP1 !== p1 && prevP2 !== p2) { 
                    const int1 = Math.abs(prevP1 - prevP2) % 12;
                    const int2 = Math.abs(p1 - p2) % 12;
                    const isPerfect = int2 === 0 || int2 === 7;
                    if (isPerfect && int1 === int2) {
                        const timeStr = getFormattedTime(t, ppq, ts.num, ts.den);
                        const isStrong = isStrongBeat(t, ppq, ts.num, ts.den);
                        errors.push({
                            tick: t, timeFormatted: timeStr,
                            type: int2 === 7 ? 'Parallel 5th' : 'Parallel 8ve',
                            details: 'Parallel Perfect Interval',
                            severity: isStrong ? 'fatal' : 'warning'
                        });
                    }
                }
            }
            prevP1 = p1; prevP2 = p2;
        } else {
            prevP1 = null; prevP2 = null;
        }
    }

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: allNotes,
        regions: harmonicRegions,
        dissonanceRatio,
        nctRatio,
        pairDissonanceScore: parseFloat(pairDissonanceScore.toFixed(1)),
        endsOnDissonance
    };
}

import { StrettoChainOption, StrettoSearchOptions, StrettoChainResult, ScoreLog } from '../../types';
import { INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';

// --- Weights & Constants ---
const W_S1 = 0.2; // Unweighted Dissonance
const W_S2 = 0.3; // Weighted Dissonance
const W_S3 = 0.2; // NCT Ratio
const W_S4 = 0.3; // Unprepared Dissonance

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);

// Chord Templates (Pitch Class Sets) for Metric S3
const CHORD_TEMPLATES: number[][] = [
    [0, 4, 7],     // Major
    [0, 3, 7],     // Minor
    [0, 3, 6],     // Dim
    [0, 4, 8],     // Aug
    [0, 4, 7, 11], // Maj7
    [0, 3, 7, 10], // m7
    [0, 4, 7, 10], // Dom7
    [0, 3, 7, 11], // mM7
    [0, 3, 6, 9],  // dim7
    [0, 3, 6, 10], // m7b5
    [0, 4, 10],    // It+6
    [0, 4, 6, 10], // Fr+6
];

// Helper Interfaces for Internal Calculation
interface InternalNote {
    relTick8: number;
    dur8: number;
    pitch: number;
}

export interface SubjectVariant {
    type: 'N' | 'I';
    truncationBeats: number;
    notes: InternalNote[];
    length8: number;
}

function countNCTs(pitches: number[]): number {
    if (pitches.length === 0) return 0;
    const pcs = Array.from(new Set(pitches.map(p => p % 12)));
    const Q_len = pcs.length;

    let maxOverlap = 0;

    for (const template of CHORD_TEMPLATES) {
        for (let i = 0; i < 12; i++) {
            const shiftedTemplate = template.map(x => (x + i) % 12);
            let overlap = 0;
            for (const pc of pcs) {
                if (shiftedTemplate.includes(pc)) overlap++;
            }
            if (overlap > maxOverlap) maxOverlap = overlap;
        }
    }

    return Q_len - maxOverlap;
}

/**
 * Calculates the S1-S4 metrics for a generated chain.
 */
export function calculateStrettoScore(
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[], 
    options: StrettoSearchOptions
): StrettoChainResult {

    // 1. Build Timeline
    // Map tick -> active voices
    const timeline = new Map<number, {pitch: number, voice: number, dur8: number}[]>();
    let maxT = 0;

    chain.forEach((e, i) => {
        const variant = variants[variantIndices[i]];
        const start8 = Math.round(e.startBeat * 2);

        variant.notes.forEach(n => {
            for (let t=0; t<n.dur8; t++) {
                const tick = start8 + n.relTick8 + t;
                if (!timeline.has(tick)) timeline.set(tick, []);
                timeline.get(tick)!.push({ 
                    pitch: n.pitch + e.transposition, 
                    voice: e.voiceIndex,
                    dur8: n.dur8
                });
                if (tick > maxT) maxT = tick;
            }
        });
    });

    // --- 1B. Run Harmony Analysis for UI ---
    // Convert the 8th-note timeline to the 16th-note format required by analyzeStrettoHarmony
    // (Timeline uses 8th notes, analyzeStrettoHarmony ticks are abstract but often higher resolution.
    //  Here we simply scale by 2 to map 8th to 16th to fit the expected input format logic if needed,
    //  or just use the ticks as IDs. The analyzer expects {pitch, dur16}. 
    //  dur8 * 2 = dur16.)
    const harmonyTimeline: Record<number, Record<number, { pitch: number, dur16: number }>> = {};
    const harmonyTicks: number[] = [];

    timeline.forEach((voices, t) => {
        const tick16 = t * 2; // Converting 8th-grid index to 16th-grid space
        harmonyTicks.push(tick16);
        harmonyTimeline[tick16] = {};
        voices.forEach(v => {
            harmonyTimeline[tick16][v.voice] = { pitch: v.pitch, dur16: v.dur8 * 2 };
        });
    });

    const harmonyAnalysis = analyzeStrettoHarmony(harmonyTimeline, harmonyTicks);

    const timePoints = Array.from(timeline.keys()).sort((a,b) => a-b);

    let totalPolyTime = 0;
    let totalDissTime = 0; // S1
    let totalWeightedDissTime = 0; // S2
    let weightedTotalPoly = 0; // S2 Denom
    let totalNCT = 0; // S3
    let S3_denom = 0; // S3 Denom

    let totalDissEvents = 0; // S4
    let unpreparedDissEvents = 0; // S4

    // Track previous state for S4 (Preparation check)
    const previousStateByVoice = new Map<number, {pitch: number, isConsonantAgainstBass: boolean}>();
    let prevBass: number | null = null;

    // 2. Iterate Timeline
    timePoints.forEach(t => {
        const voices = timeline.get(t)!;

        // Update monophonic state for S4 continuity
        if (voices.length === 1) {
            prevBass = voices[0].pitch;
            previousStateByVoice.clear();
            previousStateByVoice.set(voices[0].voice, { pitch: voices[0].pitch, isConsonantAgainstBass: true });
            return;
        }

        if (voices.length < 2) return;

        totalPolyTime++; 

        // S2 Weighting: Strong beat (divisible by 2 for 4/4 quarter assumption on 8th grid)
        const isStrong = (t % 2 === 0); 
        const weight = isStrong ? 1.5 : 1.0;
        weightedTotalPoly += weight;

        const pitches = voices.map(v => v.pitch).sort((a,b)=>a-b);
        const bass = pitches[0];

        // --- S1 & S2: Dissonance ---
        let isDiss = false;
        for(let i=0; i<pitches.length; i++) {
            for(let j=i+1; j<pitches.length; j++) {
                const int = (pitches[j] - pitches[i]) % 12;
                if (DISSONANT_INTERVALS.has(int)) isDiss = true;
                if (int === 5 && pitches[i] === bass) isDiss = true;
            }
        }

        if (isDiss) {
            totalDissTime++;
            totalWeightedDissTime += weight;
        }

        // --- S3: NCT ---
        const nctCount = countNCTs(pitches);
        totalNCT += nctCount;
        S3_denom += voices.length;

        // --- S4: Unprepared Dissonance ---
        voices.forEach(v => {
            if (v.pitch === bass) return;

            const intVsBass = (v.pitch - bass + 1200) % 12;
            const isDissVsBass = DISSONANT_INTERVALS.has(intVsBass) || intVsBass === 5;

            if (isDissVsBass) {
                totalDissEvents++;

                // P1: Must have been consonant previously
                const prevState = previousStateByVoice.get(v.voice);
                let prepared = false;

                if (prevState && prevState.isConsonantAgainstBass) {
                    // P2: Single motion constraint
                    const bassMoved = (prevBass !== null && prevBass !== bass);
                    const voiceMoved = (prevState.pitch !== v.pitch);

                    // XOR logic: Only one should move for strict preparation
                    if ((!voiceMoved && bassMoved) || (voiceMoved && !bassMoved)) {
                        prepared = true;
                    }
                }

                if (!prepared) {
                    unpreparedDissEvents++;
                }
            }
            // Update state
            previousStateByVoice.set(v.voice, { pitch: v.pitch, isConsonantAgainstBass: !isDissVsBass });
        });
        prevBass = bass;
    });

    // 3. Final Calculation
    const S1 = totalPolyTime > 0 ? totalDissTime / totalPolyTime : 0;
    const S2 = weightedTotalPoly > 0 ? totalWeightedDissTime / weightedTotalPoly : 0;
    const S3 = S3_denom > 0 ? totalNCT / S3_denom : 0;
    const S4 = totalDissEvents > 0 ? unpreparedDissEvents / totalDissEvents : 0;

    const penalty = (S1 * W_S1) + (S2 * W_S2) + (S3 * W_S3) + (S4 * W_S4);
    const score = Math.max(0, Math.round(1000 * (1 - penalty)));

    const log: ScoreLog = { 
        base: 1000, 
        bonuses: [], 
        penalties: [
            { reason: `S1: Unweighted Diss (${(S1*100).toFixed(0)}%)`, points: Math.round(S1 * 1000 * W_S1) },
            { reason: `S2: Weighted Diss (${(S2*100).toFixed(0)}%)`, points: Math.round(S2 * 1000 * W_S2) },
            { reason: `S3: NCT Density (${(S3*100).toFixed(0)}%)`, points: Math.round(S3 * 1000 * W_S3) },
            { reason: `S4: Unprepared Diss (${(S4*100).toFixed(0)}%)`, points: Math.round(S4 * 1000 * W_S4) },
        ], 
        total: score 
    };

    // 4. Consonant End Validation (Gatekeeper A)
    let isValid = true;
    if (options.requireConsonantEnd) {
        chain.forEach((e, i) => {
            const variant = variants[variantIndices[i]];
            const end8 = Math.round(e.startBeat * 2) + variant.length8;
            const lastMoment = end8 - 1;

            const activeVoices = timeline.get(lastMoment);
            if (activeVoices && activeVoices.length > 1) {
                const pitches = activeVoices.map(v => v.pitch).sort((a,b)=>a-b);
                const bass = pitches[0];
                const myVoice = activeVoices.find(v => v.voice === e.voiceIndex);

                if (myVoice) {
                    let isClean = true;
                    if (myVoice.pitch === bass) {
                        for (const other of pitches) {
                            if (other === bass) continue;
                            const int = (other - bass) % 12;
                            if (DISSONANT_INTERVALS.has(int) || int === 5) isClean = false;
                        }
                    } else {
                        const int = (myVoice.pitch - bass) % 12;
                        if (DISSONANT_INTERVALS.has(int) || int === 5) isClean = false;
                    }
                    if (!isClean) isValid = false;
                }
            }
        });
    }

    return {
        id: Math.random().toString(36),
        entries: chain,
        warnings: [],
        score,
        scoreLog: log,
        detectedChords: harmonyAnalysis.chords, 
        dissonanceRatio: S1,
        nctRatio: S3, // Populated from S3
        pairDissonanceScore: S4 * 100,
        isValid
    };
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';
import { DocumentTextIcon } from '../Icons';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[]; 
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance' | 'nct' | 'intensity' | 'entry' | 'errors';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    // Multi-select Filters
    const [selectedPitches, setSelectedPitches] = useState<Set<string>>(new Set());
    const [selectedIntervals, setSelectedIntervals] = useState<Set<string>>(new Set());
    const [selectedDelays, setSelectedDelays] = useState<Set<string>>(new Set());

    // Logic Filters
    const [maxDissonance, setMaxDissonance] = useState<number>(100);
    const [onlyResolved, setOnlyResolved] = useState<boolean>(false);

    // Extract unique values for filter toggles
    const { availablePitches, availableIntervals, availableDelays } = useMemo(() => {
        const pitches = new Set<string>();
        const intervals = new Set<string>();
        const delays = new Set<string>();

        candidates.forEach(c => {
            delays.add(c.delayBeats.toString());
            intervals.add(c.intervalLabel);
            const firstAnswerNote = c.notes.find(n => n.voiceIndex === 1);
            if (firstAnswerNote) {
                pitches.add(getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, ''));
            }
        });

        return {
            availablePitches: Array.from(pitches).sort(),
            availableIntervals: Array.from(intervals).sort((a,b) => a.localeCompare(b, undefined, {numeric: true})),
            availableDelays: Array.from(delays).sort((a,b) => parseFloat(a) - parseFloat(b))
        };
    }, [candidates]);

    // Combined Advanced Filtering
    const finalFilteredResults = useMemo(() => {
        return processedResults.filter(r => {
            if (!gradeFilter[r.grade]) return false;

            if (selectedPitches.size > 0) {
                const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                if (!firstAnswerNote) return false;
                const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
                if (!selectedPitches.has(pName)) return false;
            }

            if (selectedIntervals.size > 0 && !selectedIntervals.has(r.intervalLabel)) return false;

            if (selectedDelays.size > 0 && !selectedDelays.has(r.delayBeats.toString())) return false;

            if (Math.round(r.dissonanceRatio * 100) > maxDissonance) return false;

            if (onlyResolved && r.endsOnDissonance) return false;

            return true;
        });
    }, [processedResults, gradeFilter, selectedPitches, selectedIntervals, selectedDelays, maxDissonance, onlyResolved]);

    // Sorting Logic
    const sortedResults = useMemo(() => {
        const res = [...finalFilteredResults];
        res.sort((a, b) => {
            let diff = 0;
            const firstA = a.notes.find(n => n.voiceIndex === 1);
            const firstB = b.notes.find(n => n.voiceIndex === 1);

            switch (sortKey) {
                case 'grade':
                    const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                    diff = score[a.grade] - score[b.grade];
                    break;
                case 'delay':
                    diff = a.delayTicks - b.delayTicks;
                    break;
                case 'interval':
                    diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
                    break;
                case 'dissonance':
                    diff = a.dissonanceRatio - b.dissonanceRatio;
                    break;
                case 'nct':
                    diff = (a.nctRatio || 0) - (b.nctRatio || 0);
                    break;
                case 'intensity':
                    diff = a.pairDissonanceScore - b.pairDissonanceScore;
                    break;
                case 'entry':
                    diff = (firstA?.midi || 0) - (firstB?.midi || 0);
                    break;
                case 'errors':
                    diff = a.errors.length - b.errors.length;
                    break;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [finalFilteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' || key === 'nct' || key === 'intensity' ? 'desc' : 'asc'); }
    };

    const handleExport = () => {
        if (sortedResults.length === 0) return;

        let md = `| Interval | Delay | Entry | Diss Time | NCT % | Intensity | Errors |\n`;
        md += `| :--- | :--- | :--- | :--- | :--- | :--- | :--- |\n`;

        sortedResults.forEach(r => {
            const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
            const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
            const diss = `${Math.round(r.dissonanceRatio * 100)}%`;
            const nct = `${Math.round((r.nctRatio || 0) * 100)}%`;
            const intent = r.pairDissonanceScore.toFixed(1);
            const errs = r.errors.length > 0 ? r.errors.map(e => e.type).join(', ') : '-';

            md += `| ${r.intervalLabel} | ${r.delayBeats}B | ${entryNote} | ${diss} | ${nct} | ${intent} | ${errs} |\n`;
        });

        const blob = new Blob([md], { type: 'text/markdown' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Stretto_Lab_Export_${Date.now()}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const toggleFilterSet = (set: Set<string>, val: string) => {
        const next = new Set(set);
        if (next.has(val)) next.delete(val);
        else next.add(val);
        return next;
    };

    const renderToggleGroup = (label: string, items: string[], current: Set<string>, update: (s: Set<string>) => void) => (
        <div className="flex flex-col gap-1">
            <div className="flex justify-between items-center">
                <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">{label}</label>
                <button onClick={() => update(new Set())} className="text-[8px] text-brand-primary hover:underline">{current.size === 0 ? 'All' : 'Clear'}</button>
            </div>
            <div className="flex flex-wrap gap-1 max-h-12 overflow-y-auto bg-black/20 p-1 rounded border border-gray-700 shadow-inner">
                {items.map(item => (
                    <button
                        key={item}
                        onClick={() => update(toggleFilterSet(current, item))}
                        className={`px-1.5 py-0.5 text-[9px] font-bold rounded transition-all border ${current.has(item) ? 'bg-brand-primary border-brand-primary text-white shadow-sm' : 'bg-gray-800 border-gray-600 text-gray-500 hover:border-gray-400'}`}
                    >
                        {item}
                    </button>
                ))}
            </div>
        </div>
    );

    const getMetricColor = (val: number) => {
        if (val > 0.4) return 'text-red-400';
        if (val > 0.2) return 'text-yellow-400';
        return 'text-green-400';
    };

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-4">
                <div className="flex justify-between items-center -mb-2">
                    <h3 className="text-[10px] font-bold text-brand-primary uppercase tracking-tighter">Power Filter</h3>
                    <button 
                        onClick={handleExport}
                        className="flex items-center gap-1.5 px-2 py-1 bg-gray-700 hover:bg-gray-600 text-[9px] text-gray-300 rounded border border-gray-600 transition-colors"
                    >
                        <DocumentTextIcon className="w-3.5 h-3.5" /> Export Grid
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    {renderToggleGroup("Intervals", availableIntervals, selectedIntervals, setSelectedIntervals)}
                    {renderToggleGroup("Delays", availableDelays, selectedDelays, setSelectedDelays)}
                    {renderToggleGroup("Entry Pitches", availablePitches, selectedPitches, setSelectedPitches)}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-gray-700 pt-3">
                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Verdict</label>
                        <div className="flex gap-1">
                            {(['STRONG', 'VIABLE', 'INVALID'] as StrettoGrade[]).map(g => (
                                <button 
                                    key={g}
                                    onClick={() => setGradeFilter({ ...gradeFilter, [g]: !gradeFilter[g] })} 
                                    className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter[g] ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-600'}`}
                                >
                                    {g.charAt(0)}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex flex-col gap-1 bg-gray-900/50 p-2 rounded border border-gray-700">
                        <div className="flex justify-between">
                            <label className="text-[9px] font-bold text-red-300 uppercase tracking-widest">Dissonance Cap</label>
                            <span className="text-[10px] font-bold text-white bg-red-900/50 px-1 rounded">{maxDissonance}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="100" step="1" 
                            value={maxDissonance} 
                            onChange={(e) => setMaxDissonance(parseInt(e.target.value))}
                            className="w-full h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-red-500"
                        />
                    </div>

                    <div className="flex flex-col justify-end">
                        <label className={`flex items-center gap-2 p-2 bg-gray-900/50 rounded border cursor-pointer transition-all ${onlyResolved ? 'border-green-500/50 bg-green-900/10' : 'border-gray-700'}`}>
                            <input 
                                type="checkbox" 
                                checked={onlyResolved} 
                                onChange={(e) => setOnlyResolved(e.target.checked)}
                                className="w-3 h-3 rounded bg-gray-800 border-gray-600 text-brand-primary"
                            />
                            <span className={`text-[10px] font-bold uppercase tracking-tight ${onlyResolved ? 'text-green-400' : 'text-gray-500'}`}>Resolved End Only</span>
                        </label>
                    </div>
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-1">
                <div className="sticky top-0 bg-gray-900 z-10 grid grid-cols-12 gap-1 px-2 py-2 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800 items-center">
                    <div className="col-span-1"></div>
                    <button onClick={() => handleSort('interval')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'interval' ? 'text-brand-primary' : ''}`}>
                        Int {sortKey === 'interval' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('delay')} className={`col-span-1 text-left hover:text-white transition-colors ${sortKey === 'delay' ? 'text-brand-primary' : ''}`}>
                        Del
                    </button>
                    <button onClick={() => handleSort('entry')} className={`col-span-1 text-left hover:text-white transition-colors ${sortKey === 'entry' ? 'text-brand-primary' : ''}`}>
                        Ent
                    </button>

                    {/* Updated Prominent Metrics Headers */}
                    <button onClick={() => handleSort('dissonance')} className={`col-span-2 text-center hover:text-white transition-colors ${sortKey === 'dissonance' ? 'text-brand-primary' : ''}`}>
                        Diss %
                    </button>
                    <button onClick={() => handleSort('nct')} className={`col-span-2 text-center hover:text-white transition-colors ${sortKey === 'nct' ? 'text-brand-primary' : ''}`}>
                        NCT %
                    </button>

                    <button onClick={() => handleSort('intensity')} className={`col-span-2 text-right hover:text-white transition-colors ${sortKey === 'intensity' ? 'text-brand-primary' : ''}`}>
                        Intens
                    </button>
                    <button onClick={() => handleSort('errors')} className={`col-span-1 text-right hover:text-white transition-colors ${sortKey === 'errors' ? 'text-brand-primary' : ''}`}>
                        Err
                    </button>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos. Try widening filters.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div 
                                key={r.id} 
                                onClick={() => onSelect(r)} 
                                className={`grid grid-cols-12 gap-1 p-2 rounded cursor-pointer border-b border-gray-800 items-center transition-all ${selectedId === r.id ? 'bg-gray-800 ring-1 ring-brand-primary/50' : 'hover:bg-gray-800/50'}`}
                            >
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input 
                                        type="checkbox" 
                                        checked={checkedIds.has(r.id)} 
                                        onChange={() => onToggleCheck(r.id)} 
                                        className="rounded bg-gray-700 border-gray-600 text-brand-primary w-3 h-3" 
                                    />
                                </div>
                                <span className={`col-span-2 font-bold text-[10px] truncate ${r.intervalLabel.includes('Inv') ? 'text-blue-400' : 'text-brand-primary'}`}>
                                    {r.intervalLabel}
                                </span>
                                <span className="col-span-1 text-gray-300 text-[10px]">{r.delayBeats}B</span>
                                <span className="col-span-1 text-gray-500 text-[10px] font-mono">{entryNote}</span>

                                {/* Prominent Dissonance Metric */}
                                <span className={`col-span-2 text-xs font-mono font-bold text-center ${getMetricColor(r.dissonanceRatio)}`}>
                                    {Math.round(r.dissonanceRatio * 100)}%
                                </span>

                                {/* Prominent NCT Metric */}
                                <span className={`col-span-2 text-xs font-mono font-bold text-center ${getMetricColor(r.nctRatio || 0)}`}>
                                    {Math.round((r.nctRatio || 0) * 100)}%
                                </span>

                                <span className="col-span-2 text-[10px] text-gray-400 font-mono text-right">
                                    {r.pairDissonanceScore.toFixed(1)}
                                </span>
                                <span className="col-span-1 text-[9px] text-gray-500 text-right">
                                    {r.errors.length > 0 ? (
                                        <span className="bg-red-900/30 text-red-400 px-1 rounded border border-red-900/50">{r.errors.length}</span>
                                    ) : '-'}
                                </span>
                            </div>
                        );
                    })
                )}
            </div>

            <div className="p-2 border-t border-gray-800 bg-gray-800/50 flex justify-between items-center px-4">
                <div className="flex items-center gap-3">
                    <span className="text-[10px] text-gray-500 italic">{sortedResults.length} Visible</span>
                    <span className="text-[10px] text-gray-700">|</span>
                    <span className="text-[10px] text-gray-500">{checkedIds.size} Selected</span>
                </div>
                <button 
                    onClick={() => { 
                        setSelectedIntervals(new Set()); 
                        setSelectedDelays(new Set()); 
                        setSelectedPitches(new Set()); 
                        setMaxDissonance(100); 
                        setOnlyResolved(false);
                        setGradeFilter({STRONG: true, VIABLE: true, INVALID: true}) 
                    }}
                    className="text-[9px] text-brand-primary hover:text-white uppercase font-bold tracking-wider"
                >
                    Reset Power Filter
                </button>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { StrettoChainResult, StrettoChainOption, ScoreLog } from '../../types';
import { getIntervalLabel } from '../services/midiSpelling';
import { getVoiceLabel } from '../services/midiVoices';

interface StrettoResultsListProps {
    results: StrettoChainResult[];
    selectedId: string | null;
    onSelect: (res: StrettoChainResult) => void;
    voiceNames?: Record<number, string>;
}

export default function StrettoResultsList({ results, selectedId, onSelect, voiceNames }: StrettoResultsListProps) {
    const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
    const [scoreTooltipId, setScoreTooltipId] = useState<string | null>(null);

    if (results.length === 0) {
        return <div className="text-center text-gray-500 py-10">No chains found yet. Run the search to begin.</div>;
    }

    const toggleExpand = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setExpandedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const formatInterval = (semis: number) => {
        return getIntervalLabel(semis);
    };

    const getVoiceCode = (idx: number, total: number) => {
        if (voiceNames && voiceNames[idx]) return voiceNames[idx];

        const label = getVoiceLabel(idx, total);
        if (label.includes(' ')) {
            const parts = label.split(' ');
            return `${parts[0].charAt(0)}${parts[1]}`;
        }
        return label.charAt(0);
    };

    const renderScoreTooltip = (log?: ScoreLog) => {
        if (!log) return null;
        return (
            <div className="absolute right-0 top-full mt-2 z-50 w-64 bg-black border border-gray-600 rounded p-3 shadow-xl text-xs text-gray-300">
                <div className="font-bold text-gray-200 border-b border-gray-600 pb-1 mb-2">Score Breakdown ({log.total.toFixed(0)})</div>
                <div className="flex justify-between mb-1"><span>Base</span><span>{log.base}</span></div>
                {log.bonuses.map((b, i) => (
                    <div key={`b-${i}`} className="flex justify-between text-green-400"><span>+ {b.reason}</span><span>{b.points}</span></div>
                ))}
                {log.penalties.map((p, i) => (
                    <div key={`p-${i}`} className="flex justify-between text-red-400"><span>- {p.reason}</span><span>{p.points}</span></div>
                ))}
            </div>
        );
    };

    const renderMetricBadge = (label: string, value: number, tooltip: string) => {
        let color = 'text-green-400 border-green-900/50 bg-green-900/20';
        if (value > 0.4) color = 'text-red-400 border-red-900/50 bg-red-900/20';
        else if (value > 0.2) color = 'text-yellow-400 border-yellow-900/50 bg-yellow-900/20';

        return (
            <div className={`flex items-center gap-1 px-1.5 py-0.5 rounded border ${color}`} title={tooltip}>
                <span className="text-[9px] uppercase font-bold opacity-70">{label}</span>
                <span className="text-[10px] font-mono font-bold">{Math.round(value * 100)}%</span>
            </div>
        );
    };

    const renderChainBadges = (entries: StrettoChainOption[], isSub: boolean = false) => {
        const maxV = Math.max(...entries.map(e => e.voiceIndex)) + 1;
        const totalEstimate = Math.max(4, maxV); 

        return entries.map((e, idx) => {
            const vCode = getVoiceCode(e.voiceIndex, totalEstimate);

            if (idx === 0) {
                return (
                    <div key={idx} className={`flex flex-col items-center bg-gray-800 p-1 rounded border border-gray-700 ${isSub ? 'min-w-[40px] scale-90 origin-left' : 'min-w-[50px]'}`}>
                        <span className="text-[10px] font-bold text-brand-primary truncate max-w-[50px]" title={vCode}>{vCode}</span>
                        <span className="text-xs text-white font-mono">Subj</span>
                    </div>
                );
            }

            const absInt = e.transposition; 
            const prev = entries[idx-1];
            const relDist = e.startBeat - prev.startBeat;
            const absDist = e.startBeat;

            let typeLabel = e.type === 'I' ? 'INV' : 'NOR';
            let lenLabel = e.length < entries[0].length ? 'TRC' : 'FUL';

            const borderClass = (e.type === 'I' || lenLabel === 'TRC') ? 'border-brand-primary' : 'border-gray-600';

            return (
                <div key={idx} className={`flex flex-col bg-gray-800 p-1 rounded border ${borderClass} ${isSub ? 'min-w-[50px] scale-90 origin-left' : 'min-w-[60px]'}`}>
                    <div className="flex justify-between border-b border-gray-700 pb-0.5 mb-0.5">
                        <span className="text-[9px] font-bold text-gray-300 truncate max-w-[40px]" title={vCode}>{vCode}</span>
                        <span className={`text-[8px] font-bold ${lenLabel === 'TRC' ? 'text-orange-300' : 'text-gray-500'}`}>{lenLabel}</span>
                    </div>

                    <div className="flex flex-col items-center mb-0.5">
                        <span className="text-[10px] text-brand-primary font-bold">{formatInterval(absInt)}</span>
                        {e.type === 'I' && <span className="text-[8px] text-blue-300">INVERT</span>}
                    </div>

                    <div className="flex gap-1 text-[9px] font-mono" title={`Delay: +${relDist} / Start: @${absDist}`}>
                        <span className="text-gray-400 w-1/2 text-center border-r border-gray-700">+{relDist.toFixed(1)}</span>
                        <span className="text-white w-1/2 text-center">@{absDist.toFixed(1)}</span>
                    </div>
                </div>
            );
        });
    };

    return (
        <div className="overflow-y-auto max-h-[500px] pb-20">
            {results.map((res, i) => {
                const hasVariations = res.variations && res.variations.length > 0;
                const isExpanded = expandedIds.has(res.id);
                const isSelected = selectedId === res.id;
                const showTooltip = scoreTooltipId === res.id;

                return (
                    <div key={res.id} className="border-b border-gray-700 bg-gray-900/50 relative">
                        {/* Leader Row */}
                        <div 
                            onClick={() => onSelect(res)}
                            className={`p-2 cursor-pointer hover:bg-gray-800 transition-colors flex flex-col gap-2 ${isSelected ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                        >
                            <div className="flex justify-between items-center">
                                <div className="flex items-center gap-2">
                                    {hasVariations && (
                                        <button 
                                            onClick={(e) => toggleExpand(e, res.id)}
                                            className="text-gray-400 hover:text-white text-xs bg-gray-700 px-1.5 rounded"
                                        >
                                            {isExpanded ? '▼' : '▶'}
                                        </button>
                                    )}
                                    <span className="font-bold text-gray-300 text-xs">Chain #{i + 1}</span>
                                    {hasVariations && (
                                        <span className="text-[10px] bg-brand-primary/20 text-brand-primary px-1.5 rounded">
                                            +{res.variations?.length} Vars
                                        </span>
                                    )}
                                </div>
                                <div className="flex items-center gap-2">
                                    {renderMetricBadge("Diss", res.dissonanceRatio || 0, "Dissonance Ratio")}
                                    {renderMetricBadge("NCT", res.nctRatio || 0, "Non-Chord Tone Ratio")}

                                    <div className="relative">
                                        <button 
                                            onMouseEnter={() => setScoreTooltipId(res.id)}
                                            onMouseLeave={() => setScoreTooltipId(null)}
                                            className="text-[9px] bg-black/30 px-1.5 rounded text-gray-500 hover:text-white cursor-help"
                                        >
                                            Score: {res.score.toFixed(0)}
                                        </button>
                                        {showTooltip && renderScoreTooltip(res.scoreLog)}
                                    </div>
                                </div>
                            </div>

                            {/* Detected Chords Summary */}
                            {res.detectedChords && res.detectedChords.length > 0 && (
                                <div className="flex gap-1 overflow-hidden">
                                    {res.detectedChords.map((c, idx) => (
                                        <span key={idx} className="text-[9px] text-gray-400 bg-black/20 px-1 rounded whitespace-nowrap">{c}</span>
                                    ))}
                                </div>
                            )}

                            <div className="flex flex-wrap gap-2">
                                {renderChainBadges(res.entries)}
                            </div>
                        </div>

                        {/* Variations Sub-list */}
                        {hasVariations && isExpanded && (
                            <div className="bg-black/30 border-t border-gray-800 pl-4 py-1">
                                {res.variations!.map((v, vIdx) => {
                                    const isVarSelected = selectedId === v.id;
                                    return (
                                        <div 
                                            key={v.id} 
                                            onClick={() => onSelect(v)}
                                            className={`p-2 border-l border-gray-700 hover:bg-gray-800/50 cursor-pointer transition-colors ${isVarSelected ? 'bg-gray-800/80 border-l-2 border-l-brand-secondary' : ''}`}
                                        >
                                            <div className="flex justify-between items-center mb-1">
                                                <div className="flex items-center gap-2">
                                                    <span className="text-[10px] font-bold text-gray-500">Variation {vIdx + 1}</span>
                                                    {renderMetricBadge("Diss", v.dissonanceRatio || 0, "Diss Ratio")}
                                                    {renderMetricBadge("NCT", v.nctRatio || 0, "NCT Ratio")}
                                                </div>
                                                <span className="text-[9px] text-gray-600">Score: {v.score.toFixed(0)}</span>
                                            </div>
                                            <div className="flex flex-wrap gap-1 opacity-90">
                                                {renderChainBadges(v.entries, true)}
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import React, { useMemo } from 'react';
import { StrettoCandidate, PianoRollTrackData, HarmonicRegion, RawNote } from '../../types';
import { PlayIcon, StopIcon, DocumentTextIcon, DownloadIcon } from '../Icons';
import PianoRoll from '../PianoRoll';
import { playSpecificNotes } from '../midiPlaybackService';
import { getFormattedTime } from '../services/midiHarmony';

interface StrettoInspectorProps {
    candidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    assemblyResult: string;
    assemblyLog: string[];
    onClearAssembly: () => void;
    onDownloadChain: () => void;
}

export default function StrettoInspector({ 
    candidate, ppq, ts, isPlaying, onPlay, 
    assemblyResult, assemblyLog, onClearAssembly, onDownloadChain 
}: StrettoInspectorProps) {

    const pianoRollData: PianoRollTrackData | null = useMemo(() => {
        if (!candidate) return null;
        return {
            name: `Stretto ${candidate.intervalLabel}`,
            ppq,
            timeSignature: { numerator: ts.num, denominator: ts.den },
            notes: candidate.notes.map(n => ({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: n.velocity,
                name: n.name,
                voiceIndex: n.voiceIndex ?? 0, 
                isOrnament: false
            })),
            harmonicRegions: candidate.regions 
        };
    }, [candidate, ppq, ts]);

    const handleRegionClick = (region: HarmonicRegion) => {
        if (!candidate) return;
        const activeNotes = candidate.notes.filter(n => 
            n.ticks < region.endTick && (n.ticks + n.durationTicks) > region.startTick
        );
        if (activeNotes.length > 0) {
            const notesToPlay = activeNotes.map(n => ({
                midi: n.midi, 
                duration: n.durationTicks * (0.5 / ppq), 
                velocity: n.velocity
            }));
            playSpecificNotes(notesToPlay);
        }
    };

    const handleExportAnalysis = () => {
        if (!candidate) return;
        let text = `STRETTO ANALYSIS REPORT\nCandidate ID: ${candidate.id}\nInterval: ${candidate.intervalLabel}\nDelay: ${candidate.delayBeats} Beats\n`;
        text += `\nMETRICS\n`;
        text += `Dissonant Time: ${Math.round(candidate.dissonanceRatio * 100)}%\n`;
        text += `NCT Ratio: ${Math.round((candidate.nctRatio || 0) * 100)}%\n`;
        text += `Grade: ${candidate.grade}\n`;
        text += `Errors: ${candidate.errors.length}\n`;

        text += `\nHARMONIC SEGMENTS\n`;
        text += `Time | Chord/Interval | Notes | NCTs\n`;
        text += `---|---|---|---\n`;

        candidate.regions?.forEach(r => {
            const time = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
            const notes = r.detailedInfo?.allNotes.join(', ') || '';
            const ncts = r.detailedInfo?.ncts.join(', ') || '-';
            text += `${time} | ${r.detailedInfo?.chordName || ''} | ${notes} | ${ncts}\n`;
        });

        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Analysis_${candidate.id}.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
    };

    const getStatusColor = (type: HarmonicRegion['type']) => {
        switch(type) {
            case 'consonant_stable': return 'text-green-400';
            case 'dissonant_primary': return 'text-purple-400';
            case 'dissonant_secondary': return 'text-amber-400';
            case 'dissonant_tertiary': return 'text-orange-500';
            case 'dissonant_severe': return 'text-red-500';
            default: return 'text-gray-400';
        }
    };

    const getRoleColor = (role: string) => {
        switch(role) {
            case 'Root': return 'text-blue-400';
            case '3rd': return 'text-lime-400';
            case '5th': return 'text-teal-400';
            case 'Ext': return 'text-purple-400';
            case 'NCT': return 'text-orange-400';
            default: return 'text-gray-300';
        }
    };

    const renderVital = (label: string, value: string, color: string) => (
        <div className="flex flex-col items-center bg-black/20 px-3 py-1 rounded">
            <span className="text-[9px] text-gray-400 uppercase tracking-wider">{label}</span>
            <span className={`text-sm font-mono font-bold ${color}`}>{value}</span>
        </div>
    );

    const getMetricColor = (val: number) => {
        if (val > 0.4) return 'text-red-400';
        if (val > 0.2) return 'text-yellow-400';
        return 'text-green-400';
    };

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 flex flex-col h-[700px] shadow-lg relative overflow-hidden">
            {/* Gemini Assembly Overlay */}
            {assemblyResult && (
                <div className="absolute inset-0 bg-gray-800 z-30 p-4 flex flex-col animate-fade-in">
                    <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                        <h3 className="font-bold text-brand-primary">Gemini Stretto Chain</h3>
                        <button onClick={onClearAssembly} className="text-gray-500 hover:text-white">✕ Close</button>
                    </div>
                    <div className="flex-grow flex flex-col gap-4 overflow-hidden">
                        <div className="flex-1 bg-black rounded p-3 font-mono text-xs text-gray-300 overflow-auto border border-gray-700 whitespace-pre-wrap">
                            {assemblyResult}
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                            <button onClick={onDownloadChain} className="w-full py-2 bg-brand-secondary text-white font-bold rounded flex items-center justify-center gap-2 hover:bg-brand-primary transition-colors">
                                <DownloadIcon className="w-4 h-4"/> Download Chain MIDI
                            </button>
                            <button onClick={() => { navigator.clipboard.writeText(assemblyResult); alert("ABC Chain copied to clipboard!"); }} className="w-full py-2 bg-gray-700 text-white font-bold rounded hover:bg-gray-600 transition-colors">
                                Copy ABC Text
                            </button>
                        </div>
                        <div className="h-24 bg-gray-900 rounded p-2 border border-gray-700 overflow-auto text-[10px]">
                            <h4 className="font-bold text-gray-500 uppercase mb-1">Verification History</h4>
                            {assemblyLog.map((log, i) => (
                                <div key={i} className="border-l border-gray-700 pl-2 mb-1 text-gray-400">{log}</div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {candidate && pianoRollData ? (
                <>
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <h3 className="text-xl font-bold text-white">
                                Stretto: {candidate.intervalLabel} @ {candidate.delayBeats}B
                            </h3>

                            {/* HARMONIC VITALS BAR */}
                            <div className="flex items-center gap-2 mt-2">
                                {renderVital("Dissonance", `${Math.round(candidate.dissonanceRatio * 100)}%`, getMetricColor(candidate.dissonanceRatio))}
                                {renderVital("NCT Ratio", `${Math.round((candidate.nctRatio || 0) * 100)}%`, getMetricColor(candidate.nctRatio || 0))}
                                {renderVital("Intensity", candidate.pairDissonanceScore.toFixed(1), "text-brand-primary")}
                                <span className={`ml-2 text-xs font-bold border px-2 py-1 rounded ${candidate.grade === 'STRONG' ? 'text-green-400 border-green-500/50' : candidate.grade === 'VIABLE' ? 'text-yellow-400 border-yellow-500/50' : 'text-red-400 border-red-500/50'}`}>
                                    {candidate.grade}
                                </span>
                            </div>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={handleExportAnalysis} className="p-2 bg-gray-700 rounded-full hover:bg-gray-600 transition-colors text-white" title="Export Analysis Report">
                                <DocumentTextIcon className="w-5 h-5"/>
                            </button>
                            <button onClick={() => onPlay(candidate.notes)} className="bg-brand-primary p-2 rounded-full hover:bg-brand-secondary transition-transform active:scale-95 shadow-md">
                                {isPlaying ? <StopIcon className="w-5 h-5 text-white"/> : <PlayIcon className="w-5 h-5 text-white"/>}
                            </button>
                        </div>
                    </div>

                    <div className="h-64 flex-shrink-0 bg-gray-900 rounded border border-gray-700 mb-2 overflow-hidden shadow-inner relative">
                        <PianoRoll trackData={pianoRollData} onRegionClick={handleRegionClick} />
                    </div>

                    {/* Detailed Analysis Table */}
                    <div className="flex-grow bg-gray-900/50 rounded p-2 border border-gray-700 flex flex-col overflow-hidden relative">
                        <div className="flex justify-between items-center mb-2 px-1">
                            <h4 className="text-xs font-bold text-gray-400 uppercase">Harmonic Breakdown</h4>
                            <span className="text-[10px] text-gray-500">Tap row to audition</span>
                        </div>

                        <div className="flex-grow overflow-auto rounded border border-gray-800 pb-8">
                            <table className="w-full text-left text-[10px] text-gray-300">
                                <thead className="bg-gray-800 text-gray-500 uppercase sticky top-0 z-10">
                                    <tr>
                                        <th className="px-2 py-1.5 w-16">Time</th>
                                        <th className="px-2 py-1.5 w-24">Chord / Int</th>
                                        <th className="px-2 py-1.5">Active Notes</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-800">
                                    {candidate.regions?.map((r, i) => (
                                        <tr 
                                            key={i} 
                                            onClick={() => handleRegionClick(r)}
                                            className="hover:bg-gray-700/50 cursor-pointer transition-colors"
                                        >
                                            <td className="px-2 py-1.5 font-mono text-gray-500">
                                                {getFormattedTime(r.startTick, ppq, ts.num, ts.den)}
                                            </td>
                                            <td className={`px-2 py-1.5 font-bold ${getStatusColor(r.type)}`}>
                                                {r.detailedInfo?.chordName}
                                            </td>
                                            <td className="px-2 py-1.5 flex flex-wrap gap-1">
                                                {r.detailedInfo?.noteDetails.map((n, idx) => (
                                                    <span key={idx} className={`${getRoleColor(n.role)} font-bold`}>
                                                        {n.name}
                                                    </span>
                                                ))}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>

                        {/* LEGEND */}
                        <div className="absolute bottom-0 left-0 right-0 bg-gray-900 border-t border-gray-700 p-2 flex justify-between text-[9px] font-bold">
                            <span className="text-blue-400">Root</span>
                            <span className="text-lime-400">3rd</span>
                            <span className="text-teal-400">5th</span>
                            <span className="text-purple-400">6th/7th/Dim5</span>
                            <span className="text-orange-400">NCT</span>
                        </div>
                    </div>
                </>
            ) : (
                <div className="flex flex-col items-center justify-center h-full text-gray-500">
