import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, StrettoSearchReport } from '../../types';
import { INTERVALS, SCALE_INTERVALS } from './strettoConstants';
import { calculateStrettoScore, SubjectVariant } from './strettoScoring';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

// --- Precomputation: Scales & Inversion ---

function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; 
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

function strictTonalInversion(notes: InternalNote[], pivot: number, root: number, mode: string): InternalNote[] {
    const intervals = SCALE_INTERVALS[mode] || SCALE_INTERVALS['Major'];
    const pivotInfo = getScaleDegree(pivot, root, intervals);
    if (!pivotInfo) return notes; 

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    return notes.map(n => {
        const info = getScaleDegree(n.pitch, root, intervals);
        if (!info) return n;

        const currentGlobalIndex = info.octave * 7 + info.degree;
        const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

        const invOct = Math.floor(invertedGlobalIndex / 7);
        const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

        const newPitch = getPitchFromDegree(invOct, invDeg, root, intervals);
        return { ...n, pitch: newPitch };
    });
}

function normalizeSubject(notes: RawNote[], ppq: number): { notes: InternalNote[], offset8: number } {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return { notes: [], offset8: 0 };

    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); 
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    // Calculate metric offset: How far is the first note from the nearest Measure start (0)?
    // Actually, we just need the absolute grid position modulo measure to determine 'Strong' beats.
    // So we need the absolute 8th note index of the start.
    const offset8 = Math.round(startTick / ticksPer8);

    const internalNotes = monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));

    return { notes: internalNotes, offset8 };
}

// --- Rule Definitions (Pruning) ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
// STRICT RULE: Include 5 (P4) in Perfect Intervals to prevent parallel 4ths
const PERFECT_INTERVALS = new Set([0, 7, 5]);

/**
 * PHASE 1 CHECK: Structural Validity (Pairwise)
 * Relaxed: Does NOT check "Ends on Dissonance" (C6) as that is position-dependent.
 * Checks: Parallel Perfects (including P4), Run Length <= 2.
 * NOW INCLUDES: Strict Dissonance Ratio Filter
 */
function checkCounterpointStructure(
    variantA: SubjectVariant, 
    variantB: SubjectVariant, 
    delay8: number, 
    transposition: number,
    maxDissonanceRatio: number
): { compatible: boolean } {
    const notesA = variantA.notes;
    const notesB = variantB.notes;
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) timeline.get(tick)!.pB = n.pitch + transposition;
        }
    });

    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    let dissRunLength = 0; 
    let lastIsDiss = false;

    let overlapTicks = 0;
    let dissonantTicks = 0;

    for (let i = 0; i < ticks.length; i++) {
        const t = ticks[i];
        const state = timeline.get(t)!;

        if (state.pA === undefined || state.pB === undefined) {
            // Monophonic moment - reset trackers
            prevP1 = null; prevP2 = null;
            dissRunLength = 0;
            lastIsDiss = false;
            // Note: Rule C6 (Resolution into silence) ignored here to allow chaining
            continue;
        }

        overlapTicks++; // Count every concurrent 8th note tick

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects (Now includes P4 via PERFECT_INTERVALS)
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = p1 !== prevP1;
            const p2Moved = p2 !== prevP2;

            if (p1Moved && p2Moved) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) return { compatible: false };
                }
            }
        }

        // Rule 6: Dissonance (Structural)
        let isDiss = DISSONANT_INTERVALS.has(interval);
        if (interval === 5) isDiss = true; // P4 against bass always diss in 2-part

        if (isDiss) {
            dissonantTicks++;

            if (!lastIsDiss) dissRunLength = 1;
            else dissRunLength++;

            // Rule C2: Event Limit (r <= 2)
            if (dissRunLength > 2) return { compatible: false };

            lastIsDiss = true;
        } else {
            dissRunLength = 0;
            lastIsDiss = false;
        }

        prevP1 = p1; prevP2 = p2;
    }

    // Strict Dissonance Ratio Filter
    if (overlapTicks > 0) {
        const ratio = dissonantTicks / overlapTicks;
        if (ratio > maxDissonanceRatio) return { compatible: false };
    }

    return { compatible: true };
}

// Helper: Determine beat strength
function isStrong8th(tick8: number, tsNum: number, tsDenom: number): boolean {
    // Convert 8th tick to measure position
    // For 4/4: 8 eighths per bar. Strong are 0 (Beat 1) and 4 (Beat 3).
    // For 3/4: 6 eighths. Strong are 0 (Beat 1).
    const eighthsPerBar = (tsNum * 8) / tsDenom;
    const pos = tick8 % eighthsPerBar;

    if (pos === 0) return true; // Downbeat always strong

    if (tsNum === 4 && tsDenom === 4) {
        if (pos === 4) return true; // Beat 3 in 4/4
    }

    return false;
}

/**
 * PHASE 5 CHECK: Metric Compliance
 * Checks Rule 6 C4 (Metric Constraints) using absolute timestamps.
 * 
 * FIX: Added `metricOffset` parameter. This accounts for the Subject starting 
 * on a pickup beat (e.g. Beat 4), ensuring that `t + metricOffset` correctly 
 * aligns with the bar lines (Mod 8).
 */
function checkMetricCompliance(
    newVariant: SubjectVariant, 
    newEntry: StrettoChainOption,
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[],
    tsNum: number = 4,
    tsDenom: number = 4,
    metricOffset: number = 0
): boolean {

    const newStart8 = Math.round(newEntry.startBeat * 2);

    // Check against every existing voice
    for (let k = 0; k < chain.length; k++) {
        const existEntry = chain[k];
        const existVariant = variants[variantIndices[k]];
        const existStart8 = Math.round(existEntry.startBeat * 2);

        // Determine overlapping region
        const overlapStart = Math.max(newStart8, existStart8);
        const overlapEnd = Math.min(newStart8 + newVariant.length8, existStart8 + existVariant.length8);

        if (overlapEnd <= overlapStart) continue;

        let dissRunLength = 0;
        let lastIsDiss = false;

        // Iterate overlap ticks
        for (let t = overlapStart; t < overlapEnd; t++) {
            const tRelNew = t - newStart8;
            const tRelExist = t - existStart8;

            const noteNew = newVariant.notes.find(n => n.relTick8 <= tRelNew && (n.relTick8 + n.dur8) > tRelNew);
            const noteExist = existVariant.notes.find(n => n.relTick8 <= tRelExist && (n.relTick8 + n.dur8) > tRelExist);

            if (!noteNew || !noteExist) {
                dissRunLength = 0; lastIsDiss = false; continue;
            }

            const p1 = noteNew.pitch + newEntry.transposition;
            const p2 = noteExist.pitch + existEntry.transposition;
            const lo = Math.min(p1, p2);
            const hi = Math.max(p1, p2);
            const interval = (hi - lo) % 12;

            let isDiss = DISSONANT_INTERVALS.has(interval);
            if (interval === 5) isDiss = true;

            // Corrected Metric Check using Absolute Grid alignment
            const isStrong = isStrong8th(t + metricOffset, tsNum, tsDenom);

            if (isDiss) {
                if (!lastIsDiss) dissRunLength = 1; else dissRunLength++;

                // Rule C4B: If Strong beat, resolution must be immediate (Length 1 max)
                // This means a dissonance cannot *continue* from a strong beat, nor *start* and extend
                if (isStrong && dissRunLength > 1) return false; 

                // Rule C4A: If r=2, BOTH must be weak.
                if (dissRunLength === 2) {
                    const prevIsStrong = isStrong8th((t - 1) + metricOffset, tsNum, tsDenom);
                    if (isStrong || prevIsStrong) return false; 
                }

                // Redundant safety: Cap dissonance at 2 ticks (1 beat) strictly
                if (dissRunLength > 2) return false;

                lastIsDiss = true;
            } else {
                dissRunLength = 0;
                lastIsDiss = false;
            }
        }
    }
    return true;
}

// --- Generator ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    const { notes: baseNotes, offset8 } = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    const variants: SubjectVariant[] = [];
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });
    if (options.inversionMode !== 'None') {
        const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            if (options.inversionMode !== 'None') {
                const invNotes = strictTonalInversion(baseNotes, options.pivotMidi, options.scaleRoot, options.scaleMode);
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Phase 1: STRUCTURAL PAIRWISE PRECOMPUTATION
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    // Only check structural rules here (invariance), Metric rules checked later
                    // Passing maxPairwiseDissonance here ensures we prune unpleasantly dissonant pairs early
                    const res = checkCounterpointStructure(vA, vB, d, t, options.maxPairwiseDissonance);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    const results: StrettoChainResult[] = [];

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], 
        voiceEndTimes8: number[], 
        nInv: number, 
        nTrunc: number,
        nRestricted: number,
        nFree: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS * 3) return; // Allow more raw results for grouping later
        if (nodesVisited > MAX_SEARCH_NODES) return;

        if (chain.length === options.targetChainLength) {
            const final = calculateStrettoScore(chain, variants, variantIndices, options);
            if (final.isValid) results.push(final);
            return;
        }

        const depth = chain.length; 
        const prevEntry = chain[depth - 1];

        // --- RULE 1 & 2: DELAY LOGIC (STRICT) ---
        const possibleDelays8: number[] = [];
        let minD = 1; 
        let maxD = Math.floor(subjectLength8 * (2/3)); 

        if (depth > 0) {
            if (depth + 1 > 3) maxD = Math.min(maxD, Math.floor(subjectLength8 * 0.5) - 1);
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                maxD = Math.min(maxD, prevDelay8 + 2);
                if (depth >= 3) {
                    const prevPrevDelay8 = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                    // Expansion Reaction Logic: If expanded, force contraction
                    // The knot must contract. If current delay (prevDelay8) > previous (prevPrevDelay8),
                    // the NEXT delay must be smaller than prevPrevDelay8 (the starting point of expansion).
                    if (prevDelay8 > prevPrevDelay8) maxD = Math.min(maxD, prevPrevDelay8 - 1);
                }
                if (prevDelay8 > (subjectLength8 / 2)) maxD = Math.min(maxD, prevDelay8 - 1);
            }
        }

        for (let d = minD; d <= maxD; d++) possibleDelays8.push(d);
        possibleDelays8.sort((a,b) => a - b); 

        for (const delay8 of possibleDelays8) {
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                // STRICT NO REPETITION RULE:
                // An entry is NEVER allowed to be at the exact same distance as the previous entry.
                if (delay8 === prevDelay8) continue;
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            for (const t of transpositions) {
                for (let v = 0; v < options.ensembleTotal; v++) {

                    // --- RULE 7: RE-ENTRY ---
                    if (absStart8 < voiceEndTimes8[v] - 2) continue; 

                    // --- RULE 4: STRATIFICATION (STRICT - Transposition Based) ---
                    // "Voice Crossing" is allowed in terms of Pitch, but the structural Layers must be ordered.
                    // High Index = Lower Voice. Low Index = Higher Voice.
                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];

                        // Rule 4A: Neighbor Check
                        if (Math.abs(e.voiceIndex - v) === 1) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);

                            // The shift (transposition) of the Higher Voice must be >= Lower Voice
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            if (highVoiceTrans < lowVoiceTrans) stratFail = true;
                        }

                        // Rule 4B: Bass Clearance
                        const bassIdx = options.ensembleTotal - 1;
                        const altoIdx = bassIdx - 2; 

                        if (bassIdx >= 2) {
                            const isNewBass = (v === bassIdx);
                            const isNewAlto = (v === altoIdx);
                            const isExistingBass = (e.voiceIndex === bassIdx);
                            const isExistingAlto = (e.voiceIndex === altoIdx);

                            if ((isNewBass && isExistingAlto) || (isNewAlto && isExistingBass)) {
                                const bassTrans = isNewBass ? t : e.transposition;
                                const altoTrans = isNewAlto ? t : e.transposition;

                                // Alto Shift must be >= Bass Shift + 12 (Octave)
                                if (altoTrans < bassTrans + 12) stratFail = true;
                            }
                        }

                        // Rule 4B General Separation (v vs v+2)
                        if (Math.abs(e.voiceIndex - v) === 2) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;

                            // Higher Voice Shift >= Lower Voice Shift + 7
                            if (highVoiceTrans < lowVoiceTrans + 7) stratFail = true;
                        }
                    }
                    if (stratFail) continue;

                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        // Quota Checks
                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;
                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;

                        const intervalClass = Math.abs(t % 12);
                        const isRestricted = [3, 4, 8, 9].includes(intervalClass);
                        const isFree = [0, 7].includes(intervalClass) || intervalClass === 5; 
                        const nextRestricted = nRestricted + (isRestricted ? 1 : 0);
                        const nextFree = nFree + (isFree ? 1 : 0);

                        if (nextRestricted > 1 && nextRestricted >= nextFree) continue;
                        if (options.thirdSixthMode === 'None' && isRestricted) continue;
                        if (options.thirdSixthMode === 'Max 1' && nextRestricted > 1) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && isRestricted) continue;

                        // Phase 1 Check: Structural Compatibility
                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;
                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        // Phase 5 Check: Metric Compliance (Absolute Time with Offset)
                        const tempNextEntry: StrettoChainOption = {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * 2,
                            voiceIndex: v
                        };

                        if (!checkMetricCompliance(variant, tempNextEntry, chain, variants, variantIndices, 4, 4, offset8)) {
                            continue;
                        }

                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, tempNextEntry];

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            nextRestricted,
                            nextFree
                        );
                    }
                }
            }
        }
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = variants[0].length8;

    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: options.subjectVoiceIndex }],
        [0],
        initialVoiceState,
        0, 0, 0, 1
    );

    // Grouping Logic: Group by [Rhythm Structure] + [Voice Map]
    const groupedMap = new Map<string, StrettoChainResult[]>();

    results.forEach(res => {
        // Key: Delays + Voices (ignoring intervals)
        // Format: "D:0,2,4|V:0,1,2"
        const delays = res.entries.map(e => e.startBeat).join(',');
        const voices = res.entries.map(e => e.voiceIndex).join(',');
        const key = `D:${delays}|V:${voices}`;

        if (!groupedMap.has(key)) groupedMap.set(key, []);
        groupedMap.get(key)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groupedMap.forEach((group) => {
        // Sort group by score
        group.sort((a,b) => b.score - a.score);
        const leader = group[0];

        // Attach variations if multiple exist
        if (group.length > 1) {
            leader.variations = group.slice(1);
        }
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort((a,b) => b.score - a.score).slice(0, MAX_RESULTS),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: results.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

import { StrettoChainOption, StrettoSearchOptions, StrettoChainResult, ScoreLog } from '../../types';
import { INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';

// --- Weights & Constants ---
const W_S1 = 0.2; // Unweighted Dissonance
const W_S2 = 0.3; // Weighted Dissonance
const W_S3 = 0.2; // NCT Ratio
const W_S4 = 0.3; // Unprepared Dissonance

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);

// Chord Templates (Pitch Class Sets) for Metric S3
const CHORD_TEMPLATES: number[][] = [
    [0, 4, 7],     // Major
    [0, 3, 7],     // Minor
    [0, 3, 6],     // Dim
    [0, 4, 8],     // Aug
    [0, 4, 7, 11], // Maj7
    [0, 3, 7, 10], // m7
    [0, 4, 7, 10], // Dom7
    [0, 3, 7, 11], // mM7
    [0, 3, 6, 9],  // dim7
    [0, 3, 6, 10], // m7b5
    [0, 4, 10],    // It+6
    [0, 4, 6, 10], // Fr+6
];

// Helper Interfaces for Internal Calculation
interface InternalNote {
    relTick8: number;
    dur8: number;
    pitch: number;
}

export interface SubjectVariant {
    type: 'N' | 'I';
    truncationBeats: number;
    notes: InternalNote[];
    length8: number;
}

function countNCTs(pitches: number[]): number {
    if (pitches.length === 0) return 0;
    const pcs = Array.from(new Set(pitches.map(p => p % 12)));
    const Q_len = pcs.length;

    let maxOverlap = 0;

    for (const template of CHORD_TEMPLATES) {
        for (let i = 0; i < 12; i++) {
            const shiftedTemplate = template.map(x => (x + i) % 12);
            let overlap = 0;
            for (const pc of pcs) {
                if (shiftedTemplate.includes(pc)) overlap++;
            }
            if (overlap > maxOverlap) maxOverlap = overlap;
        }
    }

    return Q_len - maxOverlap;
}

/**
 * Calculates the S1-S4 metrics for a generated chain.
 */
export function calculateStrettoScore(
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[], 
    options: StrettoSearchOptions
): StrettoChainResult {

    // 1. Build Timeline
    // Map tick -> active voices
    const timeline = new Map<number, {pitch: number, voice: number, dur8: number}[]>();
    let maxT = 0;

    chain.forEach((e, i) => {
        const variant = variants[variantIndices[i]];
        const start8 = Math.round(e.startBeat * 2);

        variant.notes.forEach(n => {
            for (let t=0; t<n.dur8; t++) {
                const tick = start8 + n.relTick8 + t;
                if (!timeline.has(tick)) timeline.set(tick, []);
                timeline.get(tick)!.push({ 
                    pitch: n.pitch + e.transposition, 
                    voice: e.voiceIndex,
                    dur8: n.dur8
                });
                if (tick > maxT) maxT = tick;
            }
        });
    });

    // --- 1B. Run Harmony Analysis for UI ---
    // Convert the 8th-note timeline to the 16th-note format required by analyzeStrettoHarmony
    const harmonyTimeline: Record<number, Record<number, { pitch: number, dur16: number }>> = {};
    const harmonyTicks: number[] = [];

    timeline.forEach((voices, t) => {
        const tick16 = t * 2; // Converting 8th-grid index to 16th-grid space
        harmonyTicks.push(tick16);
        harmonyTimeline[tick16] = {};
        voices.forEach(v => {
            harmonyTimeline[tick16][v.voice] = { pitch: v.pitch, dur16: v.dur8 * 2 };
        });
    });

    const harmonyAnalysis = analyzeStrettoHarmony(harmonyTimeline, harmonyTicks);

    const timePoints = Array.from(timeline.keys()).sort((a,b) => a-b);

    let totalPolyTime = 0;
    let totalDissTime = 0; // S1
    let totalWeightedDissTime = 0; // S2
    let weightedTotalPoly = 0; // S2 Denom
    let totalNCTTime = 0; // S3 (Time Based: Count slices where ANY NCT exists)

    let totalDissEvents = 0; // S4
    let unpreparedDissEvents = 0; // S4

    // Track previous state for S4 (Preparation check)
    const previousStateByVoice = new Map<number, {pitch: number, isConsonantAgainstBass: boolean}>();
    let prevBass: number | null = null;

    // 2. Iterate Timeline
    timePoints.forEach(t => {
        const voices = timeline.get(t)!;

        // Update monophonic state for S4 continuity
        if (voices.length === 1) {
            prevBass = voices[0].pitch;
            previousStateByVoice.clear();
            previousStateByVoice.set(voices[0].voice, { pitch: voices[0].pitch, isConsonantAgainstBass: true });
            return;
        }

        if (voices.length < 2) return;

        totalPolyTime++; 

        // S2 Weighting: Strong beat (divisible by 2 for 4/4 quarter assumption on 8th grid)
        const isStrong = (t % 2 === 0); 
        const weight = isStrong ? 1.5 : 1.0;
        weightedTotalPoly += weight;

        const pitches = voices.map(v => v.pitch).sort((a,b)=>a-b);
        const bass = pitches[0];

        // --- S1 & S2: Dissonance ---
        let isDiss = false;
        for(let i=0; i<pitches.length; i++) {
            for(let j=i+1; j<pitches.length; j++) {
                const int = (pitches[j] - pitches[i]) % 12;
                if (DISSONANT_INTERVALS.has(int)) isDiss = true;
                if (int === 5 && pitches[i] === bass) isDiss = true;
            }
        }

        if (isDiss) {
            totalDissTime++;
            totalWeightedDissTime += weight;
        }

        // --- S3: NCT (TIME BASED LOGIC) ---
        // If there is ANY NCT in this slice, mark the slice as "harmonic clutter"
        const nctCount = countNCTs(pitches);
        if (nctCount > 0) {
            totalNCTTime++;
        }

        // --- S4: Unprepared Dissonance ---
        voices.forEach(v => {
            if (v.pitch === bass) return;

            const intVsBass = (v.pitch - bass + 1200) % 12;
            const isDissVsBass = DISSONANT_INTERVALS.has(intVsBass) || intVsBass === 5;

            if (isDissVsBass) {
                totalDissEvents++;

                // P1: Must have been consonant previously
                const prevState = previousStateByVoice.get(v.voice);
                let prepared = false;

                if (prevState && prevState.isConsonantAgainstBass) {
                    // P2: Single motion constraint
                    const bassMoved = (prevBass !== null && prevBass !== bass);
                    const voiceMoved = (prevState.pitch !== v.pitch);

                    // XOR logic: Only one should move for strict preparation
                    if ((!voiceMoved && bassMoved) || (voiceMoved && !bassMoved)) {
                        prepared = true;
                    }
                }

                if (!prepared) {
                    unpreparedDissEvents++;
                }
            }
            // Update state
            previousStateByVoice.set(v.voice, { pitch: v.pitch, isConsonantAgainstBass: !isDissVsBass });
        });
        prevBass = bass;
    });

    // 3. Final Calculation
    const S1 = totalPolyTime > 0 ? totalDissTime / totalPolyTime : 0;
    const S2 = weightedTotalPoly > 0 ? totalWeightedDissTime / weightedTotalPoly : 0;
    // S3 Update: Time Based Ratio
    const S3 = totalPolyTime > 0 ? totalNCTTime / totalPolyTime : 0;

    const S4 = totalDissEvents > 0 ? unpreparedDissEvents / totalDissEvents : 0;

    const penalty = (S1 * W_S1) + (S2 * W_S2) + (S3 * W_S3) + (S4 * W_S4);
    const score = Math.max(0, Math.round(1000 * (1 - penalty)));

    const log: ScoreLog = { 
        base: 1000, 
        bonuses: [], 
        penalties: [
            { reason: `S1: Unweighted Diss (${(S1*100).toFixed(0)}%)`, points: Math.round(S1 * 1000 * W_S1) },
            { reason: `S2: Weighted Diss (${(S2*100).toFixed(0)}%)`, points: Math.round(S2 * 1000 * W_S2) },
            { reason: `S3: NCT Time (${(S3*100).toFixed(0)}%)`, points: Math.round(S3 * 1000 * W_S3) },
            { reason: `S4: Unprepared Diss (${(S4*100).toFixed(0)}%)`, points: Math.round(S4 * 1000 * W_S4) },
        ], 
        total: score 
    };

    // 4. Consonant End Validation (Gatekeeper A)
    let isValid = true;
    if (options.requireConsonantEnd) {
        chain.forEach((e, i) => {
            const variant = variants[variantIndices[i]];
            const end8 = Math.round(e.startBeat * 2) + variant.length8;
            const lastMoment = end8 - 1;

            const activeVoices = timeline.get(lastMoment);
            if (activeVoices && activeVoices.length > 1) {
                const pitches = activeVoices.map(v => v.pitch).sort((a,b)=>a-b);
                const bass = pitches[0];
                const myVoice = activeVoices.find(v => v.voice === e.voiceIndex);

                if (myVoice) {
                    let isClean = true;
                    if (myVoice.pitch === bass) {
                        for (const other of pitches) {
                            if (other === bass) continue;
                            const int = (other - bass) % 12;
                            if (DISSONANT_INTERVALS.has(int) || int === 5) isClean = false;
                        }
                    } else {
                        const int = (myVoice.pitch - bass) % 12;
                        if (DISSONANT_INTERVALS.has(int) || int === 5) isClean = false;
                    }
                    if (!isClean) isValid = false;
                }
            }
        });
    }

    return {
        id: Math.random().toString(36),
        entries: chain,
        warnings: [],
        score,
        scoreLog: log,
        detectedChords: harmonyAnalysis.chords, 
        dissonanceRatio: S1,
        nctRatio: S3, // Now populated with Time-Based metric
        pairDissonanceScore: S4 * 100,
        isValid
    };
}

import React from 'react';
import { StrettoSearchOptions, StrettoChainResult, StrettoCandidate, RawNote, StrettoSearchReport, HarmonicRegion } from '../../types';
import StrettoSearchPanel from './StrettoSearchPanel';
import StrettoResultsList from './StrettoResultsList';
import StrettoInspector from './StrettoInspector';
import { DownloadIcon } from '../Icons';
import { generatePolyphonicHarmonicRegions } from '../services/strettoCore'; // NEW IMPORT
import { getStrictPitchName } from '../services/midiSpelling';
import { SCALE_INTERVALS } from '../services/strettoConstants';

interface StrettoChainViewProps {
    searchOptions: StrettoSearchOptions;
    setSearchOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    chainResults: StrettoChainResult[];
    selectedChain: StrettoChainResult | null;
    setSelectedChain: (res: StrettoChainResult | null) => void;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;

    // Inspector Props
    chainToCandidate: StrettoCandidate | null; // Note: We actually override this logic locally to ensure polyphony
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    onDownloadChain: () => void;
    searchReport?: StrettoSearchReport | null;

    // Master Transposition
    masterTransposition: number;
    setMasterTransposition: (val: number) => void;
    subjectNotes: RawNote[]; // New prop
}

export default function StrettoChainView({
    searchOptions, setSearchOptions, onSearch, isSearching,
    chainResults, selectedChain, setSelectedChain, voiceNames, setVoiceNames,
    chainToCandidate: _unusedLegacyProp, // We recreate it here to ensure correct polyphonic region generation
    ppq, ts, isPlaying, onPlay, onDownloadChain,
    searchReport, masterTransposition, setMasterTransposition,
    subjectNotes
}: StrettoChainViewProps) {

    // Re-implement candidate generation here to use the new Polyphonic Region Logic
    // instead of relying on the parent's potentially outdated logic
    const chainCandidate = React.useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        // Use Scale Mode from Search Options for correct inversion reconstruction
        const currentScaleIntervals = SCALE_INTERVALS[searchOptions.scaleMode] || SCALE_INTERVALS['Major'];

        const invertPitchDiatonic = (pitch: number, pivot: number) => {
            const diff = pitch - pivot;
            const oct = Math.floor(diff / 12);
            const semi = (diff % 12 + 12) % 12;
            let degree = -1;
            let minErr = 99;
            currentScaleIntervals.forEach((s, i) => {
                if (Math.abs(s - semi) < minErr) { minErr = Math.abs(s - semi); degree = i; }
            });
            const absDegree = (oct * 7) + degree;
            const invAbsDegree = -absDegree;
            const invOct = Math.floor(invAbsDegree / 7);
            const invIndex = (invAbsDegree % 7 + 7) % 7;
            return pivot + (invOct * 12) + currentScaleIntervals[invIndex];
        };

        const invertPitchChromatic = (pitch: number, pivot: number) => {
            return pivot - (pitch - pivot);
        }

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;

                if (entry.type === 'I') {
                    const rawInverted = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(n.midi, searchOptions.pivotMidi)
                        : invertPitchDiatonic(n.midi, searchOptions.pivotMidi);

                    const subjectFirst = sortedSubj[0].midi;
                    const invertedFirst = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(subjectFirst, searchOptions.pivotMidi)
                        : invertPitchDiatonic(subjectFirst, searchOptions.pivotMidi);

                    const targetStart = subjectFirst + entry.transposition;
                    const shift = targetStart - invertedFirst;
                    pitch = rawInverted + shift;
                } else {
                    pitch += entry.transposition;
                }

                pitch += masterTransposition;

                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            allNotes = [...allNotes, ...clipped];
        });

        // Use new Polyphonic logic for the Chain
        const harmonicRegions = generatePolyphonicHarmonicRegions(allNotes, searchOptions.scaleRoot);

        return { 
            id: selectedChain.id, 
            intervalLabel: "Chain", 
            intervalSemis: 0, 
            delayBeats: 0, 
            delayTicks: 0, 
            grade: 'STRONG', 
            errors: [], 
            notes: allNotes, 
            regions: harmonicRegions, 
            dissonanceRatio: selectedChain.dissonanceRatio || 0,
            nctRatio: selectedChain.nctRatio || 0, // Use the calculated value from the search result for consistency
            pairDissonanceScore: selectedChain.pairDissonanceScore || 0, // Use the calculated intensity from the search result
            endsOnDissonance: false,
            detectedChords: selectedChain.detectedChords
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi, searchOptions.useChromaticInversion, masterTransposition, searchOptions.scaleRoot, searchOptions.scaleMode]);

    return (
        <>
            <StrettoSearchPanel 
                options={searchOptions} 
                setOptions={setSearchOptions}
                onSearch={onSearch}
                isSearching={isSearching}
                voiceNames={voiceNames}
                setVoiceNames={setVoiceNames}
                subjectNotes={subjectNotes}
                ppq={ppq}
            />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                    <div className="p-3 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
                        <h3 className="text-xs font-bold text-gray-400">FOUND CHAINS ({chainResults.length})</h3>
                        {searchReport && (
                            <div className="text-[9px] text-gray-500 text-right">
                                {searchReport.stats.nodesVisited.toLocaleString()} nodes in {searchReport.stats.timeMs}ms
                            </div>
                        )}
                    </div>
                    {searchReport && searchReport.stats.stopReason !== 'Success' && (
                        <div className="bg-yellow-900/30 border-b border-yellow-800 p-2 text-[10px] text-yellow-300">
                            <strong>Search {searchReport.stats.stopReason}:</strong> No valid chains of length {searchOptions.targetChainLength} found.
                            Showing partial chains (Max Depth: {searchReport.stats.maxDepthReached}).
                        </div>
                    )}
                    <StrettoResultsList 
                        results={chainResults}
                        selectedId={selectedChain?.id || null}
                        onSelect={setSelectedChain}
                        voiceNames={voiceNames}
                    />
                </div>
                <div className="lg:col-span-2">
                    <StrettoInspector 
                        candidate={chainCandidate}
                        ppq={ppq}
                        ts={ts}
                        isPlaying={isPlaying}
                        onPlay={onPlay}
                        assemblyResult={""}
                        assemblyLog={[]}
                        onClearAssembly={() => {}}
                        onDownloadChain={onDownloadChain}
                    />

                    <div className="mt-4 flex flex-col md:flex-row justify-between items-center gap-4 bg-gray-800 p-3 rounded border border-gray-700">
                        <div className="flex items-center gap-4">
                            <span className="text-xs font-bold text-gray-400 uppercase">Master Transpose:</span>
                            <div className="flex items-center gap-2">
                                <button 
                                    onClick={() => setMasterTransposition(Math.max(-24, masterTransposition - 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >-</button>
                                <span className={`text-sm font-mono w-12 text-center ${masterTransposition !== 0 ? 'text-brand-primary font-bold' : 'text-gray-300'}`}>
                                    {masterTransposition > 0 ? '+' : ''}{masterTransposition}
                                </span>
                                <button 
                                    onClick={() => setMasterTransposition(Math.min(24, masterTransposition + 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >+</button>
                            </div>
                            <span className="text-[10px] text-gray-500 hidden sm:inline">Shift entire chain before export.</span>
                        </div>

                        {chainCandidate && (
                            <button 
                                onClick={onDownloadChain}
                                className="flex items-center gap-2 px-4 py-2 bg-brand-primary text-white font-bold rounded shadow-lg hover:bg-brand-secondary transition-colors"
                            >
                                <DownloadIcon className="w-4 h-4" /> Download Chain MIDI
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </>
    );
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion, NoteRole } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel, getPitchName } from './midiSpelling';
import { CHORD_SHAPES, CONSONANT_QUALITIES, SCALE_INTERVALS } from './strettoConstants';

const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5

export interface VoiceEvent {
    tick: number;
    endTick: number; 
    pitch1: number;
    pitch2: number;
    hasAttack1: boolean;
    hasAttack2: boolean;
}

// --- Shared Inversion Logic ---

function getScaleDegree(pitch: number, root: number, intervals: number[]): { octave: number, degree: number } | null {
    const semitone = (pitch - root + 1200) % 12; 
    let bestDegree = -1;
    let minErr = 99;

    intervals.forEach((s, i) => {
        const err = Math.abs(s - semitone);
        if (err < minErr) { minErr = err; bestDegree = i; }
    });

    const relPitch = pitch - root;
    const oct = Math.floor(relPitch / 12);
    return { octave: oct, degree: bestDegree };
}

function getPitchFromDegree(octave: number, degree: number, root: number, intervals: number[]): number {
    const normalizedDegree = (degree % 7 + 7) % 7;
    const octaveShift = Math.floor(degree / 7);
    const semi = intervals[normalizedDegree];
    return root + (octave + octaveShift) * 12 + semi;
}

/**
 * Calculates a strictly inverted pitch based on a pivot, root, and scale mode.
 * Used by both Generator and UI to ensure 1:1 consistency.
 */
export function getInvertedPitch(pitch: number, pivot: number, scaleRoot: number, scaleMode: string, useChromatic: boolean): number {
    if (useChromatic) {
        return pivot - (pitch - pivot);
    }

    const intervals = SCALE_INTERVALS[scaleMode] || SCALE_INTERVALS['Major'];

    // 1. Find where the Pivot sits in the scale
    const pivotInfo = getScaleDegree(pivot, scaleRoot, intervals);
    // If pivot isn't in scale, we can't do strict tonal inversion easily. 
    // Fallback: Treat pivot as if it were the nearest scale note? 
    // For now, just return raw if pivot fails, or maybe snap pivot.
    // Let's assume pivot is valid or we map it.
    if (!pivotInfo) return pivot - (pitch - pivot); // Fallback to chromatic if pivot invalid

    const pivotGlobalIndex = pivotInfo.octave * 7 + pivotInfo.degree;

    // 2. Find where the Target Pitch sits
    const info = getScaleDegree(pitch, scaleRoot, intervals);
    if (!info) return pivot - (pitch - pivot); // Fallback if note outside scale

    const currentGlobalIndex = info.octave * 7 + info.degree;

    // 3. Reflect index around pivot index
    // dist = current - pivot
    // new = pivot - dist = pivot - (current - pivot) = 2*pivot - current
    const invertedGlobalIndex = 2 * pivotGlobalIndex - currentGlobalIndex;

    const invOct = Math.floor(invertedGlobalIndex / 7);
    const invDeg = (invertedGlobalIndex % 7 + 7) % 7;

    return getPitchFromDegree(invOct, invDeg, scaleRoot, intervals);
}

// Determines if any dissonance exists in a set of pitches
function analyzeVerticalSlice(pitches: number[]): { isDissonant: boolean; label: string } {
    if (pitches.length < 2) return { isDissonant: false, label: '' };

    const sorted = [...pitches].sort((a,b) => a-b);
    const bass = sorted[0];

    for (let i = 0; i < sorted.length; i++) {
        for (let j = i + 1; j < sorted.length; j++) {
            const p1 = sorted[i];
            const p2 = sorted[j];
            const interval = Math.abs(p1 - p2);
            const ic = interval % 12;

            const isBassPair = (p1 === bass || p2 === bass);
            let isDiss = DISSONANT_INTERVALS.includes(ic);
            if (ic === 5 && isBassPair) isDiss = true; // P4 against bass

            if (isDiss) {
                // Prioritize displaying the "crunchiest" interval
                return { isDissonant: true, label: getIntervalLabel(interval) };
            }
        }
    }

    // If no dissonance, return first interval label or generic
    const firstInt = Math.abs(sorted[1] - sorted[0]);
    return { isDissonant: false, label: getIntervalLabel(firstInt) };
}

// Special function for Dyad inference (2 pitch classes)
function analyzeDyad(pc1: number, pc2: number): { name: string; root: number; quality: string } | null {
    const diff = (pc2 - pc1 + 12) % 12; // Assuming pc1 is bass for interval calc

    // 3rd (Major or Minor) -> Root is bottom
    if (diff === 3) return { name: "Min (no 5)", root: pc1, quality: "Min" };
    if (diff === 4) return { name: "Maj (no 5)", root: pc1, quality: "Maj" };

    // 6th (Inverted 3rd) -> Root is top
    if (diff === 8) return { name: "Maj (no 5)", root: pc2, quality: "Maj" }; // m6 -> Inverted Maj3
    if (diff === 9) return { name: "Min (no 5)", root: pc2, quality: "Min" }; // M6 -> Inverted min3

    // Perfect 5th -> Power Chord
    if (diff === 7) return { name: "5", root: pc1, quality: "5" };

    // Tritone -> Diminished (no 3rd) - Usually implies dim triad or dim7
    if (diff === 6) return { name: "Dim (no 3)", root: pc1, quality: "Dim" };

    // P4, 2nds, 7ths are treated as Intervals, not Chords here
    return null;
}

// Helper to identify chord and return quality + NCT count
// Prioritizes shapes where the chord root matches the actual bass note
function identifyChordWithNCT(pitches: number[]): { name: string, quality: string, nct: number, chordTones: number[], rootPC: number } | null {
    if (pitches.length < 2) return null;
    const uniquePCs = Array.from(new Set(pitches.map(p => p % 12)));

    // Dyad/Cluster handling for 2 unique PCs (even if multiple octaves)
    if (uniquePCs.length === 2) {
        const sortedPCs = [...uniquePCs].sort((a,b) => a-b);
        const sortedInput = [...pitches].sort((a,b) => a-b);
        const bassPC = sortedInput[0] % 12;
        const otherPC = uniquePCs.find(p => p !== bassPC) || bassPC;

        const dyadAnalysis = analyzeDyad(bassPC, otherPC);
        if (dyadAnalysis) {
            return {
                name: `${getStrictPitchName(dyadAnalysis.root).replace(/\d/g, '')} ${dyadAnalysis.name}`,
                quality: dyadAnalysis.quality,
                nct: 0,
                chordTones: uniquePCs,
                rootPC: dyadAnalysis.root
            };
        } else {
            // It's an interval (P4, 2nd, 7th)
            return null;
        }
    }

    // 3+ Unique PCs -> Standard Shape Matching
    const sorted = [...pitches].sort((a,b) => a-b);
    const bassPC = sorted[0] % 12;

    let bestMatch = null;
    let bestScore = -Infinity;

    for (const root of uniquePCs) {
        const intervals = uniquePCs.map(pc => (pc - root + 12) % 12);
        for (const shape of CHORD_SHAPES) {
            const matchedIntervals = intervals.filter(i => shape.intervals.includes(i));
            const nctCount = intervals.length - matchedIntervals.length;

            // Basic heuristic: Must match at least 2 notes of the shape
            if (matchedIntervals.length < 2) continue;

            // --- CONSTRAINT: Extension Existence ---
            if (shape.intervals.length > 3) {
                const extensionInterval = shape.intervals[shape.intervals.length - 1];
                if (!matchedIntervals.includes(extensionInterval)) {
                    continue; // Skip this shape, it's invalid (e.g. Maj7 without 7)
                }
            }

            // --- SCORING LOGIC v3 ---
            let missingPenalty = 0;
            const missingIntervals = shape.intervals.filter(i => !matchedIntervals.includes(i));

            missingIntervals.forEach(int => {
                if (int === 3 || int === 4) {
                    missingPenalty += 30; // Missing 3rd is expensive
                } else if (int === 7 || int === 6 || int === 8) {
                    missingPenalty += 10; // Missing 5th is cheap
                } else {
                    missingPenalty += 10; 
                }
            });

            let score = (matchedIntervals.length * 100) 
                      - (nctCount * 500) 
                      - missingPenalty;

            if (root === bassPC) score += 5;

            if (score > bestScore) {
                bestScore = score;
                const rootName = getStrictPitchName(root).replace(/\d/g, '');

                // Identify which PCs are Chord Tones
                const chordTones = uniquePCs.filter(pc => {
                    const int = (pc - root + 12) % 12;
                    return shape.intervals.includes(int);
                });

                bestMatch = { 
                    name: `${rootName} ${shape.name}`, 
                    quality: shape.name, 
                    nct: nctCount,
                    chordTones: chordTones,
                    rootPC: root
                };
            }
        }
    }
    return bestMatch;
}

export function generatePolyphonicHarmonicRegions(notes: RawNote[], keyRoot: number = 0): HarmonicRegion[] {
    if (notes.length === 0) return [];

    // 1. Collect all time boundaries
    const timePoints = new Set<number>();
    notes.forEach(n => {
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });
    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);

    const regions: HarmonicRegion[] = [];
    let consecutiveDissonanceCount = 0;

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const start = sortedPoints[i];
        const end = sortedPoints[i+1];
        const mid = start + (end - start) / 2; // Sample middle to avoid boundary edge cases

        // Active notes in this slice
        const active = notes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) {
            consecutiveDissonanceCount = 0; // Reset on rest/monophony
            continue;
        }

        const pitches = active.map(n => n.midi);
        const chordMatch = identifyChordWithNCT(pitches);
        const { isDissonant, label } = analyzeVerticalSlice(pitches);

        let type: HarmonicRegion['type'] = 'consonant_stable';

        let detailedInfo: NonNullable<HarmonicRegion['detailedInfo']> = {
            chordName: "",
            allNotes: active.map(n => getPitchName(n.midi, keyRoot)),
            noteDetails: [],
            chordTones: [],
            ncts: []
        };

        if (chordMatch) {
            const { quality, nct, name, chordTones, rootPC } = chordMatch;
            const isConsonantChord = CONSONANT_QUALITIES.has(quality);

            detailedInfo.chordName = name;
            detailedInfo.quality = quality;

            const ctSet = new Set(chordTones);
            const isAug = quality.toLowerCase().includes('aug');

            active.forEach(n => {
                const pc = n.midi % 12;
                const interval = (pc - rootPC + 12) % 12;
                const noteName = getPitchName(n.midi, keyRoot);

                let role: NoteRole['role'] = 'NCT';

                if (ctSet.has(pc)) {
                    detailedInfo.chordTones.push(noteName);

                    if (interval === 0) role = 'Root';
                    else if (interval === 3 || interval === 4) role = '3rd';
                    else if (interval === 7) role = '5th';
                    else if (interval === 6) role = 'Ext'; // Dim 5 / Tritone
                    else if (interval === 8) {
                        // 8 is Min 6th or Aug 5th.
                        // If chord quality is Aug, treat as 5th (Augmented)
                        role = isAug ? '5th' : 'Ext'; 
                    }
                    else role = 'Ext'; // 7th, 6th, etc.
                } else {
                    detailedInfo.ncts.push(noteName);
                    role = 'NCT';
                }

                detailedInfo.noteDetails.push({
                    name: noteName,
                    midi: n.midi,
                    role: role
                });
            });

            // Case 5: 2+ NCTs -> Red
            if (nct >= 2) {
                type = 'dissonant_severe';
                consecutiveDissonanceCount++; 
            } 
            // 1 NCT cases
            else if (nct === 1) {
                if (isConsonantChord) {
                    type = 'dissonant_secondary'; 
                } else {
                    type = 'dissonant_tertiary'; 
                }
                consecutiveDissonanceCount++;
            }
            // Clean Chords (0 NCT)
            else {
                if (isConsonantChord) {
                    type = 'consonant_stable'; 
                    consecutiveDissonanceCount = 0; 
                } else {
                    type = 'dissonant_primary'; 
                    consecutiveDissonanceCount++;
                }
            }
        } else {
            // No Chord Detected -> Interval Logic
            detailedInfo.chordName = `Interval: ${label}`;

            // For Intervals, we treat them as 'Chord Tones' but they don't have harmonic roles
            // We'll mark them as Ext to give them Purple color or maybe Root/5th if P5?
            // Let's just default to 'Root' for bass and 'Ext' for others to show color variety?
            // Actually, user spec is specific for Harmonic breakdown. For intervals, maybe just use NCT (Orange) or Ext (Purple).
            // Let's fallback to Ext (Purple) for clarity.
            const sortedActive = [...active].sort((a,b)=>a.midi - b.midi);
            sortedActive.forEach((n, i) => {
                detailedInfo.noteDetails.push({
                    name: getPitchName(n.midi, keyRoot),
                    midi: n.midi,
                    role: i === 0 ? 'Root' : 'Ext' // Arbitrary visual assignment for raw intervals
                });
            });
            detailedInfo.chordTones = detailedInfo.allNotes; 

            if (isDissonant) {
                consecutiveDissonanceCount++;
                if (consecutiveDissonanceCount === 1) {
                    type = 'dissonant_primary'; 
                } else if (consecutiveDissonanceCount === 2) {
                    type = 'dissonant_secondary'; 
                } else {
                    type = 'dissonant_tertiary'; 
                }
            } else {
                type = 'consonant_stable'; 
                consecutiveDissonanceCount = 0; 
            }
        }

        regions.push({
            startTick: start,
            endTick: end,
            type: type,
            intervalLabel: detailedInfo.chordName, // Short label
            description: detailedInfo.ncts.length > 0 ? `NCTs: ${detailedInfo.ncts.join(', ')}` : undefined,
            detailedInfo
        });
    }

    return regions;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60,
    useChromaticInversion: boolean = false,
    keyRoot: number = 0 // New param for spelling
): StrettoCandidate {

    if (subject.length === 0) {
        return {
            id: `empty`, intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, nctRatio: 0, pairDissonanceScore: 0, endsOnDissonance: true
        };
    }

    const subjectEntryPitch = subject[0].midi;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi: number;

        if (isInverted) {
            const rawInverted = getInvertedPitch(n.midi, pivotMidi, keyRoot, 'Major', useChromaticInversion);
            const invertedStart = getInvertedPitch(subjectEntryPitch, pivotMidi, keyRoot, 'Major', useChromaticInversion);
            const targetStart = subjectEntryPitch + intervalSemis;
            const shift = targetStart - invertedStart;
            newMidi = rawInverted + shift;
        } else {
            newMidi = n.midi + intervalSemis;
        }

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getPitchName(newMidi, keyRoot),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const allNotes = [...subject, ...answer];

    // Generate Regions using Polyphonic Logic with Key Root
    const harmonicRegions = generatePolyphonicHarmonicRegions(allNotes, keyRoot);

    // Calculate Metrics
    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let nctTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;

        // Dissonance accumulation
        if (r.type !== 'consonant_stable') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }

        // NCT accumulation
        if (r.detailedInfo && r.detailedInfo.ncts.length > 0) {
            nctTicks += dur;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;
    const nctRatio = totalOverlapTicks > 0 ? (nctTicks / totalOverlapTicks) : 0;

    let pairDissonanceScore = 0;
    harmonicRegions.forEach(r => {
        const mid = r.startTick + (r.endTick - r.startTick)/2;
        const active = allNotes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) return;

        const sorted = active.map(n => n.midi).sort((a,b) => a-b);
        const bass = sorted[0];
        let pairDissCount = 0;

        for(let i=0; i<sorted.length; i++) {
            for(let j=i+1; j<sorted.length; j++) {
                const interval = Math.abs(sorted[i] - sorted[j]);
                const ic = interval % 12;
                const isBassPair = (sorted[i] === bass || sorted[j] === bass);
                let isDiss = DISSONANT_INTERVALS.includes(ic);
                if (ic === 5 && isBassPair) isDiss = true;

                if (isDiss) pairDissCount++;
            }
        }

        const durBeats = (r.endTick - r.startTick) / ppq;
        pairDissonanceScore += (durBeats * pairDissCount);
    });

    const errors: StrettoError[] = [];

    let prevP1: number | null = null;
    let prevP2: number | null = null;

    const timePoints = new Set<number>();
    allNotes.forEach(n => { timePoints.add(n.ticks); timePoints.add(n.ticks+n.durationTicks); });
    const tPoints = Array.from(timePoints).sort((a,b)=>a-b);

    for(let i=0; i<tPoints.length-1; i++) {
        const t = tPoints[i];
        const n1 = subject.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);
        const n2 = answer.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);

        if (n1 && n2) {
            const p1 = n1.midi;
            const p2 = n2.midi;

            if (prevP1 !== null && prevP2 !== null) {
                if (prevP1 !== p1 && prevP2 !== p2) { 
                    const int1 = Math.abs(prevP1 - prevP2) % 12;
                    const int2 = Math.abs(p1 - p2) % 12;
                    const isPerfect = int2 === 0 || int2 === 7;
                    if (isPerfect && int1 === int2) {
                        const timeStr = getFormattedTime(t, ppq, ts.num, ts.den);
                        const isStrong = isStrongBeat(t, ppq, ts.num, ts.den);
                        errors.push({
                            tick: t, timeFormatted: timeStr,
                            type: int2 === 7 ? 'Parallel 5th' : 'Parallel 8ve',
                            details: 'Parallel Perfect Interval',
                            severity: isStrong ? 'fatal' : 'warning'
                        });
                    }
                }
            }
            prevP1 = p1; prevP2 = p2;
        } else {
            prevP1 = null; prevP2 = null;
        }
    }

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: allNotes,
        regions: harmonicRegions,
        dissonanceRatio,
        nctRatio,
        pairDissonanceScore: parseFloat(pairDissonanceScore.toFixed(1)),
        endsOnDissonance
    };
}

import { CHORD_SHAPES, SCORING } from './strettoConstants';
import { NOTE_NAMES } from './midiCore';

export interface StrettoHarmonyResult {
    reward: number;
    penalty: number;
    chords: string[]; // List of unique detected chord names for display
}

interface InternalNoteState {
    pitch: number;
    dur16: number; // Remaining duration in 16th notes
}

interface ChordMatchResult {
    name: string;
    rootIndex: number; // 0-11 relative to the input set, needs context to resolve absolute name
    matched: number;
    nct: number;
    full: boolean;
}

// Memoization Cache: 12-bit integer (Pitch Class Set) -> Best Chord Match Template
const CHORD_CACHE = new Map<number, ChordMatchResult | null>();

function getPitchSetBitmask(pitches: number[]): number {
    let mask = 0;
    for (const p of pitches) {
        mask |= (1 << (p % 12));
    }
    return mask;
}

// Core matching logic (Heavy)
function computeBestChord(pitches: number[]): ChordMatchResult | null {
    const uniquePCs = Array.from(new Set(pitches.map(p => p % 12)));
    if (uniquePCs.length < 2) return null;

    let bestMatch = null;
    let bestScore = -Infinity;

    for (const root of uniquePCs) {
        const intervals = uniquePCs.map(pc => (pc - root + 12) % 12);

        for (const shape of CHORD_SHAPES) {
            const matchedIntervals = intervals.filter(i => shape.intervals.includes(i));
            const nctCount = intervals.length - matchedIntervals.length;

            let requiredPresent = true;

            // Check 3rd (3 or 4) - Mandatory
            const has3rd = matchedIntervals.includes(3) || matchedIntervals.includes(4);
            if (!has3rd) continue; 

            // Check 5th
            const has5th = matchedIntervals.includes(7) || matchedIntervals.includes(6) || matchedIntervals.includes(8);

            let isFull = has3rd && has5th;
            if (shape.name.includes('7') || shape.name.includes('9')) {
                const has7 = matchedIntervals.includes(10) || matchedIntervals.includes(11) || matchedIntervals.includes(9);
                if (!has7) requiredPresent = false; 
                else isFull = isFull && true;
            }

            if (!requiredPresent) continue;

            const score = (matchedIntervals.length * 10) - (nctCount * 15);

            if (score > bestScore) {
                bestScore = score;
                bestMatch = { 
                    name: shape.name, 
                    rootIndex: root,
                    matched: matchedIntervals.length, 
                    nct: nctCount,
                    full: isFull 
                };
            }
        }
    }
    return bestMatch;
}

// Memoized Wrapper (Fast)
function identifyBestChordMemoized(pitches: number[]): ChordMatchResult | null {
    const mask = getPitchSetBitmask(pitches);
    if (CHORD_CACHE.has(mask)) {
        return CHORD_CACHE.get(mask)!;
    }
    const result = computeBestChord(pitches);
    CHORD_CACHE.set(mask, result);
    return result;
}

/**
 * Analyzes the harmonic content of a timeline using optimized caching.
 * Logic:
 * - 2+ Voices: Attempt to identify and report chord names.
 * - 3+ Voices: Apply scoring (Rewards/Penalties).
 * - FILTER: Only reports chords that persist for >= 1 Beat (4 x 16th notes).
 */
export function analyzeStrettoHarmony(
    timeline: { [tick16: number]: { [voiceIdx: number]: InternalNoteState } },
    ticks: number[]
): StrettoHarmonyResult {
    let harmonicReward = 0;
    let harmonicPenalty = 0;
    const detectedChordsMap = new Map<string, number>(); // Name -> Duration (16ths)

    if (ticks.length === 0) return { reward: 0, penalty: 0, chords: [] };

    for (const t of ticks) {
        const activeVoiceMap = timeline[t];
        if (!activeVoiceMap) continue;

        const activeIndices = Object.keys(activeVoiceMap).map(Number);
        const activeCount = activeIndices.length;

        // Threshold 1: Detection (2 or more voices)
        if (activeCount >= 2) {
            const longPitches: number[] = [];
            activeIndices.forEach(v => {
                const noteData = activeVoiceMap[v];
                if (noteData.dur16 >= SCORING.HARMONY_MIN_DURATION_16THS) {
                    longPitches.push(noteData.pitch);
                }
            });

            if (longPitches.length >= 2) {
                const match = identifyBestChordMemoized(longPitches);

                if (match) {
                    // Resolve absolute root name
                    const rootName = NOTE_NAMES[match.rootIndex % 12];
                    const fullName = `${rootName} ${match.name}`;

                    // Accumulate duration for this chord
                    // Each step in timeline is a 16th note (from strettoScoring.ts logic)
                    detectedChordsMap.set(fullName, (detectedChordsMap.get(fullName) || 0) + 1);

                    // Threshold 2: Scoring (3 or more voices)
                    if (activeCount >= 3) {
                        // Normalized: Score per BEAT. Each loop step is 1/16th (0.25 beat).
                        if (match.full) {
                            harmonicReward += (0.25) * SCORING.HARMONY_FULL_CHORD_REWARD; 
                        }
                        if (match.nct > 0) {
                            harmonicPenalty += (0.25) * (match.nct * SCORING.HARMONY_NCT_PENALTY_MULT);
                        }
                    }
                }
            }
        }
    }

    // Filter: Only include chords that existed for at least 1 Beat (4 x 16th notes)
    const validChords = Array.from(detectedChordsMap.entries())
        .filter(([_, dur]) => dur >= 4)
        .map(([name]) => name)
        .slice(0, 8); // Return up to 8 unique significant chords

    return {
        reward: harmonicReward,
        penalty: harmonicPenalty,
        chords: validChords
    };
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, StrettoSearchReport } from '../../types';
import { INTERVALS, SCALE_INTERVALS } from './strettoConstants';
import { calculateStrettoScore, SubjectVariant } from './strettoScoring';
import { getInvertedPitch } from './strettoCore';

// --- Constants & Types ---
const MAX_SEARCH_NODES = 500000;
const TIME_LIMIT_MS = 30000;
const MAX_RESULTS = 50;

interface InternalNote {
    relTick8: number; // 8th note grid relative to start
    dur8: number;
    pitch: number;
}

// --- Precomputation: Scales & Inversion ---

function normalizeSubject(notes: RawNote[], ppq: number): { notes: InternalNote[], offset8: number } {
    const valid = notes.filter(n => !!n).sort((a,b) => a.ticks - b.ticks);
    if (valid.length === 0) return { notes: [], offset8: 0 };

    const grouped: Map<number, RawNote[]> = new Map();
    valid.forEach(n => {
        const t = Math.round(n.ticks / (ppq/8)); 
        if (!grouped.has(t)) grouped.set(t, []);
        grouped.get(t)!.push(n);
    });

    const monoNotes: RawNote[] = [];
    Array.from(grouped.values()).forEach(group => {
        group.sort((a,b) => b.midi - a.midi);
        monoNotes.push(group[0]);
    });
    monoNotes.sort((a,b) => a.ticks - b.ticks);

    const startTick = monoNotes[0].ticks;
    const ticksPer8 = ppq / 2;

    const offset8 = Math.round(startTick / ticksPer8);

    const internalNotes = monoNotes.map(n => ({
        relTick8: Math.round((n.ticks - startTick) / ticksPer8),
        dur8: Math.max(1, Math.round(n.durationTicks / ticksPer8)),
        pitch: n.midi
    }));

    return { notes: internalNotes, offset8 };
}

// --- Rule Definitions (Pruning) ---

const DISSONANT_INTERVALS = new Set([1, 2, 6, 10, 11]);
// STRICT RULE: Include 5 (P4) in Perfect Intervals to prevent parallel 4ths
const PERFECT_INTERVALS = new Set([0, 7, 5]);

/**
 * PHASE 1 CHECK: Structural Validity (Pairwise)
 * Relaxed: Does NOT check "Ends on Dissonance" (C6) as that is position-dependent.
 * Checks: Parallel Perfects (including P4), Run Length <= 2.
 * NOW INCLUDES: Strict Dissonance Ratio Filter
 */
function checkCounterpointStructure(
    variantA: SubjectVariant, 
    variantB: SubjectVariant, 
    delay8: number, 
    transposition: number,
    maxDissonanceRatio: number
): { compatible: boolean } {
    const notesA = variantA.notes;
    const notesB = variantB.notes;
    const timeline = new Map<number, { pA?: number, pB?: number }>();

    notesA.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + t;
            if (!timeline.has(tick)) timeline.set(tick, {});
            timeline.get(tick)!.pA = n.pitch;
        }
    });

    notesB.forEach(n => {
        for(let t=0; t<n.dur8; t++) {
            const tick = n.relTick8 + delay8 + t;
            if (timeline.has(tick)) timeline.get(tick)!.pB = n.pitch + transposition;
        }
    });

    const ticks = Array.from(timeline.keys()).sort((a,b) => a-b);
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    let dissRunLength = 0; 
    let lastIsDiss = false;

    let overlapTicks = 0;
    let dissonantTicks = 0;

    for (let i = 0; i < ticks.length; i++) {
        const t = ticks[i];
        const state = timeline.get(t)!;

        if (state.pA === undefined || state.pB === undefined) {
            // Monophonic moment - reset trackers
            prevP1 = null; prevP2 = null;
            dissRunLength = 0;
            lastIsDiss = false;
            // Note: Rule C6 (Resolution into silence) ignored here to allow chaining
            continue;
        }

        overlapTicks++; // Count every concurrent 8th note tick

        const p1 = state.pA;
        const p2 = state.pB;
        const lo = Math.min(p1, p2);
        const hi = Math.max(p1, p2);
        const interval = (hi - lo) % 12;

        // Rule 5: Parallel Perfects (Now includes P4 via PERFECT_INTERVALS)
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = p1 !== prevP1;
            const p2Moved = p2 !== prevP2;

            if (p1Moved && p2Moved) {
                if (PERFECT_INTERVALS.has(interval)) {
                    const prevLo = Math.min(prevP1, prevP2);
                    const prevHi = Math.max(prevP1, prevP2);
                    const prevInt = (prevHi - prevLo) % 12;
                    if (prevInt === interval) return { compatible: false };
                }
            }
        }

        // Rule 6: Dissonance (Structural)
        let isDiss = DISSONANT_INTERVALS.has(interval);
        if (interval === 5) isDiss = true; // P4 against bass always diss in 2-part

        if (isDiss) {
            dissonantTicks++;

            if (!lastIsDiss) dissRunLength = 1;
            else dissRunLength++;

            // Rule C2: Event Limit (r <= 2)
            if (dissRunLength > 2) return { compatible: false };

            lastIsDiss = true;
        } else {
            dissRunLength = 0;
            lastIsDiss = false;
        }

        prevP1 = p1; prevP2 = p2;
    }

    // Strict Dissonance Ratio Filter
    if (overlapTicks > 0) {
        const ratio = dissonantTicks / overlapTicks;
        if (ratio > maxDissonanceRatio) return { compatible: false };
    }

    return { compatible: true };
}

// Helper: Determine beat strength
function isStrong8th(tick8: number, tsNum: number, tsDenom: number): boolean {
    const eighthsPerBar = (tsNum * 8) / tsDenom;
    const pos = tick8 % eighthsPerBar;

    if (pos === 0) return true; // Downbeat always strong

    if (tsNum === 4 && tsDenom === 4) {
        if (pos === 4) return true; // Beat 3 in 4/4
    }

    return false;
}

/**
 * PHASE 5 CHECK: Metric Compliance
 */
function checkMetricCompliance(
    newVariant: SubjectVariant, 
    newEntry: StrettoChainOption,
    chain: StrettoChainOption[], 
    variants: SubjectVariant[], 
    variantIndices: number[],
    tsNum: number = 4,
    tsDenom: number = 4,
    metricOffset: number = 0
): boolean {

    const newStart8 = Math.round(newEntry.startBeat * 2);

    // Check against every existing voice
    for (let k = 0; k < chain.length; k++) {
        const existEntry = chain[k];
        const existVariant = variants[variantIndices[k]];
        const existStart8 = Math.round(existEntry.startBeat * 2);

        // Determine overlapping region
        const overlapStart = Math.max(newStart8, existStart8);
        const overlapEnd = Math.min(newStart8 + newVariant.length8, existStart8 + existVariant.length8);

        if (overlapEnd <= overlapStart) continue;

        let dissRunLength = 0;
        let lastIsDiss = false;

        // Iterate overlap ticks
        for (let t = overlapStart; t < overlapEnd; t++) {
            const tRelNew = t - newStart8;
            const tRelExist = t - existStart8;

            const noteNew = newVariant.notes.find(n => n.relTick8 <= tRelNew && (n.relTick8 + n.dur8) > tRelNew);
            const noteExist = existVariant.notes.find(n => n.relTick8 <= tRelExist && (n.relTick8 + n.dur8) > tRelExist);

            if (!noteNew || !noteExist) {
                dissRunLength = 0; lastIsDiss = false; continue;
            }

            const p1 = noteNew.pitch + newEntry.transposition;
            const p2 = noteExist.pitch + existEntry.transposition;
            const lo = Math.min(p1, p2);
            const hi = Math.max(p1, p2);
            const interval = (hi - lo) % 12;

            let isDiss = DISSONANT_INTERVALS.has(interval);
            if (interval === 5) isDiss = true;

            // Corrected Metric Check using Absolute Grid alignment
            const isStrong = isStrong8th(t + metricOffset, tsNum, tsDenom);

            if (isDiss) {
                if (!lastIsDiss) dissRunLength = 1; else dissRunLength++;

                // Rule C4B: If Strong beat, resolution must be immediate (Length 1 max)
                if (isStrong && dissRunLength > 1) return false; 

                // Rule C4A: If r=2, BOTH must be weak.
                if (dissRunLength === 2) {
                    const prevIsStrong = isStrong8th((t - 1) + metricOffset, tsNum, tsDenom);
                    if (isStrong || prevIsStrong) return false; 
                }

                if (dissRunLength > 2) return false;

                lastIsDiss = true;
            } else {
                dissRunLength = 0;
                lastIsDiss = false;
            }
        }
    }
    return true;
}

// --- Generator ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const startTime = Date.now();
    let nodesVisited = 0;
    let maxDepth = 0;

    const { notes: baseNotes, offset8 } = normalizeSubject(rawSubject, ppq);
    if (baseNotes.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const subjectLength8 = Math.max(...baseNotes.map(n => n.relTick8 + n.dur8));

    const variants: SubjectVariant[] = [];
    variants.push({ type: 'N', truncationBeats: 0, length8: subjectLength8, notes: baseNotes });
    if (options.inversionMode !== 'None') {
        // Use Centralized Inversion Logic
        const invNotes = baseNotes.map(n => ({
            ...n,
            pitch: getInvertedPitch(n.pitch, options.pivotMidi, options.scaleRoot, options.scaleMode, options.useChromaticInversion)
        }));
        variants.push({ type: 'I', truncationBeats: 0, length8: subjectLength8, notes: invNotes });
    }
    if (options.truncationMode !== 'None' && options.truncationTargetBeats > 0) {
        const trunc8 = Math.round(options.truncationTargetBeats * 2);
        if (trunc8 < subjectLength8) {
            variants.push({ 
                type: 'N', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                notes: baseNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
            });
            if (options.inversionMode !== 'None') {
                const invNotes = baseNotes.map(n => ({
                    ...n,
                    pitch: getInvertedPitch(n.pitch, options.pivotMidi, options.scaleRoot, options.scaleMode, options.useChromaticInversion)
                }));
                variants.push({ 
                    type: 'I', truncationBeats: options.truncationTargetBeats, length8: trunc8,
                    notes: invNotes.filter(n => n.relTick8 < trunc8).map(n => ({...n, dur8: Math.min(n.dur8, trunc8 - n.relTick8)}))
                });
            }
        }
    }

    const compatTable = new Map<string, boolean>();
    const validDelays: number[] = [];
    const maxDelay8 = Math.floor(subjectLength8 * (2/3));

    for (let d = 1; d <= maxDelay8; d++) validDelays.push(d);

    const transpositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => transpositions.push(t));
    }

    // Phase 1: STRUCTURAL PAIRWISE PRECOMPUTATION
    variants.forEach((vA, iA) => {
        variants.forEach((vB, iB) => {
            validDelays.forEach(d => {
                transpositions.forEach(t => {
                    const key = `${iA}_${iB}_${d}_${t}`;
                    const res = checkCounterpointStructure(vA, vB, d, t, options.maxPairwiseDissonance);
                    if (res.compatible) compatTable.set(key, true);
                });
            });
        });
    });

    const results: StrettoChainResult[] = [];
    const partialResults: StrettoChainResult[] = []; // Store best partials
    const MAX_PARTIALS = 20;

    async function solve(
        chain: StrettoChainOption[], 
        variantIndices: number[], 
        voiceEndTimes8: number[], 
        nInv: number, 
        nTrunc: number,
        nRestricted: number,
        nFree: number
    ) {
        nodesVisited++;
        maxDepth = Math.max(maxDepth, chain.length);

        if (Date.now() - startTime > TIME_LIMIT_MS) return;
        if (results.length >= MAX_RESULTS * 3) return; 
        if (nodesVisited > MAX_SEARCH_NODES) return;

        // If target reached, store result
        if (chain.length === options.targetChainLength) {
            const final = calculateStrettoScore(chain, variants, variantIndices, options);
            if (final.isValid) results.push(final);
            return;
        }

        // --- PARTIAL RESULTS LOGIC ---
        // If the chain is significant (>= 3 entries), consider storing it as a partial result
        if (chain.length >= 3) {
            // Simple heuristic: if we have few partials or this is longer than the worst stored partial
            if (partialResults.length < MAX_PARTIALS || chain.length > partialResults[partialResults.length-1].entries.length) {
                const final = calculateStrettoScore(chain, variants, variantIndices, options);
                if (final.isValid) {
                    partialResults.push(final);
                    partialResults.sort((a,b) => b.entries.length - a.entries.length); // Keep longest
                    if (partialResults.length > MAX_PARTIALS) partialResults.pop();
                }
            }
        }

        const depth = chain.length; 
        const prevEntry = chain[depth - 1];

        // --- RULE 1 & 2: DELAY LOGIC (STRICT) ---
        const possibleDelays8: number[] = [];
        let minD = 1; 
        let maxD = Math.floor(subjectLength8 * (2/3)); 

        if (depth > 0) {
            if (depth + 1 > 3) maxD = Math.min(maxD, Math.floor(subjectLength8 * 0.5) - 1);
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                maxD = Math.min(maxD, prevDelay8 + 2);
                if (depth >= 3) {
                    const prevPrevDelay8 = Math.round((chain[depth-2].startBeat - chain[depth-3].startBeat) * 2);
                    // Expansion Reaction Logic
                    if (prevDelay8 > prevPrevDelay8) maxD = Math.min(maxD, prevPrevDelay8 - 1);
                }
                if (prevDelay8 > (subjectLength8 / 2)) maxD = Math.min(maxD, prevDelay8 - 1);
            }
        }

        for (let d = minD; d <= maxD; d++) possibleDelays8.push(d);
        possibleDelays8.sort((a,b) => a - b); 

        for (const delay8 of possibleDelays8) {
            if (depth >= 2) {
                const prevDelay8 = Math.round((chain[depth-1].startBeat - chain[depth-2].startBeat) * 2);
                if (delay8 === prevDelay8) continue;
            }

            const absStart8 = Math.round(prevEntry.startBeat * 2) + delay8;
            const absStartBeat = absStart8 / 2;

            for (const t of transpositions) {
                for (let v = 0; v < options.ensembleTotal; v++) {

                    if (absStart8 < voiceEndTimes8[v] - 2) continue; 

                    let stratFail = false;
                    for (let existingIdx = 0; existingIdx < chain.length; existingIdx++) {
                        const e = chain[existingIdx];
                        if (Math.abs(e.voiceIndex - v) === 1) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;
                            if (highVoiceTrans < lowVoiceTrans) stratFail = true;
                        }
                        const bassIdx = options.ensembleTotal - 1;
                        const altoIdx = bassIdx - 2; 
                        if (bassIdx >= 2) {
                            const isNewBass = (v === bassIdx);
                            const isNewAlto = (v === altoIdx);
                            const isExistingBass = (e.voiceIndex === bassIdx);
                            const isExistingAlto = (e.voiceIndex === altoIdx);
                            if ((isNewBass && isExistingAlto) || (isNewAlto && isExistingBass)) {
                                const bassTrans = isNewBass ? t : e.transposition;
                                const altoTrans = isNewAlto ? t : e.transposition;
                                if (altoTrans < bassTrans + 12) stratFail = true;
                            }
                        }
                        if (Math.abs(e.voiceIndex - v) === 2) {
                            const highVoiceIdx = Math.min(e.voiceIndex, v);
                            const lowVoiceIdx = Math.max(e.voiceIndex, v);
                            const highVoiceTrans = (e.voiceIndex === highVoiceIdx) ? e.transposition : t;
                            const lowVoiceTrans = (e.voiceIndex === lowVoiceIdx) ? e.transposition : t;
                            if (highVoiceTrans < lowVoiceTrans + 7) stratFail = true;
                        }
                    }
                    if (stratFail) continue;

                    for (let varIdx = 0; varIdx < variants.length; varIdx++) {
                        const variant = variants[varIdx];

                        const isInv = variant.type === 'I';
                        const isTrunc = variant.truncationBeats > 0;
                        if (isInv && !checkQuota(options.inversionMode, nInv)) continue;
                        if (isTrunc && !checkQuota(options.truncationMode, nTrunc)) continue;

                        const intervalClass = Math.abs(t % 12);
                        const isRestricted = [3, 4, 8, 9].includes(intervalClass);
                        const isFree = [0, 7].includes(intervalClass) || intervalClass === 5; 
                        const nextRestricted = nRestricted + (isRestricted ? 1 : 0);
                        const nextFree = nFree + (isFree ? 1 : 0);

                        if (nextRestricted > 1 && nextRestricted >= nextFree) continue;
                        if (options.thirdSixthMode === 'None' && isRestricted) continue;
                        if (options.thirdSixthMode === 'Max 1' && nextRestricted > 1) continue;
                        if (options.disallowComplexExceptions && (isInv || isTrunc) && isRestricted) continue;

                        let harmonicFail = false;
                        for (let k = 0; k < chain.length; k++) {
                            const prevE = chain[k];
                            const prevVarIdx = variantIndices[k];
                            const prevStart8 = Math.round(prevE.startBeat * 2);
                            const prevEnd8 = prevStart8 + variants[prevVarIdx].length8;

                            if (absStart8 < prevEnd8) {
                                const relDelay = absStart8 - prevStart8;
                                const relTrans = t - prevE.transposition;
                                const key = `${prevVarIdx}_${varIdx}_${relDelay}_${relTrans}`;
                                if (!compatTable.has(key)) {
                                    harmonicFail = true;
                                    break;
                                }
                            }
                        }
                        if (harmonicFail) continue;

                        const tempNextEntry: StrettoChainOption = {
                            startBeat: absStartBeat,
                            transposition: t,
                            type: variant.type,
                            length: variant.length8 * 2,
                            voiceIndex: v
                        };

                        if (!checkMetricCompliance(variant, tempNextEntry, chain, variants, variantIndices, 4, 4, offset8)) {
                            continue;
                        }

                        const newVoiceState = [...voiceEndTimes8];
                        newVoiceState[v] = absStart8 + variant.length8;

                        const nextChain = [...chain, tempNextEntry];

                        await solve(
                            nextChain,
                            [...variantIndices, varIdx],
                            newVoiceState,
                            nInv + (isInv?1:0),
                            nTrunc + (isTrunc?1:0),
                            nextRestricted,
                            nextFree
                        );
                    }
                }
            }
        }
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = variants[0].length8;

    await solve(
        [{ startBeat: 0, transposition: 0, type: 'N', length: variants[0].length8 * 2, voiceIndex: options.subjectVoiceIndex }],
        [0],
        initialVoiceState,
        0, 0, 0, 1
    );

    // Fallback: Use partial results if full results empty
    let sourceResults = results;
    let stopReason = results.length > 0 ? 'Success' : 'Exhausted';

    if (results.length === 0 && partialResults.length > 0) {
        sourceResults = partialResults;
        stopReason = 'Partial'; // Indicates found chains are shorter than target
    }

    // Grouping Logic
    const groupedMap = new Map<string, StrettoChainResult[]>();

    sourceResults.forEach(res => {
        const delays = res.entries.map(e => e.startBeat).join(',');
        const voices = res.entries.map(e => e.voiceIndex).join(',');
        const key = `D:${delays}|V:${voices}`;

        if (!groupedMap.has(key)) groupedMap.set(key, []);
        groupedMap.get(key)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groupedMap.forEach((group) => {
        group.sort((a,b) => b.score - a.score);
        const leader = group[0];
        if (group.length > 1) {
            leader.variations = group.slice(1);
        }
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort((a,b) => b.score - a.score).slice(0, MAX_RESULTS),
        stats: {
            nodesVisited,
            timeMs: Date.now() - startTime,
            stopReason: stopReason as any,
            maxDepthReached: maxDepth
        }
    };
}

function checkQuota(mode: StrettoConstraintMode, current: number): boolean {
    if (mode === 'None') return false;
    if (mode === 'Max 1') return current < 1;
    return true;
}

import React from 'react';
import { StrettoSearchOptions, StrettoChainResult, StrettoCandidate, RawNote, StrettoSearchReport, HarmonicRegion } from '../../types';
import StrettoSearchPanel from './StrettoSearchPanel';
import StrettoResultsList from './StrettoResultsList';
import StrettoInspector from './StrettoInspector';
import { DownloadIcon } from '../Icons';
import { generatePolyphonicHarmonicRegions, getInvertedPitch } from '../services/strettoCore'; // Use centralized inversion
import { getStrictPitchName } from '../services/midiSpelling';

interface StrettoChainViewProps {
    searchOptions: StrettoSearchOptions;
    setSearchOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    chainResults: StrettoChainResult[];
    selectedChain: StrettoChainResult | null;
    setSelectedChain: (res: StrettoChainResult | null) => void;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;

    // Inspector Props
    chainToCandidate: StrettoCandidate | null; // Note: We actually override this logic locally to ensure polyphony
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    onDownloadChain: () => void;
    searchReport?: StrettoSearchReport | null;

    // Master Transposition
    masterTransposition: number;
    setMasterTransposition: (val: number) => void;
    subjectNotes: RawNote[]; // New prop
}

export default function StrettoChainView({
    searchOptions, setSearchOptions, onSearch, isSearching,
    chainResults, selectedChain, setSelectedChain, voiceNames, setVoiceNames,
    chainToCandidate: _unusedLegacyProp, // We recreate it here to ensure correct polyphonic region generation
    ppq, ts, isPlaying, onPlay, onDownloadChain,
    searchReport, masterTransposition, setMasterTransposition,
    subjectNotes
}: StrettoChainViewProps) {

    // Re-implement candidate generation here to use the new Polyphonic Region Logic
    // instead of relying on the parent's potentially outdated logic
    const chainCandidate = React.useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;

                if (entry.type === 'I') {
                    // Use Shared Core Logic for Inversion
                    const rawInverted = getInvertedPitch(n.midi, searchOptions.pivotMidi, searchOptions.scaleRoot, searchOptions.scaleMode, searchOptions.useChromaticInversion);
                    const subjectFirst = sortedSubj[0].midi;
                    const invertedFirst = getInvertedPitch(subjectFirst, searchOptions.pivotMidi, searchOptions.scaleRoot, searchOptions.scaleMode, searchOptions.useChromaticInversion);

                    const targetStart = subjectFirst + entry.transposition;
                    const shift = targetStart - invertedFirst;
                    pitch = rawInverted + shift;
                } else {
                    pitch += entry.transposition;
                }

                pitch += masterTransposition;

                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            allNotes = [...allNotes, ...clipped];
        });

        // Use new Polyphonic logic for the Chain
        const harmonicRegions = generatePolyphonicHarmonicRegions(allNotes, searchOptions.scaleRoot);

        return { 
            id: selectedChain.id, 
            intervalLabel: "Chain", 
            intervalSemis: 0, 
            delayBeats: 0, 
            delayTicks: 0, 
            grade: 'STRONG', 
            errors: [], 
            notes: allNotes, 
            regions: harmonicRegions, 
            dissonanceRatio: selectedChain.dissonanceRatio || 0,
            nctRatio: selectedChain.nctRatio || 0, // Use the calculated value from the search result for consistency
            pairDissonanceScore: selectedChain.pairDissonanceScore || 0, // Use the calculated intensity from the search result
            endsOnDissonance: false,
            detectedChords: selectedChain.detectedChords
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi, searchOptions.useChromaticInversion, masterTransposition, searchOptions.scaleRoot, searchOptions.scaleMode]);

    return (
        <>
            <StrettoSearchPanel 
                options={searchOptions} 
                setOptions={setSearchOptions}
                onSearch={onSearch}
                isSearching={isSearching}
                voiceNames={voiceNames}
                setVoiceNames={setVoiceNames}
                subjectNotes={subjectNotes}
                ppq={ppq}
            />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                    <div className="p-3 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
                        <h3 className="text-xs font-bold text-gray-400">FOUND CHAINS ({chainResults.length})</h3>
                        {searchReport && (
                            <div className="text-[9px] text-gray-500 text-right">
                                {searchReport.stats.nodesVisited.toLocaleString()} nodes in {searchReport.stats.timeMs}ms
                            </div>
                        )}
                    </div>
                    {searchReport && searchReport.stats.stopReason === 'Partial' && (
                        <div className="bg-orange-900/30 border-b border-orange-800 p-2 text-[10px] text-orange-200">
                            <strong>Partial Results:</strong> Full chains of {searchOptions.targetChainLength} entries not found. Showing longest valid chains (Max: {searchReport.stats.maxDepthReached}).
                        </div>
                    )}
                    {searchReport && searchReport.stats.stopReason === 'Exhausted' && (
                        <div className="bg-red-900/30 border-b border-red-800 p-2 text-[10px] text-red-200">
                            <strong>Search Failed:</strong> No valid chains found. Try relaxing rules.
                        </div>
                    )}
                    <StrettoResultsList 
                        results={chainResults}
                        selectedId={selectedChain?.id || null}
                        onSelect={setSelectedChain}
                        voiceNames={voiceNames}
                    />
                </div>
                <div className="lg:col-span-2">
                    <StrettoInspector 
                        candidate={chainCandidate}
                        ppq={ppq}
                        ts={ts}
                        isPlaying={isPlaying}
                        onPlay={onPlay}
                        assemblyResult={""}
                        assemblyLog={[]}
                        onClearAssembly={() => {}}
                        onDownloadChain={onDownloadChain}
                    />

                    <div className="mt-4 flex flex-col md:flex-row justify-between items-center gap-4 bg-gray-800 p-3 rounded border border-gray-700">
                        <div className="flex items-center gap-4">
                            <span className="text-xs font-bold text-gray-400 uppercase">Master Transpose:</span>
                            <div className="flex items-center gap-2">
                                <button 
                                    onClick={() => setMasterTransposition(Math.max(-24, masterTransposition - 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >-</button>
                                <span className={`text-sm font-mono w-12 text-center ${masterTransposition !== 0 ? 'text-brand-primary font-bold' : 'text-gray-300'}`}>
                                    {masterTransposition > 0 ? '+' : ''}{masterTransposition}
                                </span>
                                <button 
                                    onClick={() => setMasterTransposition(Math.min(24, masterTransposition + 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >+</button>
                            </div>
                            <span className="text-[10px] text-gray-500 hidden sm:inline">Shift entire chain before export.</span>
                        </div>

                        {chainCandidate && (
                            <button 
                                onClick={onDownloadChain}
                                className="flex items-center gap-2 px-4 py-2 bg-brand-primary text-white font-bold rounded shadow-lg hover:bg-brand-secondary transition-colors"
                            >
                                <DownloadIcon className="w-4 h-4" /> Download Chain MIDI
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </>
    );
}

